import Link from '../../components/Link';
const _amulet_of_reverse_incantation = {title: "Amulet of Reverse Incantation", jsx: <><h2 id="magic-wondrous-amulet_of_reverse_incantation-amulet-of-reverse-incantation">Amulet of Reverse Incantation</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 56</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> head; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>An ivory cameo depicting two elderly, bearded wizards with identical faces hangs on this amulet's delicate silver chain. Three times per day, when casting a spell with a verbal component, the wearer of an amulet of reverse incantation can recite the spell's words backward as a free action in order to invert the spell's effect, as described below.</p>
<ul>
<li>If the wearer casts a spell that can counter or dispel another specific spell, she can activate the amulet to convert the spell being cast into the spell it specifically counters. For example, <Link to="/spell/haste">haste</Link> would become <Link to="/spell/slow">slow</Link>, or <Link to="/spell/reduce_person">reduce person</Link> would become <Link to="/spell/enlarge_person">enlarge person</Link>.</li>
<li>If the wearer casts a spell that detects or affects creatures of a certain alignment, the spell instead affects creatures of the opposite alignment. For example, <Link to="/spell/chaos_hammer">chaos hammer</Link> would damage and blind chaotic creatures and outsiders instead of lawful ones.</li>
<li>If the wearer casts a <Link to="/main/inflict_spells">cure or inflict spell</Link>, she can activate the amulet to convert the spell being cast into the other type of the same spell level, such as converting <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link> into <Link to="/spell/inflict_moderate_wounds">inflict moderate wounds</Link>.</li>
</ul>
<p>Alignment restrictions still apply for casters who can't cast spells with certain alignment descriptors.</p>
<h3 id="magic-wondrous-amulet_of_reverse_incantation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/tongues">tongues</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _animal_mask = {title: "Animal Mask", jsx: <><h2 id="magic-wondrous-animal_mask-animal-mask">Animal Mask</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 201</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 2,700 gp; <strong>Weight</strong> -</p>
<p>This finely constructed mask of colored cloth and carved bone incorporates parts of the animal it represents, such as its hair, hide, horn, fur, and teeth. Depicting the head of an ape, bear, boar, cat, fox, horse, pig, rat, or wolf, the mask completely covers the wearer's face, but the wearer can see through the mask's eyes as though they were her own.</p>
<p>As a swift action, the wearer can transform her head into the form of the animal depicted by the mask for up to 5 minutes per day, absorbing the mask into her body in the process but leaving in place any other item she wears on her head. While so transformed, the wearer retains the ability to speak normally and can complete verbal spell components, utter command words, and activate spell completion and spell trigger items. She also gains low-light vision, <Link to="/umr/scent">scent</Link>, and either a <Link to="/umr/gore_attack">bite or gore attack</Link> (as appropriate to the animal) that deals 1d4 points of damage for a Medium wearer (1d3 if Small).</p>
<p>This duration does not need to be consecutive, but it must be used in 1-minute increments.</p>
<h3 id="magic-wondrous-animal_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Cost</strong> 1,350 gp</p>
</>};
const _aspect_mask = {title: "Aspect Mask", jsx: <><h2 id="magic-wondrous-aspect_mask-aspect-mask">Aspect Mask</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 225</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 6,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This leather mask is vaguely animalistic, and is inlaid with various primitive designs. Three times per day on command, the wearer gains the benefit of a single aspect of an animal attuned to the mask, as if by the hunter's <Link to="/ability/animal_focus">animal focus</Link> class feature. Each mask is attuned to one type of animal from the animal focus list, chosen when the mask is created.</p>
<h3 id="magic-wondrous-aspect_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have animal focus or wild shape class feature; <strong>Cost</strong> 3,250 gp</p>
</>};
const _bastion_crown = {title: "Bastion Crown", jsx: <><h2 id="magic-wondrous-bastion_crown-bastion-crown">Bastion Crown</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 30</Link><br/><strong>Aura</strong> faint conjuration and conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Often worn by paranoid rulers, this simple iron crown is thick and heavy. The wearer is immune to ninja, rogue, and slayer talents that add effects to a <Link to="/ability/sneak_attack">sneak attack</Link>, such as <Link to="/talent/bleeding_attack">bleeding attack</Link> or <Link to="/talent/crippling_strike">crippling strike</Link>, though the wearer takes the extra damage from sneak attacks as normal. In addition, the wearer gains a +4 insight bonus on saving throws against death effects and an <Link to="/pclass/assassin">assassin's</Link> death attack ability. Finally, the wearer can cast <em>neutralize poison</em> on himself once per day, using the caster level of the item for any caster level check required.</p>
<h3 id="magic-wondrous-bastion_crown-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_ward">death ward</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _batrachian_helm = {title: "Batrachian Helm", jsx: <><h2 id="magic-wondrous-batrachian_helm-batrachian-helm">Batrachian Helm</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 240</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This oily bronze helm is fashioned in the shape of a frog's head. Three times per day as a swift action, the helm fires an unerring tongue of force at a visible target within 20 feet.</p>
<p>If the target is an unattended object weighing 250 pounds or less, it is pulled 20 feet toward the wearer. If the target is a creature of the wearer's size or smaller, the wearer may make a <Link to="/rule/combat_maneuver">combat maneuver</Link> check as a free action to pull the target 20 feet toward him.</p>
<p>If the target is a creature larger than the wearer, an unattended object weighing more than 250 pounds, or an immobile structure such as a wall, the wearer is pulled 20 feet toward the target. This movement does not provoke attacks of opportunity, and the object or creature stops if the movement would move it into a solid object or creature.</p>
<h3 id="magic-wondrous-batrachian_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _baxs_mask = {title: "Bax's Mask", jsx: <><h2 id="magic-wondrous-baxs_mask-baxs-mask">Bax's Mask</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 45</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 9,100 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This plain mask is made of a reflective, dark gray ceramic. When worn, the mask transforms to look like the wearer's skull, and it gradually becomes eerier and more fearsome the closer a viewer gets to the wearer. Whenever a creature enters a square adjacent to the wearer of Bax's mask, that creature must succeed at a DC 13 Will save or become <Link to="/misc/shaken">shaken</Link> for as long as it remains adjacent to the wearer. An affected creature can attempt a new save by moving away from the wearer and reentering a square adjacent to the wearer. A creature that succeeds at the save is immune to the mask's effect for 24 hours. A creature shaken by Bax's mask does not become <Link to="/misc/frightened">frightened</Link> if affected by the mask again, but other fear effects stack with the creature's shaken condition as normal.</p>
<h3 id="magic-wondrous-baxs_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/scare">scare</Link>; <strong>Cost</strong> 4,550 gp</p>
</>};
const _beautiful_war_paint = {title: "Beautiful War Paint", jsx: <><h2 id="magic-wondrous-beautiful_war_paint-beautiful-war-paint">Beautiful War Paint</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 260</Link><br/><strong>Aura</strong> faint enchantment and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 6,300 gp; <strong>Weight</strong> 1 lb.</p>
<p>This pot of multicolored makeup was created by warpriests of <Link to="/faith/shelyn">Shelyn</Link> who wanted to be beautiful as well as deadly in battle. It can be used as conventional makeup, stage makeup, or war paint. It can be applied quickly for a lesser effect, but its true power is revealed when it's applied with great care. If the wearer applies the makeup as a full-round action, she gains the effects of <Link to="/spell/bless">bless</Link> and <Link to="/spell/expeditious_retreat">expeditious retreat</Link>. If the wearer applies the makeup over the course of 10 minutes, she gains the effects of <em>good hope</em> and <em>haste.</em> Applying the makeup provokes attacks of opportunity. The finished makeup has no effect until the wearer activates it as a swift action, at which time its magic lasts either 5 minutes or 5 rounds, depending on the duration of the activated spells (thereafter, the makeup lasts as long as high-quality nonmagical makeup). The magic of the makeup fades after 24 hours if not activated.</p>
<p>The makeup uses only the head magic item slot when applied (the pot does not use a magic item slot). The pot contains enough makeup for three uses.</p>
<h3 id="magic-wondrous-beautiful_war_paint-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/good_hope">good hope</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 3,150 gp</p>
</>};
const _besmaras_bicorne = {title: "Besmara's Bicorne", jsx: <><h2 id="magic-wondrous-besmaras_bicorne-besmaras-bicorne">Besmara's Bicorne</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 260</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 55</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 1,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This large pirate hat bears a skull-and-crossbones on the front. The wearer gains a +2 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> and <Link to="/skill/climb">Climb</Link> checks.</p>
<p>If <Link to="/faith/besmara">Besmara</Link> is the wearer's patron, the wearer automatically floats to the surface of any body of water (at a speed of 30 feet) unless she desires otherwise; this does not prevent the wearer from falling safely into water or interacting with water in any other way.</p>
<h3 id="magic-wondrous-besmaras_bicorne-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/levitate">levitate</Link>, creator must have 5 ranks in Acrobatics and Climb; <strong>Cost</strong> 850 gp</p>
</>};
const _besmaras_tricorne = {title: "Besmara's Tricorne", jsx: <><h2 id="magic-wondrous-besmaras_tricorne-besmaras-tricorne">Besmara's Tricorne</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 261</Link>, <Link to="/source/pathfinder_55_the_wormwood_mutiny">Pathfinder #55: The Wormwood Mutiny pg. 58</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 2,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black leather tricorne hat is weather-beaten and salt-stained. It grants its wearer a +2 competence bonus on <Link to="/skill/profession">Profession (sailor)</Link> and <Link to="/skill/swim">Swim</Link> checks.</p>
<p>If <Link to="/faith/besmara">Besmara</Link> is the wearer's patron, once per day the wearer can speak a command word to transform the hat into a small ship's boat such as a <Link to="/rule/aqt_4">cutter, jolly boat, or longboat</Link>. The boat is 20 feet long, has two pairs of oars and a single mast with a square sail, and can carry up to 12 passengers and crew. Upon command, or after 8 hours, the boat returns to its hat form, dumping out any occupants.</p>
<h3 id="magic-wondrous-besmaras_tricorne-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/shrink_item">shrink item</Link>, creator must have 5 ranks in Profession (sailor); <strong>Cost</strong> 1,300 gp</p>
</>};
const _bitter_widows_veil = {title: "Bitter Widow's Veil", jsx: <><h2 id="magic-wondrous-bitter_widows_veil-bitter-widows-veil">Bitter Widow's Veil</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 56</Link><br/><strong>Aura</strong> faint enchantment and divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This delicate black veil is made of black lace and crepe and affixed to a midnight blue bonnet. When it's donned, amorphous shadows swirl beneath the veil across the wearer's face.</p>
<p>Whenever an ally within 30 feet of the wearer falls unconscious by taking lethal damage, the bitter widow's veil gains 1 charge. The wearer can expend 1 charge as a standard action to unleash a bereaved scream in a 30-foot cone. Creatures within the area must succeed at a DC 16 Will save or become <Link to="/misc/shaken">shaken</Link> for 4 minutes. If a creature that brought a humanoid or monstrous humanoid to fewer than 0 hit points within the past 12 hours fails the save, it's <Link to="/misc/dazed">dazed</Link> for 1 round as it is consumed with sorrow, after which it's subject to the shaken effect.</p>
<p>As long as the bitter widow's veil has an unspent charge, the wearer can see and hear ethereal creatures as though affected by <em>see invisibility.</em> The veil can contain only 1 charge at a time. Unused charges dissipate after 1 hour.</p>
<h3 id="magic-wondrous-bitter_widows_veil-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/crushing_despair">crushing despair</Link>, <Link to="/spell/overwhelming_grief">overwhelming grief</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _blind_helm = {title: "Blind Helm", jsx: <><h2 id="magic-wondrous-blind_helm-blind-helm">Blind Helm</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 147</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 13th<br/><strong>Slot</strong> head; <strong>Price</strong> 85,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This plain steel helm completely covers the face, lacking even eyeholes or a slit to peer out of. Its wearer is <Link to="/misc/blinded">blinded</Link> by the helm, but gains <Link to="/umr/blindsense">blindsense</Link> with a range of 60 feet. As a swift action, the wearer can expend one use of mythic power to gain blindsight with a range of 60 feet for 1 minute, or instead expend two uses of mythic power to gain <Link to="/umr/blindsight">blindsight</Link> with a range of 120 feet for 1 minute. The wearer can expend three uses of mythic power to gain the effects of <em>true seeing</em> for 1 minute.</p>
<h3 id="magic-wondrous-blind_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/echolocation">echolocation</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 42,500 gp</p>
</>};
const _bloody_mantis = {title: "Bloody Mantis", jsx: <><h2 id="magic-wondrous-bloody_mantis-bloody-mantis">Bloody Mantis</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 21</Link><br/><strong>Aura</strong> moderate divination, enchantment, and illusion; <strong>CL</strong> 11th<br/><strong>Slot</strong> head; <strong>Price</strong> 52,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>The antennae on this <Link to="/magic-wondrous/mask_of_the_mantis">mask of the mantis</Link> have been truncated. Bloody Mantis has three charges per day, which replenish automatically every 24 hours. Each charge grants the wearer two of the following abilities for 30 minutes: darkvision to a range of 60 feet, the effects of <em>see invisibility,</em> the effects of <em>deathwatch,</em> or a +5 competence bonus on <Link to="/skill/perception">Perception</Link> checks. Additionally, three times per day the wearer can also use <em>disguise self,</em> although he always retains the mask's nub-like antennae and must cover them with her hair or a hood to conceal them. Finally, if the wearer strikes a target with a melee attack during a surprise round, the target can't speak or cast spells with verbal components for 1 round.</p>
<p>Bloody Mantis contains the spirit of a haughty assassin lord, and has the <Link to="/rule/special_purpose">special purpose</Link> of slaying insurrectionists, traitors, and other challengers to rightful monarchs. Bloody Mantis can use <em>geas/quest</em> once per day, but it rarely does so at the behest of its wearer. Instead, the mask targets its wearer with the effect whenever it dominates the wearer in a personality conflict, tasking the wearer to assassinate a target appropriate for its special purpose. So long as the wearer pursues this goal, Bloody Mantis uses its abilities to aid the wearer. The mask can spend its charges to improve its own senses rather than the wearer's, and is likely to waste charges in this way if its wearer resists its will.</p>
<h3 id="magic-wondrous-bloody_mantis-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/deathwatch">deathwatch</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/geas_quest">geas/quest</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Price</strong> 26,250 gp</p>
<h3 id="magic-wondrous-bloody_mantis-statistics">Statistics</h3>
<p><strong>Alignment</strong> lawful evil; <strong>Ego</strong> 12<br/><strong>Senses</strong> 30 ft.<br/><strong>Int</strong> 12, <strong>Wis</strong> 15, <strong>Cha</strong> 10<br/><strong>Communication</strong> speech (Common, Infernal)</p>
</>};
const _bridle_of_charon = {title: "Bridle of Charon", jsx: <><h2 id="magic-wondrous-bridle_of_charon-bridle-of-charon">Bridle of Charon</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_spiral_of_bones_5">Pathfinder Spiral of Bones #5 pg. 30</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 14th<br/><strong>Slot</strong> head; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Studded with shards of inert soul gems, this bridle imbues its wearer with a fraction of the power of <Link to="/faith/the_pale_horse">the Pale Horse</Link>, the Horseman of Death's steed. Once per day as an immediate action, the rider of a creature wearing this item can activate it as part of the mount's movement. It becomes incorporeal during its movement, though it must stop in an unoccupied space. Any object the creature passes through during its incorporeal movement begins to crumble, having its hit points reduced by half (ignoring hardness). Any living creatures' spaces the mount passes through during its incorporeal movement feel the cold wind of death and must succeed at a DC 20 Fortitude save or take a -4 penalty to its Strength, Dexterity, and Constitution scores that lasts for 1 minute.</p>
<h3 id="magic-wondrous-bridle_of_charon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">Bestow Curse</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>; <strong>Cost</strong> 20,000 gp</p>
</>};
const _bridle_of_tricks_3_tricks = {title: "Bridle of Tricks (3 tricks)", jsx: <><h2 id="magic-wondrous-bridle_of_tricks_3_tricks-bridle-of-tricks">Bridle of Tricks</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 30</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 900 gp (3 tricks), 1,600 gp (4 tricks), 2,500 gp (5 tricks); <strong>Weight</strong> 2 lbs.</p>
<p>Appearing to be a finely crafted bridle of polished steel and blue-dyed leather, a bridle of tricks can be placed on any animal or magical beast with an appropriate shape to wear a bridle (creatures with unusual anatomies may be affected with GM discretion). While wearing the bridle, a creature is treated as knowing three, four, or five additional <Link to="/ability/animal_tricks">tricks</Link>, as if it had been taught the tricks with the <Link to="/skill/handle_animal">Handle Animal</Link> skill. The tricks granted by a bridle of tricks are set when it is created, and cannot be changed. The most common tricks found in a bridle of tricks are attack, defend, fetch, guard, and heel.</p>
<h3 id="magic-wondrous-bridle_of_tricks_3_tricks-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, creator must have 5 ranks in the Handle Animal skill; <strong>Cost</strong> 450 gp (3 tricks), 800 gp (4 tricks), 1,250 gp (5 tricks)</p>
</>};
const _buffering_cap = {title: "Buffering Cap", jsx: <><h2 id="magic-wondrous-buffering_cap-buffering-cap">Buffering Cap</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 240</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This cloth hat is floppy and shapeless. It offers its wearer an unusual amount of protection against particularly devastating blows. Once per day when struck by a critical hit, the wearer can spend an immediate action to convert the bonus damage of the critical hit into nonlethal damage. The cap has no effect if the wearer is immune to nonlethal damage.</p>
<h3 id="magic-wondrous-buffering_cap-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _callers_feather = {title: "Caller's Feather", jsx: <><h2 id="magic-wondrous-callers_feather-callers-feather">Caller's Feather</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 20</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>This magnificent feather, plucked from the wing of a powerful erinyes or angel, allows the wearer to call stronger outsiders to her service. The wearer can use the feather to call 2 more HD worth of creatures when casting a <em>planar binding</em> or <em>planar ally</em> spell (including <em>lesser</em> and <em>greater</em> versions) or when casting <Link to="/spell/gate">gate</Link>. Alternatively, when casting one of these spells, the spellcaster can expend this feather to summon a single outsider with up to 2 more Hit Dice than the spell would normally allow. For example, he may summon a <Link to="/monster/trumpet_archon">trumpet archon</Link> with planar ally, or a <Link to="/monster/pit_fiend">pit fiend</Link> with <Link to="/spell/greater_planar_binding">greater planar binding</Link>. The wearer gains a +2 insight bonus on all Charisma checks and Charisma-based skill checks to influence the creature called. Once used, the feather crumbles to mundane dust.</p>
<h3 id="magic-wondrous-callers_feather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _cap_of_darkest_dreams_changeling = {title: "Cap of Darkest Dreams (Changeling)", jsx: <><h2 id="magic-wondrous-cap_of_darkest_dreams_changeling-cap-of-darkest-dreams-changeling">Cap of Darkest Dreams (Changeling)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 230</Link><br/><strong>Aura</strong> strong illusion and necromancy; <strong>CL</strong> 14th<br/><strong>Slot</strong> head; <strong>Price</strong> 90,000 gp; <strong>Weight</strong> -</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This black gossamer cap is woven from ethereal moonbeams and nightmares. Whenever the wearer would experience a nightmare, whether magical or mundane (including the dream haunting ability of a <Link to="/monster/night_hag">night hag</Link>), the cap absorbs it without effect.</p>
<p>Once per day, when a <Link to="/race/changeling">changeling</Link> wearer sleeps with her face covered by the cap, she can send a <em>nightmare</em> (DC 17). If the victim fails his saving throw against the <em>nightmare,</em> the wearer can target him with <em>major curse</em> as well, but must describe to the victim a condition under which the curse will be lifted. The victim automatically understands the terms of the curse even if he does not share a language with the wearer. The condition must be possible to the wearer's knowledge given what she knows of the victim's resources, but may be extremely difficult to achieve and may require significant luck or assistance (at the GM's discretion). A cap of darkest dreams can maintain only one curse at a time; if the wearer uses the cap to curse a new victim, any previous curse ends. Once per day by uttering the command word, a changeling wearer can unleash the vile essence of nightmares upon all creatures around her. She emanates a <em>cloak of dreams</em> as per the spell. Any creature sent to sleep by this aura automatically suffers a <em>nightmare</em> (DC 17) evoking its deepest fears.</p>
<h3 id="magic-wondrous-cap_of_darkest_dreams_changeling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cloak_of_dreams">cloak of dreams</Link>, <Link to="/spell/major_curse">major curse</Link>, <Link to="/spell/nightmare">nightmare</Link>, creator must be a changeling; <strong>Cost</strong> 45,000 gp</p>
</>};
const _cap_of_enervation = {title: "Cap of Enervation", jsx: <><h2 id="magic-wondrous-cap_of_enervation-cap-of-enervation">Cap of Enervation</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 9</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> -</p>
<p>This floppy leather hat allows a <Link to="/monster/boggard">boggard</Link> or other frog-like creature to drain the strength of those it strikes with its tongue attack. If the wearer ends its turn with its tongue attached to or grappling another creature, the grappled creature takes a -1 penalty to Strength, and the wearer's tongue gains 5 <Link to="/rule/temporary_hit_points">temporary hit points</Link>. The penalty and temporary hit points last for 1 minute. For each round that the target remains attached, the Strength penalty increases by 1, the tongue gains an additional 5 temporary hit points (maximum 10), and the duration resets.</p>
<h3 id="magic-wondrous-cap_of_enervation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ray_of_enfeeblement">ray of enfeeblement</Link>, <Link to="/spell/vampiric_touch">vampiric touch</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _cap_of_human_guise = {title: "Cap of Human Guise", jsx: <><h2 id="magic-wondrous-cap_of_human_guise-cap-of-human-guise">Cap of Human Guise</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 240</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 154</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 800 gp; <strong>Weight</strong> -</p>
<p>This threadbare hat allows its wearer to alter her appearance at will as with a <em>disguise self</em> spell, except she can only appear as a plainly dressed Small human child, adult halfling, or adult gnome, such as a peasant, blacksmith, or shopkeeper. The wearer can slightly alter the cap's appearance as part of the disguise, but otherwise must match the overall unremarkable look of the illusory form.</p>
<p>Though invented and primarily used by Small humanoids, it can be used by any Small or Medium humanoid creature.</p>
<h3 id="magic-wondrous-cap_of_human_guise-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>; <strong>Cost</strong> 400 gp</p>
</>};
const _cap_of_light = {title: "Cap of Light", jsx: <><h2 id="magic-wondrous-cap_of_light-cap-of-light">Cap of Light</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 240</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 900 gp; <strong>Weight</strong> -</p>
<p>This small cloth skullcap resembles those some priests wear, but is topped with a small silver statue in the shape of a lit candle. The wearer can command the statue to radiate <em>light</em> (as the spell). The light can also be turned off on command.</p>
<h3 id="magic-wondrous-cap_of_light-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/light">light</Link>; <strong>Cost</strong> 450 gp</p>
</>};
const _cap_of_the_free_thinker = {title: "Cap of the Free Thinker", jsx: <><h2 id="magic-wondrous-cap_of_the_free_thinker-cap-of-the-free-thinker">Cap of the Free Thinker</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 240</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>This soft cap helps the wearer free herself from outside influences. Once per day, when the wearer fails a saving throw against a mind-affecting effect, she can reroll the save and take the second result.</p>
<h3 id="magic-wondrous-cap_of_the_free_thinker-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mind_blank">mind blank</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _cats_eye_crown = {title: "Cat's Eye Crown", jsx: <><h2 id="magic-wondrous-cats_eye_crown-cats-eye-crown">Cat's Eye Crown</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 240</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 94</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This slender silver crown is decorated with a single cat's eye gemstone as a centerpiece. When the gem is attached to the crown, its wearer gains darkvision 60 feet, or increases her darkvision by 60 feet if she already possesses that sense. The gemstone is detachable, and can be rolled into rooms, dropped into holes, thrown through windows, or planted on a creature. Once per day, on command, the crown's wearer gains the benefit of the <em>clairaudience/clairvoyance</em> spell, but uses the cat's eye gemstone as that spell's sensor and gains darkvision when viewing through that sensor. If the stone is held or carried by a creature, even within a sack or some other container, the creature wearing the crown uses the senses of the creature carrying the gemstone as the sensor instead, whether or not the creature carrying the gemstone is aware of the stone's true purpose or even its existence. Destroying the gem (hardness 8, hp 5) severs the link, but a new cat's eye gemstone worth at least 100 gp can be fashioned and attuned to the crown. The attunement process takes 24 hours.</p>
<h3 id="magic-wondrous-cats_eye_crown-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link>, <Link to="/spell/darkvision">darkvision</Link>, creator must be a catfolk; <strong>Cost</strong> 9,000 gp</p>
</>};
const _circlet_of_mindsight = {title: "Circlet of Mindsight", jsx: <><h2 id="magic-wondrous-circlet_of_mindsight-circlet-of-mindsight">Circlet of Mindsight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 240</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 51</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 22,000 gp; <strong>Weight</strong> -</p>
<p>This elaborate circlet of gold-and-platinum filigree bears tiny gems in settings that look disturbingly like human eyes. When worn, the circlet lets the wearer sense the presence of other thinking creatures in her immediate area. The wearer gains the benefits of <Link to="/umr/blindsense">blindsense</Link> 30 feet, but only against creatures with an Intelligence score that are susceptible to mind-affecting effects.</p>
<p>Undead, constructs, and mindless creatures like most oozes and vermin cannot be perceived when using the circlet, nor can creatures under the effects of <Link to="/spell/mind_blank">mind blank</Link> or a <Link to="/magic-ring/ring_of_mind_shielding">ring of mind shielding</Link>.</p>
<p>The circlet does not interfere with the wearer's ability to see normally. If the wearer has <Link to="/umr/blindsense">blindsense</Link> or <Link to="/umr/blindsight">blindsight</Link>, he is able to differentiate creatures detected with those senses from creatures detected with the circlet of mindsight.</p>
<h3 id="magic-wondrous-circlet_of_mindsight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>; <strong>Cost</strong> 11,000 gp</p>
</>};
const _circlet_of_persuasion = {title: "Circlet of Persuasion", jsx: <><h2 id="magic-wondrous-circlet_of_persuasion-circlet-of-persuasion">Circlet of Persuasion</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 241</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 506</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> -</p>
<p>This delicately engraved silver headband grants its wearer a +3 competence bonus on Charisma-based checks.</p>
<h3 id="magic-wondrous-circlet_of_persuasion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _circlet_of_petty_discord = {title: "Circlet of Petty Discord", jsx: <><h2 id="magic-wondrous-circlet_of_petty_discord-circlet-of-petty-discord">Circlet of Petty Discord</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 26</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 84,000 gp; <strong>Weight</strong> -</p>
<p>Once per day, when the wearer of this delicate silver crown casts a spell from the charm subschool, he can add a subtle compulsion to the effect. All targets affected by the spell must succeed at a DC 20 Will saving throw or become incredibly frustrated with their allies. For the next 10 rounds, affected targets still recognize their allies (and do not attack them), but they cannot treat them as allies when determining movement or <Link to="/rule/flanking">flanking</Link>, nor can they use any feats (including teamwork feats), spells, abilities, or effects that allow them to target allies or use allies to gain beneficial effects, nor can they be the targets of such friendly effects. Affected targets also cannot <Link to="/rule/aid_another_2">aid another</Link>.</p>
<h3 id="magic-wondrous-circlet_of_petty_discord-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/confusion">confusion</Link>, <Link to="/spell/suggestion">suggestion</Link>; <strong>Cost</strong> 42,000 gp</p>
</>};
const _circlet_of_spell_eating = {title: "Circlet of Spell-Eating", jsx: <><h2 id="magic-wondrous-circlet_of_spell_eating-circlet-of-spell-eating">Circlet of Spell-Eating</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 16</Link><br/><strong>Aura</strong> moderate (no school); <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 1,500 gp (Type I), 6,000 gp (Type II), 13,500 gp (Type III), 24,000 gp (Type IV); <strong>Weight</strong> -</p>
<p>Iridescent whorls and runes in a flowing eldritch script adorn this golden circlet. The circlet functions as a <Link to="/magic-ring/ring_of_spell_knowledge">ring of spell knowledge</Link>, allowing a spontaneous caster to learn and store an additional arcane spell. However, once the circlet has been worn for 1d6 days, the wearer must succeed at a DC 16 Will save each day when meditating to renew her spell slots. Failure indicates that she loses knowledge of a random spell, whose level cannot exceed the maximum level of the circlet of spell-eating. Knowledge of this spell is lost until the circlet is removed, returning at a rate of one spell per day, beginning with the lowest-level spell forgotten.</p>
<p>So long as the circlet of spell-eating has caused its wearer to forget at least one spell, its creator can cast the first spell lost to the item once per day as a spell-like ability.</p>
<h3 id="magic-wondrous-circlet_of_spell_eating-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>; <strong>Cost</strong> 750 gp (Type I), 3,000 gp (Type II), 6,750 gp (Type III), 12,000 gp (Type IV)</p>
</>};
const _clasp_of_the_mind_scream = {title: "Clasp of the Mind Scream", jsx: <><h2 id="magic-wondrous-clasp_of_the_mind_scream-clasp-of-the-mind-scream">Clasp of the Mind Scream</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_27_what_lies_in_dust">Pathfinder #27: What Lies in Dust pg. 54</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 8th<br/><strong>Slot</strong> head; <strong>Price</strong> 12,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>This strange device grants the ability to mentally communicate with others, yet proves difficult to control. It generates a constant field of mental static that grants the wearer a +1 bonus on Will saves against mind-affecting effects. The wearer may generate an attack similar to the spell <em>shout,</em> though the sound is mental, and thus does not affect items or creatures immune to mind-affecting effects, and its damage is not affected by sonic vulnerability, resistance, or immunity. In addition, as part of the attack, the wearer may make a DC 20 Charisma check to shape a specific noise or message of five words or fewer. These sounds are purely mental and not heard by any creature outside the area of effect.</p>
<p>The wearer may use this effect 1d3 times per day. The GM determines how many times per day the clasp of the mind scream can be used. If the wearer attempts to use the clasp beyond this number of times, he is affected by its effects and the clasp is inert for the next 24 hours.</p>
<h3 id="magic-wondrous-clasp_of_the_mind_scream-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/shout">shout</Link>; <strong>Cost</strong> 6,400 gp</p>
</>};
const _commanders_helm_dwarf_lesser = {title: "Commander's Helm (Dwarf) (Lesser)", jsx: <><h2 id="magic-wondrous-commanders_helm_dwarf_lesser-commanders-helm-dwarf">Commander's Helm (Dwarf)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 230</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 4th<br/><strong>Slot</strong> head; <strong>Price</strong> 10,000 gp (Lesser), 16,000 gp (Greater), 24,000 gp (Superior); <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This broad helmet is marked with archaic dwarven military insignia. When each helm is created, it is attuned to one teamwork feat. The wearer gains that feat for as long as she wears the helm and meets its prerequisites. With a command word, the wearer can grant that feat to all allies that meet its prerequisites within 30 feet for 1 minute. The helm can be activated up to three times per day.</p>
<p>If the wearer is a <Link to="/race/dwarf">dwarf</Link>, she can choose any teamwork feat she possesses to grant in this way. The helm can grant no more than one feat at a time; when a new feat is granted, all subjects lose any previously granted feat.</p>
<p>A lesser commander's helm can contain a feat with either a base attack bonus prerequisite no greater than +5 or a skill rank prerequisite no greater than 5. A greater commander's helm can contain a feat with a base attack bonus prerequisite no greater than +10 or a skill rank prerequisite no greater than 10. A superior commander's helm can contain any teamwork feat. The same restrictions apply to the feats that a dwarf wearer can grant when choosing from feats she possesses.</p>
<h3 id="magic-wondrous-commanders_helm_dwarf_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, the <Link to="/main/teamwork_feat">teamwork feat</Link> to be imbued, <Link to="/spell/tactical_acumen">tactical acumen</Link>, creator must be a dwarf; <strong>Cost</strong> 5,000 gp (Lesser), 8,000 gp (Greater), 12,000 gp (Superior)</p>
</>};
const _crown_of_ash = {title: "Crown of Ash", jsx: <><h2 id="magic-wondrous-crown_of_ash-crown-of-ash">Crown of Ash</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_34_blood_for_blood">Pathfinder #34: Blood for Blood pg. 66</Link><br/><strong>Aura</strong> strong divination and transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> head; <strong>Price</strong> 29,900 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This crown gives a +4 competence bonus on Charisma checks and Charisma-based skill checks when dealing with creatures of the fey type. When dealing with creatures associated with fey but not fey themselves, such as gnomes, the wearer gains a +2 competence bonus on these checks.</p>
<p>The wearer can speak, read, and understand Sylvan, If the wearer of the crown of ash is not a fey, he gains low-light vision, a +4 bonus on saves against enchantment spells, and DR 5/cold iron.</p>
<h3 id="magic-wondrous-crown_of_ash-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>; <strong>Cost</strong> 14,950 gp</p>
</>};
const _crown_of_blasting_minor = {title: "Crown of Blasting (Minor)", jsx: <><h2 id="magic-wondrous-crown_of_blasting_minor-crown-of-blasting">Crown of Blasting</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 241</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 507</Link><br/><strong>Aura</strong> moderate (minor) or strong (major) evocation; <strong>CL</strong> 6th (minor), 17th (major)<br/><strong>Slot</strong> head; <strong>Price</strong> 6,480 gp (minor), 23,760 gp (major); <strong>Weight</strong> 1 lb.</p>
<p><strong className="hl">Minor:</strong> On command, this simple golden crown projects a blast of <em>searing light</em> (3d8 points of damage) once per day.</p>
<p><strong className="hl">Major</strong>: On command, this elaborate golden crown projects a blast of <em>searing light</em> (5d8 maximized for 40 points of damage) once per day.</p>
<h3 id="magic-wondrous-crown_of_blasting_minor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/maximize_spell">Maximize Spell</Link> (major only), <Link to="/spell/searing_light">searing light</Link>; <strong>Cost</strong> 3,240 gp (minor), 11,880 gp (major)</p>
</>};
const _crown_of_challenge = {title: "Crown of Challenge", jsx: <><h2 id="magic-wondrous-crown_of_challenge-crown-of-challenge">Crown of Challenge</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 28</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 21,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This jagged steel crown is rough and scratched but shows no sign of being dented or misshapen. Once per day, the wearer can issue a challenge to a creature able to see and hear him. The creature gains a +2 morale bonus on melee attack rolls and damage rolls against the crown's wearer for 1 minute. The creature challenged also takes a -2 penalty on attack rolls and damage rolls against all targets other than the wearer, and takes a -2 penalty to the save DCs of its spells, spell-like abilities, and supernatural abilities that affect other targets unless they also affect the wearer of the crown. These penalties last 1 minute or until the creature challenged makes a melee attack against the wearer of the crown.</p>
<p>If the crown's wearer has the challenge class feature, he gains the benefit of his challenge against the creature challenged without expending a daily use of his own challenge ability.</p>
<h3 id="magic-wondrous-crown_of_challenge-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_planar_ally">greater planar ally</Link>; <strong>Cost</strong> 10,500 gp</p>
</>};
const _crown_of_conquest = {title: "Crown of Conquest", jsx: <><h2 id="magic-wondrous-crown_of_conquest-crown-of-conquest">Crown of Conquest</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 241</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 78</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 24,600 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This crown of steel and gold projects an aura of menacing power. The wearer gains a +4 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks, and whenever he confirms a critical hit, the crown creates a <em>prayer</em> effect centered on the crown's wearer (caster level 5th).</p>
<p>If the wearer of the crown has the <Link to="/feat/leadership">Leadership</Link> feat, he gains a +1 bonus to his Leadership score and any follower or cohort of the wearer gains a +1 bonus on attack rolls and saving throws against fear effects while within line of sight of the wearer.</p>
<h3 id="magic-wondrous-crown_of_conquest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bless">bless</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/prayer">prayer</Link>; <strong>Cost</strong> 12,300 gp</p>
</>};
const _crown_of_false_rule = {title: "Crown of False Rule", jsx: <><h2 id="magic-wondrous-crown_of_false_rule-crown-of-false-rule">Crown of False Rule</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 30</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This item appears to be a crown studded with gems, but its valuable metals are only veneers and its gems are clever fakes. The wielder can alter the crown's appearance at will to that of any crown or circlet she has seen before, but only for as long as she wears the crown. In any form, the crown is detectable as a valueless fake with a successful DC 30 <Link to="/skill/appraise">Appraise</Link> check. The wearer of a crown of false rule is considered the rightful political ruler of wherever she is for the purposes of magical spells or effects; for example, the wearer can receive the benefits of a magic throne, draw a sword that can be removed only by a king, open a vault that unlocks at the duchess's touch, and so forth. This ability does not function in areas without a monarch or similar ruler (such as in a democracy), and it is not effective against <Link to="/spell/discern_location">discern location</Link> or the actions of deities or similarly powerful beings. For the purposes of <em>detect</em> spells (and spells with similar capabilities), a crown of false rule does not appear to radiate a magical aura.</p>
<h3 id="magic-wondrous-crown_of_false_rule-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_aura">magic aura</Link>, <Link to="/spell/veil">veil</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _crown_of_heaven = {title: "Crown of Heaven", jsx: <><h2 id="magic-wondrous-crown_of_heaven-crown-of-heaven">Crown of Heaven</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 242</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 150,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This slim golden diadem, bejeweled with diamonds and sapphires, grants its wearer fluency in Celestial and allows her to <em>detect evil</em> at will and use <em>tongues</em> once per day, both on command. She also gains a +5 sacred bonus on <Link to="/skill/knowledge_planes">Knowledge (planes)</Link> checks regarding outsiders with the good or evil subtypes, and any effect she creates with the good descriptor takes effect at +1 caster level.</p>
<p>A crown, an <Link to="/magic-wondrous/orb_of_golden_heaven">orb</Link>, and a <Link to="/magic-rod/scepter_of_heaven">scepter of heaven</Link> - collectively known as a <em>regalia of heaven</em> - increase in power when used together. If the wearer of a <em>crown of heaven</em> wields an <em>orb</em> or <em>scepter of heaven,</em> effects she creates with the good descriptor gain an additional +1 caster level, and she gains a +1 sacred bonus to AC and on saves against attacks or effects created by evil creatures. She also radiates an aura of menace in a 20-foot radius. Any evil creature within this aura takes a -2 penalty on attack rolls, on saving throws, and to AC until it successfully hits the wearer of the regalia (DC 20 Will negates). A creature that saves is immune to this effect for 24 hours. If the aura is dispelled, the wearer can restore it as a standard action.</p>
<p>If the crown is worn while the wearer is wielding both an <em>orb</em> and <em>scepter of heaven,</em> the crown's caster level increases to 15th, effects the wearer creates with the good descriptor gain an additional +1 caster level increase, and her sacred bonus to AC and saves increases to +2. In addition, as a full-round action, the wearer can create an aura of sanctity for as long as she concentrates. This aura provides a +4 deflection bonus to AC and a +4 resistance bonus on saving throws against attacks made or effects created by evil creatures, as well as the benefits of a <em>magic circle against evil</em> and a <Link to="/spell/lesser_globe_of_invulnerability">lesser globe of invulnerability</Link>.</p>
<p>A crown of heaven bestows one <Link to="/rule/negative_level">negative level</Link> on any evil creature bearing it, which cannot be removed or overcome while carrying the crown. If the same creature carries an orb or scepter of heaven, it gains one additional negative level per object. An evil creature intentionally donning a crown of heaven gains an additional negative level and is affected as bestow curse (DC 17) immediately and every 24 hours that the crown is worn. A neutral character can attempt a DC 17 Fortitude save to avoid gaining these negative levels.</p>
<h3 id="magic-wondrous-crown_of_heaven-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/aura_of_doom">aura of doom</Link>, <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/dispel_evil">dispel evil</Link>, <Link to="/spell/magic_circle_against_evil">magic circle against evil</Link>, <Link to="/spell/tongues">tongues</Link>; <strong>Cost</strong> 75,000 gp</p>
</>};
const _crown_of_swords = {title: "Crown of Swords", jsx: <><h2 id="magic-wondrous-crown_of_swords-crown-of-swords">Crown of Swords</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 242</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 78</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This radiant crown of steel is bedecked with miniature <Link to="/eq-material/mithral">mithral</Link> swords. A crown of swords can be used up to 10 times per day. When struck in combat, the wearer may spend one use as an immediate action to create a <Link to="/eq-weapon/longsword">longsword</Link>-shaped <em>spiritual weapon</em> that then attacks her attacker. On the wearer's next turn, she may spend one additional use each round to continue attacking that target with the <em>spiritual weapon;</em> the <em>spiritual weapon</em> cannot be redirected and disappears if the target is killed or moves out of range. Multiple <em>spiritual weapons</em> may be created (even attacking the same target) if the wearer is attacked in subsequent rounds.</p>
<h3 id="magic-wondrous-crown_of_swords-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spiritual_weapon">spiritual weapon</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _crystal_helm = {title: "Crystal Helm", jsx: <><h2 id="magic-wondrous-crystal_helm-crystal-helm">Crystal Helm</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_sea">Blood of the Sea pg. 20</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 24,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This clear, spherical helm resembles a giant bowl the wearer inverts over his head. Donning or removing the crystal helm requires a standard action, as an invisible magical film stretches across the opening of the bowl. If a creature dons a crystal helm on land, it immediately fills with salt water. If a creature dons a crystal helm underwater, it immediately fills with air. So long as the bearer can breathe water or air, respectively, the crystal helm allows the wearer to breathe normally. The contents of a crystal helm constantly replenish and do not leak out of the bowl. A creature that dons the crystal helm without knowing its power may be in for a shock.</p>
<h3 id="magic-wondrous-crystal_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/air_breathing">air breathing</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 12,000 gp</p>
</>};
const _cyclops_helm = {title: "Cyclops Helm", jsx: <><h2 id="magic-wondrous-cyclops_helm-cyclops-helm">Cyclops Helm</h2>
<p><strong>Sources</strong> <Link to="/source/the_emerald_spire_superdungeon">The Emerald Spire Superdungeon pg. 124</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 5,600 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This helm is made from the husk of a <Link to="/monster/cyclops">cyclops's</Link> shrunken head, and grants a limited version of that creature's flash of insight ability. Once per day as an immediate action, the wearer can choose the result of the die roll instead of rolling her next attack roll, saving throw, skill check, or ability check.</p>
<h3 id="magic-wondrous-cyclops_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 2,800 gp</p>
</>};
const _dance_of_seven_veils = {title: "Dance of Seven Veils", jsx: <><h2 id="magic-wondrous-dance_of_seven_veils-dance-of-seven-veils">Dance of Seven Veils</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_135_runeplague">Pathfinder #135: Runeplague pg. 67</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> head or neck; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> -</p>
<p>This scarf is crafted from fine, almost transparent silk of a deep red hue. When worn about the head as a veil or the neck as a scarf, the dance of seven veils disguises the wearer in a different shape, as per <em>disguise self.</em> The wearer can cast <em>levitate</em> at will, gains a +4 competence bonus on <Link to="/skill/bluff">Bluff</Link> and <Link to="/skill/diplomacy">Diplomacy</Link> checks, and gains a +2 enhancement bonus to Intelligence and Charisma.</p>
<h3 id="magic-wondrous-dance_of_seven_veils-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/levitate">levitate</Link>, <Link to="/spell/feather_fall">feather fall</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _daylight_diadem = {title: "Daylight Diadem", jsx: <><h2 id="magic-wondrous-daylight_diadem-daylight-diadem">Daylight Diadem</h2>
<p><strong>Sources</strong> <Link to="/source/seers_of_the_drowned_city">Seers of the Drowned City pg. 53</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Four sunstone-embedded sunflowers adorn this golden diadem. The first daylight diadems were created far to the east by Keleshite worshipers of <Link to="/faith/sarenrae">Sarenrae</Link>, but their usefulness in battling undead has seen them become quite widespread. In the often overcast Sodden Lands, these magical diadems offer an additional comfort to those who enjoy the sun as well, serving as a constant reminder that regardless of the cloud cover above, the sun remains steadfast in its guardianship over the day.</p>
<p>As part of a standard action taken to <Link to="/ability/channel_positive_energy">channel positive energy</Link>, the wearer can activate a daylight diadem by removing a flower to extend the range of her channel positive energy ability to 60 feet. The removed flower is consumed upon use.</p>
<p>The wearer can also release the full brilliance of her daylight diadem in a single burst. With a command word, she causes all of the sunflowers remaining on the daylight diadem to be consumed and shed bright light in a 60-foot radius. This light counters or dispels any darkness spells of 4th level or lower and is treated as natural sunlight - the effect persists for a number of rounds equal to double the number of sunflowers consumed. While within the area of this light, all weapons are treated as good-aligned for the purpose of bypassing damage reduction and deal an additional 1d6 points of damage to evil creatures. This additional damage results directly from divine power and is therefore not subject to being reduced by resistance to energy. Creatures that are specifically hindered or harmed by sunlight take double this amount (2d6 points of damage per hit).</p>
<p>Once all four flowers have been used, a daylight diadem can no longer be activated, but each time the crown is exposed to the light of the rising sun, a new sunflower (to a maximum of four sunflowers) blooms on the diadem.</p>
<h3 id="magic-wondrous-daylight_diadem-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/sunbeam">sunbeam</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _death_mask = {title: "Death Mask", jsx: <><h2 id="magic-wondrous-death_mask-death-mask">Death Mask</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 58</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 6th<br/><strong>Slot</strong> head; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This elaborate wooden mask is carved in the image of Pharasma. The owner of a death mask can place the mask upon a corpse to ask the corpse up to three questions as if by <em>speak with dead,</em> except the corpse does not get a Will saving throw if the mask's owner is of a different alignment than the corpse had in life. This effect works as long as the head of the corpse is intact enough to fit the mask onto, no matter how damaged the corpse is otherwise. A death mask functions on a given corpse only once in this way; additional attempts to ask the corpse questions fail.</p>
<p>If a living person dons the death mask, her appearance changes to that of the last person whose corpse was spoken with using the mask, as <em>alter self.</em> The wearer resembles the deceased person as she looked in life.</p>
<h3 id="magic-wondrous-death_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/speak_with_dead">speak with dead</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _demon_mothers_mask = {title: "Demon Mother's Mask", jsx: <><h2 id="magic-wondrous-demon_mothers_mask-demon-mothers-mask">Demon Mother's Mask</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 263</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 56</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 3,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This primitive hyena mask is usually made of leather, but may be made of soft metal like copper or carved from an animal's skull. The wearer gains a +2 competence bonus on <Link to="/skill/handle_animal">Handle Animal</Link> and <Link to="/skill/heal">Heal</Link> checks. The wearer can smell when nearby creatures are in heat or otherwise especially fertile (creatures such as humans that can breed at any time of the year always smell fertile unless they are barren).</p>
<p>If <Link to="/faith/lamashtu">Lamashtu</Link> is the wearer's patron, the mask counts as an unholy symbol and a hole for a third eye appears in its forehead. The wearer can use <em>summon monster II</em> once per day to summon a <Link to="/template/fiendish">fiendish</Link> hyena, which obeys the wearer as if they shared a common language. The wearer may interbreed with animals within one size category of the wearer's size. The offspring of such unions are members of the mother's race with the fiendish simple template and bear monstrous aesthetic features of the father's race.</p>
<h3 id="magic-wondrous-demon_mothers_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_animals_or_plants">detect animals or plants</Link>, <Link to="/spell/polymorph">polymorph</Link>, <Link to="/spell/summon_monster_ii">summon monster II</Link>, creator must have 5 ranks in Handle Animal and Heal; <strong>Cost</strong> 1,800 gp</p>
</>};
const _dervish_sikke = {title: "Dervish Sikke", jsx: <><h2 id="magic-wondrous-dervish_sikke-dervish-sikke">Dervish Sikke</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 52</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This cylindrical felt hat, favored by <Link to="/arc-bard/dawnflower_dervish">Dawnflower dervishes</Link>, grants its wearer a +2 competence bonus on one <Link to="/skill/knowledge">Knowledge</Link> or <Link to="/skill/perform">Perform</Link> skill, chosen when the dervish sikke is created. Most dervish sikkes grant bonuses on <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> or Perform (dance) checks.</p>
<p>If the wearer is a <Link to="/class/bard">bard</Link>, he is considered 5 class levels higher for purposes of determining the effects of his bardic knowledge class feature. In addition, the bonuses granted by a bard's <Link to="/performance/inspire_courage">inspire courage</Link> and <Link to="/performance/inspire_competence">inspire competence</Link> class features are increased by 1. Finally, a bard wearing a dervish sikke can take 10 on any Perform skill check he has ranks in.</p>
<h3 id="magic-wondrous-dervish_sikke-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/timely_inspiration">timely inspiration</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _desert_veil = {title: "Desert Veil", jsx: <><h2 id="magic-wondrous-desert_veil-desert-veil">Desert Veil</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 4</Link><br/><strong>Aura</strong> moderate abjuration and conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> -</p>
<p>Small round mirrors adorn the edges of this yellow, Qadiran silk veil, which covers the wearer's mouth and nose. The veil protects the wearer against extreme temperatures, as per <em>endure elements.</em> In addition, once per day while in a warm or temperate desert, the wearer can speak a command word to create a 20-foot-radius oasis that functions like a casting of <em>grove of respite.</em> The oasis appears in a spot the wearer designates within 40 feet and disappears after 8 hours. Any creature outside the oasis that sees it must succeed at a DC 16 Will saving throw or dismiss it as a mirage to be ignored. A creature that steps inside the oasis, however, recognizes its substance.</p>
<h3 id="magic-wondrous-desert_veil-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/grove_of_respite">grove of respite</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _diabolical_masquerade_mask = {title: "Diabolical Masquerade Mask", jsx: <><h2 id="magic-wondrous-diabolical_masquerade_mask-diabolical-masquerade-mask">Diabolical Masquerade Mask</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 263</Link><br/><strong>Aura</strong> faint conjuration, enchantment, and illusion; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 2,900 gp; <strong>Weight</strong> 1 lb.</p>
<p>This masquerade mask resembles a handsome horned devil with red lenses in place of eyes. It functions as a <Link to="/magic-wondrous/hat_of_disguise">hat of disguise</Link>. The wearer can use <em>charm person</em> and <em>infernal healing</em> each once per day. When <em>infernal healing</em> is active, the mask becomes visible whether or not the wearer is using its disguise abilities (although all other elements of the disguise remain).</p>
<h3 id="magic-wondrous-diabolical_masquerade_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/infernal_healing">infernal healing</Link>; <strong>Cost</strong> 1,450 gp</p>
</>};
const _diadem_of_inspiring_rule = {title: "Diadem of Inspiring Rule", jsx: <><h2 id="magic-wondrous-diadem_of_inspiring_rule-diadem-of-inspiring-rule">Diadem of Inspiring Rule</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 31</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> -</p>
<p>This ornate, ostentatious diadem grants its wearer a +3 competence bonus to her <Link to="/feat/leadership">Leadership</Link> score.</p>
<h3 id="magic-wondrous-diadem_of_inspiring_rule-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _diadem_of_the_interplanetary_emissary_lashunta = {title: "Diadem of the Interplanetary Emissary (Lashunta)", jsx: <><h2 id="magic-wondrous-diadem_of_the_interplanetary_emissary_lashunta-diadem-of-the-interplanetary-emissary-lashunta">Diadem of the Interplanetary Emissary (Lashunta)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 231</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> head; <strong>Price</strong> 67,500 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This elaborate silver diadem features stylized antennae similar to those of a <Link to="/race/lashunta">lashunta</Link>. While worn, it maintains a constant planetary adaptation upon a wearer. The diadem's magic also enhances a lashunta wearer's telepathy, allowing her to mentally communicate with any creature that has a language, rather than only creatures that share a language with her.</p>
<h3 id="magic-wondrous-diadem_of_the_interplanetary_emissary_lashunta-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/planetary_adaptation">planetary adaptation</Link>, <Link to="/spell/tongues">tongues</Link>, creator must be a Lashunta; <strong>Cost</strong> 33,750 gp</p>
</>};
const _earth_child_faceguard = {title: "Earth Child Faceguard", jsx: <><h2 id="magic-wondrous-earth_child_faceguard-earth-child-faceguard">Earth Child Faceguard</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>Decorated with the emblems of the Earth Child cadre, an earth child faceguard is designed to refine the wearer's focus when fighting giants. The wearer gains the benefits of Earth Child Style, regardless of whether she meets the prerequisites. If the wearer does not possess the defensive training racial trait, the dodge bonus to AC against giants is reduced to +2. If the wearer already possesses the Earth Child Style feat, she can enter the earth child stance as a free action.</p>
<h3 id="magic-wondrous-earth_child_faceguard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/earth_child_style">Earth Child Style</Link>, <Link to="/spell/know_the_enemy">know the enemy</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _explorers_pith_helmet = {title: "Explorer's Pith Helmet", jsx: <><h2 id="magic-wondrous-explorers_pith_helmet-explorers-pith-helmet">Explorer's Pith Helmet</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 13</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 3,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>This colonial-style helmet protects the wearer from jungle nuisances. The wearer is affected by a constant <em>endure elements</em> effect (as the spell, hot weather only) and gains a +4 competence bonus on saving throws against the distraction ability of swarms. In addition, once per day the wearer can conjure an invisible porter that acts as either a <em>floating disk</em> or an <em>unseen servant</em> (wearer's choice).</p>
<h3 id="magic-wondrous-explorers_pith_helmet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/floating_disk">floating disk</Link>, <Link to="/spell/hide_from_animals">hide from animals</Link>, <Link to="/spell/unseen_servant">unseen servant</Link>; <strong>Cost</strong> 1,600 gp</p>
</>};
const _falcon_crown = {title: "Falcon Crown", jsx: <><h2 id="magic-wondrous-falcon_crown-falcon-crown">Falcon Crown</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_82_secrets_of_the_sphinx">Pathfinder #82: Secrets of the Sphinx pg. 63</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 42,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This metal headdress is shaped like a falcon's head and enameled in brilliant colors. Originally crafted for a wizard dedicated to <Link to="/faith/horus">Horus</Link> as a reward from his pharaoh for his prowess on the battlefield, the falcon crown was believed lost when the wizard was struck down by an ancient blue dragon. Centuries later, however, archaeologists discovered the falcon crown among the ruins of Tumen. Researcher-priests of <Link to="/faith/nethys">Nethys</Link> acquired the crown shortly after, and when the Nethysian priestess Serethet became the Forgotten Pharaoh, she claimed the falcon crown for herself.</p>
<p>The wearer of the falcon crown gains a +2 insight bonus to her Armor Class. In addition, up to three times per day as an immediate action, the wearer of the falcon crown can sacrifice a prepared spell or unused spell slot of 1st level or higher and transform it into a damaging ray, targeting any foe within 30 feet as a ranged touch attack. This ray deals 1d4 points of damage for every level of the spell or spell slot sacrificed. A non-spellcaster cannot create rays with the falcon crown, but can still gain the AC bonus.</p>
<h3 id="magic-wondrous-falcon_crown-construction">Construction</h3>
<p><strong>Requirements</strong> Arcane Blast, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/foresight">foresight</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 21,000 gp</p>
</>};
const _false_face = {title: "False Face", jsx: <><h2 id="magic-wondrous-false_face-false-face">False Face</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 229</Link><br/><strong>Aura</strong> none (see text); <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 1,600 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This simple, hand-painted party mask emanates no magical aura. Its true usefulness is revealed only when it's worn. When a person dons the mask, she instantly assumes the appearance of single specific Small or Medium humanoid creature. Each mask has a single "face" that can't be changed once the item is created. This effect otherwise works as <em>disguise self.</em></p>
<h3 id="magic-wondrous-false_face-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/magic_aura">magic aura</Link>; <strong>Cost</strong> 800 gp</p>
</>};
const _flame_of_bakrakhan = {title: "Flame of Bakrakhan", jsx: <><h2 id="magic-wondrous-flame_of_bakrakhan-flame-of-bakrakhan">Flame of Bakrakhan</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins pg. 29</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This ancient Thassilonian diadem is crafted in the shape of an enraged face with an enormous ruby in the center. The gem allows its wearer to channel her rage into pure flame. While under the effects of rage, as a standard action the wearer can expend 1 round of rage or <Link to="/ability/raging_song">raging song</Link> to cause the ruby to release a beam of fire like a miniature hellfire flume. If the wearer succeeds at a ranged touch attack against a creature or object within 30 feet, the beam deals 2d6 points of fire damage to that target. If the wearer instead expends 3 rounds of rage, bloodrage, or raging song, the beam becomes a 60-foot line instead, dealing 5d6 points of fire damage to all creatures and objects along that line (Reflex DC 14 negates).</p>
<h3 id="magic-wondrous-flame_of_bakrakhan-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/scorching_ray">scorching ray</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _fog_cutting_lenses = {title: "Fog-Cutting Lenses", jsx: <><h2 id="magic-wondrous-fog_cutting_lenses-fog-cutting-lenses">Fog-Cutting Lenses</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 69</Link>, <Link to="/source/pathfinder_4_fortress_of_the_stone_giants">Pathfinder #4: Fortress of the Stone Giants pg. 50</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 421</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> face; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These goggles are made of polished rock crystal, with frames of polished brass and a simple leather strap and buckle sized for a giant's head (but easily adjustable for smaller wearers). The goggles allow the wearer to see through magical and normal fogs, mists, and similar obscurement. They do not confer darkvision or low-light vision. Further, the goggles distort and skew vision strangely, imposing a -4 penalty on <Link to="/skill/perception">Perception</Link> checks.</p>
<h3 id="magic-wondrous-fog_cutting_lenses-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/fog_cloud">fog cloud</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _frontoviks_gas_mask = {title: "Frontovik's Gas Mask", jsx: <><h2 id="magic-wondrous-frontoviks_gas_mask-frontoviks-gas-mask">Frontovik's Gas Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_71_rasputin_must_die">Pathfinder #71: Rasputin Must Die! pg. 60</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 17,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A frontovik's gas mask has the appearance of a typical Zelinsky-Kummant gas mask used by the Russian army: a rubberized cloth bag worn over the face, with two thick glass eyepieces and a rectangular filter canister. Named for the frontovik, the typical combat-hardened veteran of the front line, a frontovik's gas mask allows its wearer to breathe freely, even underwater or in a vacuum, as well as making its wearer immune to harmful gases and vapors, including inhaled diseases, poisons, and magic spells such as <Link to="/spell/cloudkill">cloudkill</Link> and <Link to="/spell/stinking_cloud">stinking cloud</Link>. In addition, the wearer can see through magical and normal clouds, fogs, mists, and similar effects that grant <Link to="/rule/concealment">concealment</Link>, but only so long as the wearer is within the area of such concealment. A frontovik's gas mask does not grant any other kind of vision (such as darkvision or low-light vision). Wearing a gas mask imposes a -2 penalty on hearing- and sight-based <Link to="/skill/perception">Perception</Link> checks.</p>
<h3 id="magic-wondrous-frontoviks_gas_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/fog_cloud">fog cloud</Link>, <Link to="/spell/life_bubble">life bubble</Link>; <strong>Cost</strong> 8,500 gp</p>
</>};
const _frostwild_bridle = {title: "Frostwild Bridle", jsx: <><h2 id="magic-wondrous-frostwild_bridle-frostwild-bridle">Frostwild Bridle</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 28</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 48,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>When this bridle of crystal-studded white leather is placed on a horse or similar mount, the animal's eyes emit a bright azure glow and its hair glistens with magical frost. A frostwild bridle provides cold resistance 20 to its wearer. Also, three times per day on the rider's command, the animal wearing a frostwild bridle can breathe a 60-foot cone of frost that deals 9d6 points of cold damage to all creatures in the area. A successful DC 17 Reflex save halves the damage.</p>
<h3 id="magic-wondrous-frostwild_bridle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cone_of_cold">cone of cold</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 24,000 gp</p>
</>};
const _gag_of_silence = {title: "Gag of Silence", jsx: <><h2 id="magic-wondrous-gag_of_silence-gag-of-silence">Gag of Silence</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 21</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black leather cord has a red wooden ball attached at its center. When the cord is tied around a creature's head and the wooden ball is placed in the creature's mouth, the creature cannot speak or make any vocal sounds, including verbal components of spells. When removed from the creature, the ball breaks off from the leather cord, ending the effect. A creature that is not otherwise restrained can easily untie the gag and remove it.</p>
<h3 id="magic-wondrous-gag_of_silence-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/silence">silence</Link>; <strong>Cost</strong> 250 gp</p>
</>};
const _goz_mask = {title: "Goz Mask", jsx: <><h2 id="magic-wondrous-goz_mask-goz-mask">Goz Mask</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 185</Link>, <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 298</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> head; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Shortly after the Eye of Abendego began, the <Link to="/rule/storm_kindlers">Storm Kindlers</Link> created enchanted masks to aid in the navigation of the often storm-lashed swamps. Today, many of these distinctive masks remain, now worn by humanoid chieftains and Koboto witch doctors. The masks are often defaced, with their original appearance twisted into monstrous or demonic visages. Their new owners refer to them as goz masks.</p>
<p>A goz mask allows the wearer to see through fog, smoke, and other obscuring vapors as if they did not exist. This ability functions underwater as well, allowing the wearer to see through thick silt and other aquatic precipitates. Additionally, the wearer is treated as one size category larger and gains a +4 bonus on all saving throws made to resist the effects of <Link to="/rule/wind">wind</Link>. A goz mask allows its wearer to breathe water for 60 minutes per day - these minutes need not be consecutive, but must be expended in 10-minute increments.</p>
<h3 id="magic-wondrous-goz_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/control_winds">control winds</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _grapplers_mask = {title: "Grappler's Mask", jsx: <><h2 id="magic-wondrous-grapplers_mask-grapplers-mask">Grappler's Mask</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 242</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 306</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This mask is fashioned from dark leather decorated with geometrical patterns that emphasize the wearer's fearsomeness. It covers the wearer's face, but leaves his mouth and eyes uncovered. The wearer may attempt to <Link to="/rule/bull_rush">bull rush</Link> and <Link to="/rule/grapple">grapple</Link> without provoking attacks of opportunity.</p>
<h3 id="magic-wondrous-grapplers_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _gray_gamblers_hat = {title: "Gray Gambler's Hat", jsx: <><h2 id="magic-wondrous-gray_gamblers_hat-gray-gamblers-hat">Gray Gambler's Hat</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 264</Link><br/><strong>Aura</strong> faint illusion and transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> -</p>
<p>This crumpled leather hat has roughly hammered metal studs around its brim, and is often worn by worshipers of <Link to="/faith/droskar">Droskar</Link> who venerate the dwarf god for his cheating aspect. The wearer can use it as a <Link to="/magic-wondrous/hat_of_disguise">hat of disguise</Link>, but only to disguise herself as a dwarf. Three times per day as a free action, the wearer can manipulate a rolled die within 10 feet (such as in a game of chance), altering the roll by a value of 1 in either direction. The wearer adds 1 to the DC of any enchantment (compulsion) spells she casts.</p>
<h3 id="magic-wondrous-gray_gamblers_hat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/mage_hand">mage hand</Link>; <strong>Cost</strong> 1,200 gp</p>
</>};
const _greathelm_of_the_mammoth_lord = {title: "Greathelm of the Mammoth Lord", jsx: <><h2 id="magic-wondrous-greathelm_of_the_mammoth_lord-greathelm-of-the-mammoth-lord">Greathelm of the Mammoth Lord</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 133</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 24,700 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This hide helm is a powerful variant of the more common <Link to="/magic-wondrous/helm_of_the_mammoth_lord">helm of the Mammoth Lord</Link>. Like its lesser incarnation, a greathelm of the Mammoth Lord is set with plates of ivory carved with runes, with a pair of tusks curving down either side of the wearer's face for cheek guards. The helm's tusks provide a gore attack dealing 1d8 points of damage for a Medium wearer (or 1d6 points of damage for a Small wearer) and count as magic and cold for the purpose of overcoming damage reduction. The greathelm of the Mammoth Lord also protects the wearer from cold environments as per <em>endure elements.</em></p>
<p>Furthermore, it provides a +5 competence bonus on <Link to="/skill/handle_animal">Handle Animal</Link>, <Link to="/skill/ride">Ride</Link>, and <Link to="/ability/wild_empathy">wild empathy</Link> checks with elephants, mammoths, mastodons, and other elephant-like creatures. On command, the wearer can use detect animals or plants or speak with animals, but only to detect or communicate with elephant-like creatures. Once per day, the wearer can transform into a mammoth (treat as an <Link to="/monster/mastodon">mastodon</Link>) as <em>beast shape III.</em></p>
<h3 id="magic-wondrous-greathelm_of_the_mammoth_lord-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_iii">beast shape III</Link>, <Link to="/spell/charm_animal">charm animal</Link>, <Link to="/spell/detect_animals_or_plants">detect animals or plants</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, creator must have 5 ranks in Handle Animal and Ride; <strong>Cost</strong> 12,350 gp</p>
</>};
const _grim_helm = {title: "Grim Helm", jsx: <><h2 id="magic-wondrous-grim_helm-grim-helm">Grim Helm</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_139_the_dead_road">Pathfinder #139: The Dead Road pg. 64</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 48,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>The matte surface of this pitted gray helm seems to absorb light, rather than reflect it. The skull mask that serves as its visor is a constant reminder of the fate that awaits all mortals. The wearer of the helm is immune to fear effects but cannot gain the benefit of any morale bonuses.</p>
<p>A creature that comes within 20 feet of the wearer must succeed at a Will save (DC 14) or lose the benefit of morale bonuses while it remains in that area. A creature that succeeds at this saving throw is immune to this ability for 24 hours.</p>
<h3 id="magic-wondrous-grim_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>; <strong>Cost</strong> 24,000 gp</p>
</>};
const _halo_of_inner_calm = {title: "Halo of Inner Calm", jsx: <><h2 id="magic-wondrous-halo_of_inner_calm-halo-of-inner-calm">Halo of Inner Calm</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 242</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 173</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This silvery ring looks like a halo. When worn by a <Link to="/race/tiefling">tiefling</Link> it hovers just above his head, though it still uses the head magic item slot. It helps to calm the baser emotions and the dark whispers that plague tieflings, granting the wearer a +4 resistance bonus on saving throws against all spells with the emotion descriptor. When worn by a tiefling of a good alignment, it provides spell resistance 13 against spells with the evil descriptor and a +2 sacred bonus on saving throws.</p>
<h3 id="magic-wondrous-halo_of_inner_calm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/holy_aura">holy aura</Link>, creator must be a tiefling of good alignment; <strong>Cost</strong> 8,000 gp</p>
</>};
const _halo_of_menace = {title: "Halo of Menace", jsx: <><h2 id="magic-wondrous-halo_of_menace-halo-of-menace">Halo of Menace</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 242</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 89</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 84,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>When placed over the head, this halo of shimmering polished steel floats above it, though it still takes up the head slot. The halo constantly radiates a 20-foot-radius aura from its wearer. Any hostile creature within the aura must succeed at a DC 20 Will save or take a -2 penalty on attack rolls, on saving throws, and to AC for the next 24 hours or until it hits the wearer with an attack or damages it with a spell, spell-like ability, or supernatural ability. Chaotic creatures take a -2 penalty on this saving throw. A creature that has resisted or broken the effect of the halo of menace cannot be affected by the same wearer's aura for 24 hours. The aura is a mind-affecting effect.</p>
<h3 id="magic-wondrous-halo_of_menace-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/orders_wrath">order's wrath</Link>, creator must be an <Link to="/race/aasimar">aasimar</Link> or an <Link to="/family/archon">archon</Link>; <strong>Cost</strong> 42,000 gp</p>
</>};
const _hat_of_disguise = {title: "Hat of Disguise", jsx: <><h2 id="magic-wondrous-hat_of_disguise-hat-of-disguise">Hat of Disguise</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 243</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 516</Link>, <Link to="/source/curse_of_the_riven_sky">Curse of the Riven Sky pg. 30</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 1st (normal), 3rd (greater)<br/><strong>Slot</strong> head; <strong>Price</strong> 1,800 gp (normal), 12,000 gp (greater); <strong>Weight</strong> -</p>
<p>This apparently normal hat allows its wearer to alter her appearance as with a <em>disguise self</em> spell. As part of the disguise, the hat can be changed to appear as a comb, ribbon, headband, cap, coif, hood, helmet, or other headwear.</p>
<p>The greater hat of disguise allows its wearer to alter her appearance. It functions as an <em>alter self</em> spell (as opposed to <em>disguise self</em>). The hat becomes a part of the disguise and can be a hat, a helmet, a headscarf, and so forth.</p>
<h3 id="magic-wondrous-hat_of_disguise-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link> (normal) or <Link to="/spell/alter_self">alter self</Link> (greater); <strong>Cost</strong> 900 gp (normal), 6,000 gp (greater)</p>
</>};
const _hat_of_hatreds = {title: "Hat of Hatreds", jsx: <><h2 id="magic-wondrous-hat_of_hatreds-hat-of-hatreds">Hat of Hatreds</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 346</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> moderate illusion; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Weight</strong> -</p>
<p>This hat performs in all ways like a <em>hat of disguise</em> until its owner attempts to use it to disguise himself in the presence of a hostile creature. Once he does, the hat causes him to assume the guise of the creature or person the hostile creature most wants to harm. The hat never causes the wearer to assume the appearance of someone the viewer wouldn't harm if he had the opportunity (for example, the greatly feared leader of the local temple).</p>
<p>Once the hat reveals its true abilities, it no longer responds to attempts by its wearer to change his appearance. Instead, it automatically causes him to take on the guise of someone known to and despised by those viewing him, complete with supplementary illusions that make that wearer appear disoriented, injured, or weak. For example, in a goblin lair, the wearer might look like the tribe's chief, but sleepy and vulnerable. In a human town, the wearer may look like the hated local bully, drunk and staggering. In an evil town, the wearer looks like a confused visitor and appears to be an ideal target to victimize with some crime.</p>
<p>Curse-breaking magic is necessary to remove the hat.</p>
<h3 id="magic-wondrous-hat_of_hatreds-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/hat_of_disguise">hat of disguise</Link>; <strong>Cost</strong> -</p>
</>};
const _hat_of_infinite_disguises = {title: "Hat of Infinite Disguises", jsx: <><h2 id="magic-wondrous-hat_of_infinite_disguises-hat-of-infinite-disguises">Hat of Infinite Disguises</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 54</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 11th<br/><strong>Slot</strong> head; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This large, elaborate, and colorful hat is festooned with trinkets from at least a dozen different cultures. The wearer can disguise herself (but not other creatures) at will with a command word, as per <em>veil.</em> A second command word removes the disguise. When part of a disguise, the hat can be changed to appear as any appropriate accessory.</p>
<h3 id="magic-wondrous-hat_of_infinite_disguises-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/veil">veil</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _hat_of_the_seven_winds = {title: "Hat of the Seven Winds", jsx: <><h2 id="magic-wondrous-hat_of_the_seven_winds-hat-of-the-seven-winds">Hat of the Seven Winds</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 189</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black tricorne hat is embroidered with the pattern of a ship. The wearer does not take any penalties from rain, takes penalties from <Link to="/rule/wind">high wind speeds</Link> as though she were one size category larger than she actually is, and gains a +4 bonus on saving throws against wind effects.</p>
<h3 id="magic-wondrous-hat_of_the_seven_winds-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/control_winds">control winds</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _helm_of_brilliance = {title: "Helm of Brilliance", jsx: <><h2 id="magic-wondrous-helm_of_brilliance-helm-of-brilliance">Helm of Brilliance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 243</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 518</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 13th<br/><strong>Slot</strong> head; <strong>Price</strong> 125,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This normal-looking helm takes its true form and manifests its powers when the user dons it and speaks the command word. Made of brilliant silver and polished steel, a newly created helm is set with large magic gems: 10 diamonds, 20 rubies, 30 fire opals, and 40 opals. When struck by bright light, the helm scintillates and sends forth reflective rays in all directions from its crown-like, gem-tipped spikes. The jewels' functions are as follows:</p>
<ul>
<li>Diamond: <em>Prismatic spray</em> (save DC 20)</li>
<li>Ruby: <em>Wall of fire</em></li>
<li>Fire opal: <em>Fireball</em> (10d6, Reflex DC 20 half)</li>
<li>Opal: <em>Daylight</em></li>
</ul>
<p>The helm may be used once per round, but each gem can perform its spell-like power just once. Until all its jewels are depleted, a helm of brilliance also has the following magical properties when activated.</p>
<p>It emanates a bluish light when undead are within 30 feet. This light causes 1d6 points of damage per round to all such creatures within that range.</p>
<p>The wearer may command any weapon he wields to become a <Link to="/magic-enh/flaming">flaming</Link> weapon. This is in addition to whatever abilities the weapon may already have (unless the weapon already is a flaming weapon). The command takes 1 round to take effect.</p>
<p>The helm provides fire resistance 30. This protection does not stack with similar protection from other sources.</p>
<p>Once all its jewels have lost their magic, the helm loses its powers and the gems turn to worthless powder. Removing a jewel destroys it.</p>
<p>If a creature wearing the helm is damaged by magical fire (after the fire protection is taken into account) and fails an additional DC 15 Will save, the remaining gems on the helm overload and detonate. Remaining diamonds become <em>prismatic sprays</em> that each randomly target a creature within range (possibly the wearer), rubies become straight-line <em>walls of fire</em> extending outward in a random direction from the helm wearer, and fire opals become <em>fireballs</em> centered on the helm wearer. The opals and the helm itself are destroyed.</p>
<h3 id="magic-wondrous-helm_of_brilliance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_undead">detect undead</Link>, <Link to="/spell/fireball">fireball</Link>, <Link to="/spell/flame_blade">flame blade</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/prismatic_spray">prismatic spray</Link>, <Link to="/spell/protection_from_energy">protection from energy</Link>, <Link to="/spell/wall_of_fire">wall of fire</Link>; <strong>Cost</strong> 62,500 gp</p>
<h2 id="magic-wondrous-helm_of_brilliance-helm-of-brilliance-lesser">Helm of Brilliance (Lesser)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 243</Link>, <Link to="/source/classic_treasures_revisited">Classic Treasures Revisited pg. 31</Link><br/><strong>Aura</strong> moderate varied; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 36,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This helm functions like a helm of brilliance but is lower-powered. Instead of the standard helm's allotment of gems, the lesser helm has 10 diamonds (<em>fireball,</em> 10d6 damage, Reflex DC 20 half), 20 corals (<em>flaming sphere</em>), 30 garnets (<em>scorching ray</em>), and 40 agates (<em>light</em>). It still glows near and harms undead, has the <em>flaming</em> weapon special ability, and provides fire resistance (though only 20 instead of 30).</p>
<p>Just like the standard helm, the wearer risks detonation if damaged by magical fire; diamonds become <em>fireballs</em> centered on the wearer, corals become <em>flaming spheres</em> in and adjacent to the wearer's space, garnets become <em>scorching rays</em> that fire randomly at creatures in range, and the agates and the helm itself are destroyed.</p>
<h3 id="magic-wondrous-helm_of_brilliance-construction">Construction</h3>
<p><strong>Requirements</strong> Craft Wondrous Item, <em>detect undead, fireball, flame blade,</em> <Link to="/spell/flaming_sphere">flaming sphere</Link>, <Link to="/spell/light">light</Link>, <em>protection from energy,</em> <Link to="/spell/scorching_ray">scorching ray</Link>; <strong>Cost</strong> 18,000 gp</p>
</>};
const _helm_of_comprehend_languages_and_read_magic = {title: "Helm of Comprehend Languages and Read Magic", jsx: <><h2 id="magic-wondrous-helm_of_comprehend_languages_and_read_magic-helm-of-comprehend-languages-and-read-magic">Helm of Comprehend Languages and Read Magic</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 243</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 518</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 4th<br/><strong>Slot</strong> head; <strong>Price</strong> 5,200 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Appearing as a normal helmet, a helm of comprehend languages and read magic grants its wearer the ability to understand the spoken words of any creature and to read text in any language and any magical writing. The wearer gains a +5 competence bonus on <Link to="/skill/linguistics">Linguistics</Link> checks to understand messages written in incomplete, archaic, or exotic forms. Note that understanding a magical text does not necessarily imply ability to use its spells.</p>
<h3 id="magic-wondrous-helm_of_comprehend_languages_and_read_magic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/read_magic">read magic</Link>; <strong>Cost</strong> 2,600 gp</p>
</>};
const _helm_of_electric_radiance = {title: "Helm of Electric Radiance", jsx: <><h2 id="magic-wondrous-helm_of_electric_radiance-helm-of-electric-radiance">Helm of Electric Radiance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 243</Link>, <Link to="/source/classic_treasures_revisited">Classic Treasures Revisited pg. 31</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 13th<br/><strong>Slot</strong> head; <strong>Price</strong> 125,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>The helm of electric radiance is similar to a helm of brilliance, except its spells focus on electricity rather than fire. Other aspects of the helm, such as detecting and damaging undead, remain unchanged. The helm has 10 sapphires that can be used for chain lightning, 20 pieces of amber that can be used for lightning bolt, 30 pieces of petrified wood that can be used for shocking sphere (as flaming sphere but dealing electricity damage), and 40 opals that can be used for daylight. In addition, the wearer gains resistance to electricity 30 and his weapons become shocking weapons instead of flaming weapons.</p>
<h3 id="magic-wondrous-helm_of_electric_radiance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/chain_lightning">chain lightning</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/detect_undead">detect undead</Link>, <Link to="/spell/flaming_sphere">flaming sphere</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>, <Link to="/spell/protection_from_energy">protection from energy</Link>, <Link to="/spell/shocking_grasp">shocking grasp</Link>; <strong>Cost</strong> 62,500 gp</p>
</>};
const _helm_of_fearsome_mien = {title: "Helm of Fearsome Mien", jsx: <><h2 id="magic-wondrous-helm_of_fearsome_mien-helm-of-fearsome-mien">Helm of Fearsome Mien</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 244</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 306</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This metal helm is made to look like the wearer has large fangs and other features resembling those of a fearsome predator. If the wearer is a <Link to="/class/barbarian">barbarian</Link>, she can use the <Link to="/ragepower/intimidating_glare">intimidating glare</Link> rage power whenever she rages. The helm has no effect if the wearer is not a barbarian (or another class with the rage class feature).</p>
<h3 id="magic-wondrous-helm_of_fearsome_mien-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cause_fear">cause fear</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _helm_of_ikimizi = {title: "Helm of Ikimizi", jsx: <><h2 id="magic-wondrous-helm_of_ikimizi-helm-of-ikimizi">Helm of Ikimizi</h2>
<p><strong>Sources</strong> <Link to="/source/lost_kingdoms">Lost Kingdoms pg. 32</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> -; <strong>Weight</strong> 3 lbs.</p>
<p>The helm of Ikimizi grants its wearer a +4 circumstance bonus on attack rolls made to confirm critical hits. However, whenever the wearer threatens a critical hit (regardless of whether or not he actually succeeds), he immediately becomes berserk (gaining all the benefits and drawbacks of the <Link to="/class/barbarian">barbarian's</Link> rage ability). For 1d4+1 rounds, he is compelled to attack the nearest creature until it has fallen, regardless of whether the target is friend or foe.</p>
<p>In addition, whenever the wearer of a helm of Ikimizi slays a creature, he must spend at least 1 full-round action feasting on the flesh of the fallen creature, heedless of anything or anyone else around him.</p>
<p>Once it is equipped, the helm of Ikimizi can only be removed by a <Link to="/spell/remove_curse">remove curse</Link> spell.</p>
<h3 id="magic-wondrous-helm_of_ikimizi-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/helm_of_comprehend_languages_and_read_magic">helm of comprehend languages and read magic</Link>, <Link to="/magic-wondrous/helm_of_telepathy">helm of telepathy</Link>, <Link to="/magic-wondrous/helm_of_underwater_action">helm of underwater action</Link>; <strong>Cost</strong> -</p>
</>};
const _helm_of_ooze = {title: "Helm of Ooze", jsx: <><h2 id="magic-wondrous-helm_of_ooze-helm-of-ooze">Helm of Ooze</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 31</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 21,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This bulky, rusted helm incorporates a pair of goggles that sit on the wearer's brow. The wearer of a helm of ooze control gains a limited ability to telepathically command oozes. Once per day as a standard action, the wearer can attempt to gain control over a single ooze within 60 feet. The ooze must succeed at a DC 17 Will save or fall under the wearer's mental control. This compulsion affects even mindless oozes. The control offered by the helm is very limited, and the wearer is able to issue only one of the following commands at a time, as a move action, to a controlled ooze within 60 feet.</p>
<p><strong>Attack:</strong> The ooze attacks the nearest creature.</p>
<p><strong>Halt:</strong> The ooze remains in place. It does not take any actions but is not considered helpless.</p>
<p><strong>Move:</strong> The ooze moves toward a point in space that the wearer can see.</p>
<p>The wearer can control up to 20 Hit Dice worth of oozes at any given time. An ooze with 5 or more Hit Dice can attempt a new Will save each day to free itself from the wearer's control. An ooze ordered to halt receives a new Will save to overcome the helm's control if attacked. Oozes with an Intelligence score, as well as those with 11 or more Hit Dice, are immune to this effect.</p>
<p>The wearer can issue a command to multiple controlled oozes with a single move action, but if she does, each ooze receives the same command. Oozes that have been issued a command continue to follow that command until a new command is issued or they are released from the helm's control. Removing the helm does not release the oozes from control, but the helm must be worn to issue new commands. If 24 hours pass without the helm being worn, then all affected oozes are released from control.</p>
<h3 id="magic-wondrous-helm_of_ooze-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_command">greater command</Link>; <strong>Cost</strong> 10,750 gp</p>
</>};
const _helm_of_opposite_alignment = {title: "Helm of Opposite Alignment", jsx: <><h2 id="magic-wondrous-helm_of_opposite_alignment-helm-of-opposite-alignment">Helm of Opposite Alignment</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 347</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 540</Link></p>
<p><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> head; <strong>Weight</strong> 3 lbs.</p>
<p>When placed upon the head, this item's curse immediately takes effect (Will DC 15 negates). On a failed save, the alignment of the wearer is radically altered to an alignment as different as possible from the former alignment - good to evil, chaotic to lawful, neutral to some extreme commitment (LE, LG, CE, or CG). Alteration in alignment is mental as well as moral, and the individual changed by the magic thoroughly enjoys his new outlook. A character who succeeds on his save can continue to wear the helmet without suffering the effect of the curse, but if he takes it off and later puts it on again, another save is required.</p>
<p>Only a <Link to="/spell/wish">wish</Link> or a <Link to="/spell/miracle">miracle</Link> can restore a character's former alignment, and the affected individual does not make any attempt to return to the former alignment. In fact, he views the prospect with horror and avoids it in any way possible. If a character of a class with an alignment requirement is affected, an <Link to="/spell/atonement">atonement</Link> spell is needed as well if the curse is to be obliterated. When a <em>helm of opposite alignment</em> has functioned once, it loses its magical properties.</p>
<h3 id="magic-wondrous-helm_of_opposite_alignment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/hat_of_disguise">hat of disguise</Link>, <Link to="/magic-wondrous/helm_of_comprehend_languages_and_read_magic">helm of comprehend languages and read magic</Link>, <Link to="/magic-wondrous/helm_of_telepathy">helm of telepathy</Link>; <strong>Cost</strong> -</p>
</>};
const _helm_of_reclamation = {title: "Helm of Reclamation", jsx: <><h2 id="magic-wondrous-helm_of_reclamation-helm-of-reclamation">Helm of Reclamation</h2>
<p><strong>Sources</strong> <Link to="/source/classic_treasures_revisited">Classic Treasures Revisited pg. 31</Link><br/><strong>Aura</strong> strong varied; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 80,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>The helm of reclamation is designed to destroy large groups of undead or powerful individual undead creatures, and is often used by undead-hating clerics with a flair for the dramatic. The gems of this helm produce <em>sunburst</em> (10 yellow diamonds), <em>searing light</em> (30 bloodstones), and <em>daylight</em> (40 opals). Like a standard <Link to="/magic-wondrous/helm_of_brilliance">helm of brilliance</Link>, it glows near and harms undead, and has the <Link to="/magic-enh/flaming">flaming</Link> weapon ability, but does not protect against fire or risk detonation.</p>
<h3 id="magic-wondrous-helm_of_reclamation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/detect_undead">detect undead</Link>, <Link to="/spell/flame_blade">flame blade</Link>, <Link to="/spell/searing_light">searing light</Link>, <Link to="/spell/sunburst">sunburst</Link>; <strong>Cost</strong> 40,000 gp</p>
</>};
const _helm_of_telepathy = {title: "Helm of Telepathy", jsx: <><h2 id="magic-wondrous-helm_of_telepathy-helm-of-telepathy">Helm of Telepathy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 244</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 518</Link><br/><strong>Aura</strong> faint divination and enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This pale metal or ivory helm covers much of the head when worn. The wearer can use <em>detect thoughts</em> at will. Furthermore, he can send a telepathic message to anyone whose surface thoughts he is reading (allowing two-way communication). Once per day, the wearer of the helm can implant a <em>suggestion</em> (as the spell, Will DC 14 negates) along with his telepathic message.</p>
<h3 id="magic-wondrous-helm_of_telepathy-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/suggestion">suggestion</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _helm_of_teleportation = {title: "Helm of Teleportation", jsx: <><h2 id="magic-wondrous-helm_of_teleportation-helm-of-teleportation">Helm of Teleportation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 244</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 518</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 73,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>A character wearing this helm may <em>teleport</em> three times per day, instantly transporting himself and objects he might be carrying on his person to a designated destination, exactly as if he had cast the spell of the same name.</p>
<h3 id="magic-wondrous-helm_of_teleportation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/teleport">teleport</Link>; <strong>Cost</strong> 36,750 gp</p>
</>};
const _helm_of_the_fanged_crown = {title: "Helm of the Fanged Crown", jsx: <><h2 id="magic-wondrous-helm_of_the_fanged_crown-helm-of-the-fanged-crown">Helm of the Fanged Crown</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 86</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This <Link to="/rule/gray_maidens">Gray Maiden</Link>-style helm has an ornate crown-like pattern sculpted into its brow. The first such helms were created in the final days of Queen Ileosa's reign for use by commanders in the organization, but her loyalists have had additional copies made in her honor since her fall from power, and many of the Erinyes Company proudly wear such helms today.</p>
<p>A helm of the Fanged Crown allows its wearer to use heroism on herself once per day as a standard action. However, the spell's bonuses act as penalties instead on attack rolls and skill checks against devils, devilbound creatures, and creatures with the infernal sorcerer bloodline, and on saving throws against effects generated by such creatures. Once activated, the effects last for 3 hours or until the helm is removed.</p>
<h3 id="magic-wondrous-helm_of_the_fanged_crown-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _helm_of_the_mammoth_lord = {title: "Helm of the Mammoth Lord", jsx: <><h2 id="magic-wondrous-helm_of_the_mammoth_lord-helm-of-the-mammoth-lord">Helm of the Mammoth Lord</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North pg. 29</Link>, <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 244</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This hide helm is set with plates of ivory carved with primitive runes, with a pair of tusks curving down on either side of the wearer's face for cheek guards. The tusks of the helm provide a gore attack dealing 1d6 points of damage for a Medium wearer (or 1d4 points of damage for a Small wearer) and count as a magic weapon for the purposes of overcoming damage reduction.</p>
<p>The helm of the Mammoth Lord also protects the wearer from cold environments as the <em>endure elements</em> spell. Furthermore, it provides a +5 competence bonus on <Link to="/skill/handle_animal">Handle Animal</Link>, <Link to="/skill/ride">Ride</Link>, and <Link to="/ability/wild_empathy">wild empathy</Link> checks with elephants, mammoths, mastodons, and other elephant-like creatures.</p>
<p>On command, the wearer may use <em>detect animals or plants</em> or <em>speak with animals,</em> but only to detect or communicate with elephant-like creatures.</p>
<h3 id="magic-wondrous-helm_of_the_mammoth_lord-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/charm_animal">charm animal</Link>, <Link to="/spell/detect_animals_or_plants">detect animals or plants</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, creator must have 5 ranks in Handle Animal and Ride; <strong>Cost</strong> 4,250 gp</p>
</>};
const _helm_of_the_serpent_king = {title: "Helm of the Serpent King", jsx: <><h2 id="magic-wondrous-helm_of_the_serpent_king-helm-of-the-serpent-king">Helm of the Serpent King</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 152</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 96,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This helm is made of large, alchemically hardened snake scales, and is crafted in the shape of a stylized serpent mouth. Its wearer stares out through the serpent's eyes, and sees all things cast in a yellow tint. When worn, it grants the following spell-like abilities to the wearer:</p>
<ul>
<li><Link to="/spell/hypnotism">Hypnotism</Link> (3/day)</li>
<li><em>Summon nature's ally III</em> (<Link to="/monster/constrictor_snake">constrictor snake</Link> only, 3/day)</li>
<li><em>Beast shape III</em> (snake form only, 1/day)</li>
<li><Link to="/spell/poison">Poison</Link> (1/day)</li>
</ul>
<p>A mythic creature can expend one use of mythic power when using the <em>beast shape III</em> spell-like ability to instead cast it as <em>mythic beast shape III.</em> Alternatively, he can expend two uses of mythic power to instead cast the augmented version of <em>mythic beast shape III.</em></p>
<h3 id="magic-wondrous-helm_of_the_serpent_king-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/beast_shape_iii">beast shape III</Link>, <Link to="/spell/summon_natures_ally_iii">summon nature's ally III</Link>; <strong>Cost</strong> 48,000 gp</p>
</>};
const _helm_of_the_valkyrie = {title: "Helm of the Valkyrie", jsx: <><h2 id="magic-wondrous-helm_of_the_valkyrie-helm-of-the-valkyrie">Helm of the Valkyrie</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 230</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 14th<br/><strong>Slot</strong> head; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This shining helm glints with the multicolored hues of the aurora, and features wings carved of fine whalebone that sweep back from the temples. While it is in good shape, it shows signs of having seen battle. Once per day the wearer can summon a giant spectral wolf. Treat this as <em>phantom steed</em> cast by a 14th-level caster, but with an AC of 24 (-1 size, +8 natural armor, +7 Dexterity) and 100 hit points. The wolf can persist for up to 24 hours, as long as the creature that summoned it is still wearing the helm of the valkyrie. Even though it takes the form of a fierce predator and is more powerful than other phantom steeds, the mount is nothing more than mist and can't attack.</p>
<h3 id="magic-wondrous-helm_of_the_valkyrie-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/phantom_steed">phantom steed</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _helm_of_underwater_action = {title: "Helm of Underwater Action", jsx: <><h2 id="magic-wondrous-helm_of_underwater_action-helm-of-underwater-action">Helm of Underwater Action</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 244</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 518</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 24,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>The wearer of this helmet can see underwater. Drawing the small lenses in compartments on either side into position before the wearer's eyes activates the visual properties of the helm, allowing her to see five times farther than water and light conditions would allow for normal human vision. (Weeds, obstructions, and the like block vision in the usual manner.) If the command word is spoken, the helm of underwater action gives the wearer a 30-foot swim speed and creates a globe of air around the wearer's head and maintains it until the command word is spoken again, enabling her to breathe freely.</p>
<h3 id="magic-wondrous-helm_of_underwater_action-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 12,000 gp</p>
</>};
const _helmet_of_the_golden_general = {title: "Helmet of the Golden General", jsx: <><h2 id="magic-wondrous-helmet_of_the_golden_general-helmet-of-the-golden-general">Helmet of the Golden General</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 357</Link></p>
<p><strong>Aura</strong> strong divination; <strong>CL</strong> 13th<br/><strong>Slot</strong> head; <strong>Price</strong> 62,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This golden gem-studded helmet acts like a <Link to="/magic-wondrous/crown_of_conquest">crown of conquest</Link> and grants its wielder three <Link to="/main/feats_performance">performance</Link> or <Link to="/main/teamwork_feat">teamwork</Link> feats. The wearer can use each of these feats as if it were on his feat list. Once chosen, at the time of the item's creation, these feats cannot be changed. The helmet must be worn for 24 hours in order to gain the teamwork or performance feats.</p>
<p>Furthermore this helmet can speak through a central ruby that sits over the nose guard of the helmet. It knows Common and four other languages. These helmets are always confident - even arrogant - and give a running commentary of the battle, praising heroism, chiding tactical missteps, and giving its wearer and its allies martial advice. It has the following other powers.</p>
<ul>
<li>Three times per day, it can affect its wearer or an ally within 30 feet as the <em>true strike</em> spell.</li>
<li>Three times per day, it can attempt to demoralize all enemies within 30 feet as a free action, as if using the <Link to="/skill/intimidate">Intimidate</Link> skill. The helmet's Intimidate is bonus +17.</li>
</ul>
<h3 id="magic-wondrous-helmet_of_the_golden_general-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, the item's performance and teamwork feat, <Link to="/spell/bless">bless</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/prayer">prayer</Link>, <Link to="/spell/scare">scare</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Price</strong> 31,000 gp</p>
<h3 id="magic-wondrous-helmet_of_the_golden_general-statistics">Statistics</h3>
<p><strong>Alignment</strong> neutral good; <strong>Ego</strong> 14<br/><strong>Senses</strong> 30 ft.<br/><strong>Int</strong> 14, <strong>Wis</strong> 16, <strong>Cha</strong> 14<br/><strong>Communication</strong> speech (Common and four other languages)</p>
</>};
const _hollow_mask = {title: "Hollow Mask", jsx: <><h2 id="magic-wondrous-hollow_mask-hollow-mask">Hollow Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_124_city_in_the_deep">Pathfinder #124: City in the Deep pg. 81</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This porous wooden mask fits against the wearer's face much more tightly than its bulky, abstract design suggests. The mask is capable of storing air; the wearer can breathe normally underwater for 5 minutes before he has to <Link to="/misc/hold_his_breath">hold his breath</Link>. While underwater, so long as there is still air left in the mask, it converts speech into vibrations in the water and vice versa, allowing the wearer to speak normally and hear the speech of other creatures wearing hollow masks within 60 feet as though they were not underwater. After a wearer has used the mask underwater, the mask needs an equal amount of time (maximum 5 minutes) to replenish its air supply.</p>
<h3 id="magic-wondrous-hollow_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/air_bubble">air bubble</Link>, <Link to="/spell/message">message</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _hood_of_privacy = {title: "Hood of Privacy", jsx: <><h2 id="magic-wondrous-hood_of_privacy-hood-of-privacy">Hood of Privacy</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 27</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 120,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This voluminous silver hood shimmers like a scattered handful of diamonds. The hood completely covers the wearer's face, hiding his identity, but does not impair the wearer's senses. The wearer gains a +4 bonus on saving throws against mind-affecting effects. The wearer is immediately aware when someone attempts to gain information about him through a divination spell or effect, such as <Link to="/spell/scrying">scrying</Link>. As a swift action, the wearer can reduce the hood's saving throw bonus by 1 to thwart such a divination attempt, providing whatever false information the wearer desires to the diviner, or even to conceal the information entirely as though the wearer were undetectable to the divination effect. The creature using the divination effect can attempt a DC 26 Will save to learn that the information is fabricated or concealed. Expended bonuses return at a rate of 1 per week.</p>
<h3 id="magic-wondrous-hood_of_privacy-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_scrying">detect scrying</Link>, <Link to="/spell/mind_blank">mind blank</Link>; <strong>Cost</strong> 60,000 gp</p>
</>};
const _hood_of_the_living = {title: "Hood of the Living", jsx: <><h2 id="magic-wondrous-hood_of_the_living-hood-of-the-living">Hood of the Living</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 28</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 2,840 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple leather coif is of a style popular along the Crusader Road and throughout northern Avistan. The wearer gains a +2 resistance bonus on Will saves against mind-affecting effects created by undead creatures. Three times per day, the wearer may activate the hood of the living to detect the auras of any undead creatures within a 30-foot radius. Doing so is a full-round action that discloses the presence of any undead auras, the number of undead auras, and the direction of the nearest undead aura, as though the user had concentrated for 3 rounds while using <em>detect undead.</em></p>
<p>When activated, a hood of the living also detects any living creatures within a 30-foot radius that are acting under the effects of a charm or compulsion created by an undead creature. This effect only reveals the presence of such creatures, not their number or location.</p>
<h3 id="magic-wondrous-hood_of_the_living-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_undead">detect undead</Link>, <Link to="/spell/protection_from_evil">protection from evil</Link>; <strong>Cost</strong> 1,420 gp</p>
</>};
const _horned_helm_of_the_wild_stag = {title: "Horned Helm of the Wild Stag", jsx: <><h2 id="magic-wondrous-horned_helm_of_the_wild_stag-horned-helm-of-the-wild-stag">Horned Helm of the Wild Stag</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 60</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Numerous antlers protrude from this ornate leather helm, creating an impressive array of bony points that jut out in several directions. When the horned helm of the wild stag is donned, the wearer's facial structure subtly elongates in a manner reminiscent of a stag's head. He gains a +2 dodge bonus to AC against attacks of opportunity.</p>
<p>Once per day when the wearer <Link to="/rule/charge">charges</Link> an enemy or attempts an <Link to="/rule/overrun">overrun</Link> combat maneuver, he can as part of his action activate the helm to summon dozens of spectral stags to accompany him during his movement. These ghostly stags gallop around him in a frenzy, with the unmistakable sound of pounding hooves, and stampede through any creature within 5 feet of the wearer at any point during his movement. Although this stampede causes no physical damage, each affected creature must attempt a DC 16 Will save to avoid being overcome by the frenzy of the rampaging herd. A creature that fails this save must use its next turn to charge the nearest valid target (including its allies), if possible. Creatures that are unable to charge must instead move away from the wearer of the helm as quickly as possible on their next turn. This is a mind-affecting compulsion effect.</p>
<h3 id="magic-wondrous-horned_helm_of_the_wild_stag-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/aspect_of_the_stag">aspect of the stag</Link>, <Link to="/spell/moonstruck">moonstruck</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _howling_helm = {title: "Howling Helm", jsx: <><h2 id="magic-wondrous-howling_helm-howling-helm">Howling Helm</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 244</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 22,600 gp; <strong>Weight</strong> 2 lbs.</p>
<p>The wearer of this helm, crafted from a beast's skull, gains the ability to communicate with dogs, wolves, dire wolves, foxes, jackals, coyotes, and similar canine animals as the <em>speak with animals</em> spell. The wearer gains a +2 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> checks and Charisma checks to influence wolf-like magical beasts such as <Link to="/monster/blink_dog">blink dogs</Link>, <Link to="/monster/winter_wolf">winter wolves</Link>, and <Link to="/monster/worg">worgs</Link>.</p>
<p>On command three times per day, the wearer can unleash a terrifying howl. When he does so, he makes a single <Link to="/skill/intimidate">Intimidate</Link> check to demoralize all opponents within 30 feet that can hear the howl. At the start of the wearer's following turn, 1d3 <Link to="/monster/wolves">wolves</Link> appear as if summoned by the spell <em>summon nature's ally III.</em> They act on the wearer's initiative and follow her instructions (or attacking her opponents, if she cannot communicate with them) for 5 rounds before vanishing in a swirl of pine needles and snow.</p>
<h3 id="magic-wondrous-howling_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, <Link to="/spell/summon_natures_ally_iii">summon nature's ally III</Link>; <strong>Cost</strong> 11,300 gp</p>
</>};
const _hunters_nose_ring = {title: "Hunter's Nose Ring", jsx: <><h2 id="magic-wondrous-hunters_nose_ring-hunters-nose-ring">Hunter's Nose Ring</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 93</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This nose ring seems to be braided from five platinum strands. It grants its wearer the <Link to="/umr/scent">scent</Link> ability along with a +4 competence bonus on <Link to="/skill/perception">Perception</Link> checks involving smell and on <Link to="/skill/survival">Survival</Link> checks to track using scent.</p>
<h3 id="magic-wondrous-hunters_nose_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bloodhound">bloodhound</Link>, platinum ring worth 250 gp; <strong>Cost</strong> 5,000 gp</p>
</>};
const _hurricane_crown = {title: "Hurricane Crown", jsx: <><h2 id="magic-wondrous-hurricane_crown-hurricane-crown">Hurricane Crown</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_60_from_hells_heart">Pathfinder #60: From Hell's Heart pg. 54</Link><br/><strong>Aura</strong> strong conjuration and evocation; <strong>CL</strong> 17th<br/><strong>Slot</strong> head; <strong>Price</strong> 125,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A band of golden skulls encircles this golden crown, and smaller skulls top its points. Forged for the first Hurricane King, Turpin Irons, when he sailed out of the Eye of Abendego more than 100 years ago to claim rulership over the Shackles, the Hurricane Crown has been passed down (or taken by force) from one Hurricane King to the next ever since. On command, the Hurricane Crown changes its shape and appearance to assume the form of a normal piece of headwear (such as a hat or scarf). The crown retains all its properties (including weight) when so disguised. Only a <em>true seeing</em> spell or similar magic reveals the true nature of the crown when disguised.</p>
<p>The wearer of the Hurricane Crown gains a +5 competence bonus on <Link to="/skill/profession">Profession (sailor)</Link> checks and <Link to="/skill/survival">Survival</Link> checks made to determine direction or predict the weather at sea, and he can see normally through fog, mist, smoke, and precipitation or weather effects, whether natural or magical. Once per day, the wearer can cast <em>control winds;</em> if the wearer is standing on a ship, the ship and any creatures aboard it are unaffected by the controlled winds unless the wearer wishes to affect them, even if the ship's area is larger than the spell's unaffected area. In addition, once per day, the wearer of the Hurricane Crown can surround himself in either a shroud of elemental water or supernatural winds, as the <em>seamantle</em> or <em>winds of vengeance</em> spells.</p>
<p>Lastly, the wearer of the Hurricane Crown can create a single-use <em>phase door</em> in the rock of Lucrehold to access the sea caves and Hidden Harbor beneath the island. If the crown's wearer is standing on a ship, the <em>phase door</em> is large enough to accommodate the ship and any creatures on it. The <em>phase door</em> remains invisible and inaccessible to all other creatures and ships, and otherwise functions as a normal <em>phase door.</em> This ability can be used at will.</p>
<h3 id="magic-wondrous-hurricane_crown-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/control_winds">control winds</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/phase_door">phase door</Link>, <Link to="/spell/seamantle">seamantle</Link>, <Link to="/spell/true_seeing">true seeing</Link>, <Link to="/spell/winds_of_vengeance">winds of vengeance</Link>; <strong>Cost</strong> 62,500 gp</p>
</>};
const _hyena_shawl = {title: "Hyena Shawl", jsx: <><h2 id="magic-wondrous-hyena_shawl-hyena-shawl">Hyena Shawl</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 93</Link><br/><strong>Aura</strong> moderate abjuration and necromancy; <strong>CL</strong> 8th<br/><strong>Slot</strong> head; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> -</p>
<p>When wrapped around the neck and jaw, this swath of black cloth lets its wearer see normally in a <Link to="/rule/severe_events">sandstorm</Link> (her vision isn't reduced, nor does she take the -4 penalty on <Link to="/skill/perception">Perception</Link> checks) and avoid taking nonlethal damage from the storm.</p>
<p>Once per day on command, the shawl's wearer can emit a strange cackling. Enemies within 30 feet of the shawl's wearer who can hear the cackling must succeed at a DC 16 Will saving throw or become <Link to="/misc/frightened">frightened</Link> for 1 round. Those who succeed at the saving throw are <Link to="/misc/shaken">shaken</Link> for 1d4 rounds instead. Both of the cackle's effects are sonic mind-affecting fear effects.</p>
<h3 id="magic-wondrous-hyena_shawl-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fear">fear</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _imperial_army_greathelm = {title: "Imperial Army Greathelm", jsx: <><h2 id="magic-wondrous-imperial_army_greathelm-imperial-army-greathelm">Imperial Army Greathelm</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 60</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 29,000 gp; <strong>Weight</strong> 6 lbs.</p>
<p>Many seasoned military commanders in Molthune wear this style of silver helmet adorned with a single oversized red plume. If the wearer of an Imperial Army greathelm has the <Link to="/feat/leadership">Leadership</Link> feat, he gains a +3 bonus to his Leadership score, and any of his followers or cohorts gain a +1 bonus on attack rolls and on saving throws against fear effects while they're within line of sight of him.</p>
<p>If the wearer possesses the tactician class feature, the range of that ability increases to 60 feet.</p>
<h3 id="magic-wondrous-imperial_army_greathelm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, Leadership, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/greater_command">greater command</Link>; <strong>Cost</strong> 14,500 gp</p>
</>};
const _iron_circlet_of_guarded_souls = {title: "Iron Circlet of Guarded Souls", jsx: <><h2 id="magic-wondrous-iron_circlet_of_guarded_souls-iron-circlet-of-guarded-souls">Iron Circlet of Guarded Souls</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 245</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> head; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple <Link to="/eq-material/cold_iron">cold iron</Link> circle has no markings or ornamentation upon it, and is always slightly cool to the touch. The circle shields both the wearer's soul and his identity from mystic intrusion. The wearer is immune to effects that target souls (such as <em>trap the soul</em>) or that would be foiled by a <em>nondetection</em> spell (unlike <em>nondetection,</em> the diviner's caster cannot attempt a spell resistance check to overcome this effect). If the wearer is slain, he cannot be restored to life by magic (save by a <Link to="/spell/miracle">miracle</Link>, <Link to="/spell/wish">wish</Link>, or divine intervention) until the circlet is removed.</p>
<h3 id="magic-wondrous-iron_circlet_of_guarded_souls-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/nondetection">nondetection</Link>, <Link to="/spell/trap_the_soul">trap the soul</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _jingasa_of_the_fortunate_soldier = {title: "Jingasa of the Fortunate Soldier", jsx: <><h2 id="magic-wondrous-jingasa_of_the_fortunate_soldier-jingasa-of-the-fortunate-soldier">Jingasa of the Fortunate Soldier</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 245</Link>, <Link to="/source/pathfinder_52_forest_of_spirits">Pathfinder #52: Forest of Spirits pg. 60</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This conical iron jingasa, or war hat, grants the wearer a +1 deflection bonus to AC. When struck by a critical hit or <Link to="/ability/sneak_attack">sneak attack</Link>, the wearer can spend an immediate action to negate the critical hit or sneak attack (similar to the <Link to="/magic-enh/fortification">fortification</Link> armor special ability, but without requiring a roll). The damage is instead rolled normally. This ability functions only once, though the jingasa continues to grant its deflection bonus even after the other ability is expended.</p>
<h3 id="magic-wondrous-jingasa_of_the_fortunate_soldier-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, <Link to="/spell/moment_of_prescience">moment of prescience</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _judges_wig = {title: "Judge's Wig", jsx: <><h2 id="magic-wondrous-judges_wig-judges-wig">Judge's Wig</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 245</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 59,200 gp; <strong>Weight</strong> -</p>
<p>This flowing wig of white ringlets grants its wearer an unmistakable impression of dignity and gravitas. This grants a +4 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> and <Link to="/skill/intimidate">Intimidate</Link> checks. At will, the wearer can concentrate on a creature within 30 feet to scrutinize it with <em>discern lies.</em></p>
<h3 id="magic-wondrous-judges_wig-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/discern_lies">discern lies</Link>; <strong>Cost</strong> 29,600 gp</p>
</>};
const _khepresh_of_refuge = {title: "Khepresh of Refuge", jsx: <><h2 id="magic-wondrous-khepresh_of_refuge-khepresh-of-refuge">Khepresh of Refuge</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_84_pyramid_of_the_sky_pharaoh">Pathfinder #84: Pyramid of the Sky Pharaoh pg. 61</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 63,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This traditional Osirian crown - known as a khepresh, or "war crown" - made of hardened blue leather and adorned with discs of blue-tinted electrum and a rearing, hooded cobra of gold, was crafted specifically for the Sky Pharaoh Hakotep I. The khepresh of refuge grants its wearer a +3 deflection bonus to AC and fire resistance 10. In addition, the crown has 3 charges per day. When struck by a critical hit or sneak attack, the wearer can spend 1 charge as an immediate action to negate the critical hit or sneak attack (as the <Link to="/magic-enh/fortification">fortification</Link> armor special ability, but without requiring a roll). The damage is instead rolled normally. Alternatively, the wearer can spend 1 charge as an immediate action to reroll a failed saving throw. He must take the result of the reroll, even if it's worse.</p>
<h3 id="magic-wondrous-khepresh_of_refuge-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/moment_of_prescience">moment of prescience</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Cost</strong> 31,500 gp</p>
</>};
const _kybwaka_war_mask = {title: "Kybwa'ka War Mask", jsx: <><h2 id="magic-wondrous-kybwaka_war_mask-kybwaka-war-mask">Kybwa'ka War Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_27_what_lies_in_dust">Pathfinder #27: What Lies in Dust pg. 57</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 4th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,700 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This oversized wooden mask covers the face and extends down to a point at the wearer's waist, covering most of his chest and abdomen. It is simplistically carved as a stylized, bestial face distorted with rage or nightmarish styles. The light wood provides little protection, yet is magically reinforced to grant a +1 armor bonus. In addition, once per day as a free action, the wearer can cause the mask to warp and contort ferociously, causing a single creature within 15 feet to make a DC 14 Will save or become <Link to="/misc/frightened">frightened</Link>. This is a mind-affecting fear effect.</p>
<h3 id="magic-wondrous-kybwaka_war_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/scare">scare</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 1,850 gp</p>
</>};
const _laurel_of_command = {title: "Laurel of Command", jsx: <><h2 id="magic-wondrous-laurel_of_command-laurel-of-command">Laurel of Command</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 245</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> -</p>
<p>Laurel leaves crafted from fine gold decorate this circlet that imparts powers of persuasion and leadership. The wearer's voice carries great authority and can inspire others to victory. As a swift action, the wearer can speak words of encouragement or advice to an ally within 30 feet. That ally gains a +2 morale bonus on attack rolls, saving throws, skill checks, and ability checks until the start of the wearer's next turn. The wearer can use the laurel to grant this bonus to himself. A creature cannot gain this bonus more than once per day.</p>
<h3 id="magic-wondrous-laurel_of_command-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _laurel_wreath = {title: "Laurel Wreath", jsx: <><h2 id="magic-wondrous-laurel_wreath-laurel-wreath">Laurel Wreath</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 153</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 19,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This crown of laurel leaves inspires its wearer to achieve mighty deeds. She gains a +4 morale bonus on saving throws against mind-affecting effects. If she succeeds at a saving throw against a harmful mind-affecting effect, the surge of confidence gives her a +2 morale bonus on attack rolls, skill checks, and weapon damage rolls for 1 minute. If she fails such a saving throw, she is instead <Link to="/misc/shaken">shaken</Link> for 1 minute, though this condition doesn't stack with other fear effects to make her <Link to="/misc/frightened">frightened</Link> or <Link to="/misc/panicked">panicked</Link>.</p>
<p>A mythic creature wearing the wreath gains 2 <Link to="/rule/temporary_hit_points">temporary hit points</Link> per tier at the start of each day. These temporary hit points are restored whenever the wearer rests 8 hours or otherwise gains the equivalent of doing so.</p>
<h3 id="magic-wondrous-laurel_wreath-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/crushing_despair">crushing despair</Link>, <Link to="/spell/good_hope">good hope</Link>; <strong>Cost</strong> 9,500 gp</p>
</>};
const _lepidstadt_investigators_hat = {title: "Lepidstadt Investigator's Hat", jsx: <><h2 id="magic-wondrous-lepidstadt_investigators_hat-lepidstadt-investigators-hat">Lepidstadt Investigator's Hat</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins pg. 29</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 8th<br/><strong>Slot</strong> head; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> -</p>
<p>This black deerstalker cap features a subtle, sinister, eye-like design stitched on the front flap. The hat grants a +2 competence bonus on all <Link to="/skill/knowledge">Knowledge</Link> checks to identify monsters.</p>
<p>If the wearer is an <Link to="/class/investigator">investigator</Link>, the hat allows him to take advantage of his deductions in combat. Whenever he uses inspiration to identify a non-humanoid creature, he can record the result of the inspiration die and use it again later. Within the next minute, before rolling an attack roll against that creature, a skill check against that creature, or a saving throw against one of that creature's attacks, he can add the recorded inspiration die result to his roll - if he does so, he can't use inspiration to apply another inspiration die to the roll. Using the recorded result doesn't require the investigator to spend a use of inspiration, and the recorded result goes away once it's used. He can have only one inspiration die result recorded in this way. If he uses inspiration to identify another monster before using his recorded inspiration die, he must decide whether to replace the old result before rolling.</p>
<h3 id="magic-wondrous-lepidstadt_investigators_hat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/know_the_enemy">know the enemy</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _lore_needle = {title: "Lore Needle", jsx: <><h2 id="magic-wondrous-lore_needle-lore-needle">Lore Needle</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 17</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>This thick silver needle is approximately 6 inches long and can be carefully inserted into the brain of a willing or helpless target in order to magically expand the target's knowledge. Implanting a lore needle takes 10 minutes and requires a successful DC 15 <Link to="/skill/heal">Heal</Link> check. A user can insert the needle into her own head with a successful DC 25 Heal check. On a failure, the needle deals 2 points of <Link to="/rule/constitution_damage">Constitution damage</Link> and 2 points of Intelligence damage to the target and is not implanted. A creature with an implanted lore needle can, up to three times per day when attempting a <Link to="/skill/knowledge">Knowledge</Link> check, apply to that check its bonus on any other single Knowledge skill in which it is trained.</p>
<h3 id="magic-wondrous-lore_needle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/modify_memory">modify memory</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _magicians_hat = {title: "Magician's Hat", jsx: <><h2 id="magic-wondrous-magicians_hat-magicians-hat">Magician's Hat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 245</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>Mystic symbols embroidered in gold thread decorate this conical hat. Three times per day as a free action when casting a spell, the wearer can shift metamagic feats on prepared spells. The wearer can either move a metamagic feat from another prepared spell to a spell being cast or from the spell being cast to another prepared spell. In either case, the spell that gains the metamagic feat can't exceed the spell slot of the spell that originally had the metamagic feat. For example, a wizard with <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/feat/silent_spell">silent</Link> <Link to="/spell/dispel_magic">dispel magic</Link>, and <Link to="/spell/dimension_door">dimension door</Link> prepared could cast a silent <em>detect thoughts</em> (and would now have <em>dispel magic</em> prepared), but could not cast silent <em>dimension door.</em> Moving metamagic feats does not increase spell casting time, even for <Link to="/feat/quickened">quickened</Link> spells. The hat provides no benefit to spontaneous casting or spell-like abilities.</p>
<h3 id="magic-wondrous-magicians_hat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mnemonic_enhancer">mnemonic enhancer</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _magnates_miter = {title: "Magnate's Miter", jsx: <><h2 id="magic-wondrous-magnates_miter-magnates-miter">Magnate's Miter</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 18</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 18th<br/><strong>Slot</strong> head; <strong>Price</strong> 90,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This alabaster headdress is studded with lines of delicate rubies and represents the height of Kersite fashion mixed with Kalistocratic needs. These austere headdresses come with an imbued soul - one utterly dedicated to assisting the adherents of the <Link to="/rule/prophecies_of_kalistrade">Prophecies of Kalistrade</Link> unto death. Once per day as an immediate action, the wearer can allow the personality within the miter to rise to the fore of her own consciousness. This effect lasts for 1 minute, during which the wearer can roll twice and use the higher result for all Intelligence-, Wisdom-, and Charisma-based skill checks. The wearer can activate this ability after such a skill check has been rolled but before the result is determined, allowing for a reroll.</p>
<p>Additionally, once per day as an immediate action, the wearer can gain the benefits of <em>tower of iron will V,</em> as the possessing spirit rises to block any mental effects against the wearer. This ability can be used regardless of whether the miter's other ability is active.</p>
<h3 id="magic-wondrous-magnates_miter-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divide_mind">divide mind</Link>, <Link to="/spell/possession">possession</Link>, <Link to="/spell/tower_of_iron_will_v">tower of iron will V</Link>; <strong>Cost</strong> 45,000 gp</p>
</>};
const _maidens_helm = {title: "Maiden's Helm", jsx: <><h2 id="magic-wondrous-maidens_helm-maidens-helm">Maiden's Helm</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 87</Link>, <Link to="/source/pathfinder_62_curse_of_the_ladys_light">Pathfinder #62: Curse of the Lady's Light pg. 62</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 6th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>A maiden's helm appears as the distinctive plate and plumed helm worn by the <Link to="/rule/gray_maidens">Gray Maidens</Link>. The helm imparts enhanced power and gravitas to the wearer's voice, granting a +5 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks. The wearer of a maiden's helm can use <em>command</em> three times per day as a spell-like ability.</p>
<h3 id="magic-wondrous-maidens_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cause_fear">cause fear</Link>, <Link to="/spell/command">command</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _mask_of_a_thousand_tomes = {title: "Mask Of A Thousand Tomes", jsx: <><h2 id="magic-wondrous-mask_of_a_thousand_tomes-mask-of-a-thousand-tomes">Mask Of A Thousand Tomes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 245</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The random snippets of script that write across the surface of this parchment-colored eyeless mask hint at the knowledge of the many tomes stored within. The mask grants its wearer a +10 competence bonus on all <Link to="/skill/knowledge">Knowledge</Link> skill checks, but the wearer is <Link to="/misc/blinded">blinded</Link> while wearing the mask. The mask must be worn for 10 minutes before the wearer gains its bonus.</p>
<h3 id="magic-wondrous-mask_of_a_thousand_tomes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _mask_of_anonymous_mien = {title: "Mask of Anonymous Mien", jsx: <><h2 id="magic-wondrous-mask_of_anonymous_mien-mask-of-anonymous-mien">Mask of Anonymous Mien</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 31</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This featureless mask is little more than a white disk with eyeholes and a pair of short leather straps for tying. After donning the mask, the wearer can meditate for 1 minute in order to assume a faceless identity, becoming an utterly generic and unremarkable member of the wearer's race and gender. <Link to="/skill/knowledge">Knowledge</Link> checks about the wearer's faceless identity don't reveal information about his true identity, unless his true identity is revealed to the world at large. Additionally, attempts to scry or otherwise locate the wearer work only if the creature is attempting to locate the wearer's faceless identity (or the creature knows the wearer's faceless identity and the wearer's true identity are one and the same). Otherwise, the spell has no effect, revealing nothing but darkness, as if the target were invalid or did not exist. In addition, if the wearer owns multiple masks of anonymous mien, the faceless identity he assumes is the same for all such items.</p>
<p>A <Link to="/class/vigilante">vigilante</Link> who wears a mask of anonymous mien treats the faceless identity created by the item as a vigilante identity for the purpose of his class abilities, although this identity is separate from his actual vigilante identity.</p>
<h3 id="magic-wondrous-mask_of_anonymous_mien-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/nondetection">nondetection</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _mask_of_conflicting_energies = {title: "Mask of Conflicting Energies", jsx: <><h2 id="magic-wondrous-mask_of_conflicting_energies-mask-of-conflicting-energies">Mask of Conflicting Energies</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 266</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This mask is white on one side and black on the other, with glittering gem lenses covering the eyes. Up to three times per day, the wearer can change the energy damage of a fire spell she casts to cold, a cold spell to fire, an acid spell to electricity, or an electricity spell to acid. All other effects of the spell are unchanged (for example, an <Link to="/spell/ice_storm">ice storm</Link> changed to fire damage still deals bludgeoning damage and bestows a penalty on <Link to="/skill/perception">Perception</Link> checks). The mask affects only spells up to 3rd level.</p>
<h3 id="magic-wondrous-mask_of_conflicting_energies-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/elemental_spell">Elemental Spell</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _mask_of_cutting_flesh = {title: "Mask of Cutting Flesh", jsx: <><h2 id="magic-wondrous-mask_of_cutting_flesh-mask-of-cutting-flesh">Mask of Cutting Flesh</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 266</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 58</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black leather mask is studded with bits of bone and metal, with smooth-sewn holes for the wearer's eyes, mouth, and nostrils. It laces in the back with long straps and covers the entire face, leaving only the ears and back of the head exposed. The wearer gains a +2 resistance bonus on Fortitude saving throws.</p>
<p>If <Link to="/faith/zon_kuthon">Zon-Kuthon</Link> is the wearer's patron, once per day the wearer can whisper a command word to lash out at a target within 100 feet, unerringly slashing the target with an invisible blade of force that deals 2d4+2 points of force damage (spell resistance applies). As a free action, the wearer can will the mask to unlace and reshape itself into a leather cap on top of the wearer's head, or hide itself within the wearer's shirt or helm.</p>
<h3 id="magic-wondrous-mask_of_cutting_flesh-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_rope">animate rope</Link>, <Link to="/spell/magic_missile">magic missile</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _mask_of_destruction_and_creation_nethys = {title: "Mask of Destruction and Creation (Nethys)", jsx: <><h2 id="magic-wondrous-mask_of_destruction_and_creation_nethys-mask-of-destruction-and-creation-nethys">Mask of Destruction and Creation (Nethys)</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_of_balance">Faiths of Balance pg. 27</Link><br/><strong>Aura</strong> faint evocation and illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This reversible silken mask is flat white on one side and a swirling mass of colors above a black background on the other. When worn with the white side out, it allows the wearer to use <em>detect magic</em> once per day. When worn with the black side out, it allows the wearer to use <em>read magic</em> once per day. If <Link to="/faith/nethys">Nethys</Link> is your patron, you can use the black side of the mask to cast <em>magic missile</em> as a 3rd-level caster once per day. Likewise, you can use the white side of the mask to cast <em>disguise self</em> once per day.</p>
<h3 id="magic-wondrous-mask_of_destruction_and_creation_nethys-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/magic_missile">magic missile</Link>, <Link to="/spell/read_magic">read magic</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _mask_of_giants_lesser = {title: "Mask of Giants (Lesser)", jsx: <><h2 id="magic-wondrous-mask_of_giants_lesser-mask-of-giants-lesser">Mask of Giants (Lesser)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 245-6</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 307</Link><br/><strong>Aura</strong> moderate transmutation (lesser), strong transmutation (greater); <strong>CL</strong> 6th (lesser), 13th (greater)<br/><strong>Slot</strong> head; <strong>Price</strong> 30,000 gp (lesser), 90,000 gp (greater); <strong>Weight</strong> 1 lb.</p>
<p>This wooden mask depicts a leering humanoid with an oversized nose and ears. If the wearer has the wild shape class feature, the mask allows her to use wild shape to take the form of a humanoid with the giant subtype. The forms allowed by a lesser mask of giants are <Link to="/monster/ogre">ogre</Link>, <Link to="/monster/troll">troll</Link>, <Link to="/monster/fire_giant">fire giant</Link>, <Link to="/monster/frost_giant">frost giant</Link>, and <Link to="/monster/stone_giant">stone giant</Link>. If the form has any of the following abilities, the wearer gains the listed ability: darkvision 60 feet, low-light vision, <Link to="/umr/scent">scent</Link>. In giant form, the wearer gains a +4 size bonus to Strength, a -2 penalty to Dexterity, and a +1 natural armor bonus.</p>
<h3 id="magic-wondrous-mask_of_giants_lesser-mask-of-giants-greater">Mask of Giants (Greater)</h3>
<p>A greater mask of giants has all the powers of a lesser mask of giants, plus it grants additional abilities in giant form. If the form has any of the following abilities, the wearer gains the listed ability: <Link to="/umr/rend">rend</Link> (2d6 damage), <Link to="/umr/regeneration">regeneration</Link> 5 (acid or fire), <Link to="/umr/rock_catching">rock catching</Link>, <Link to="/umr/rock_throwing">rock throwing</Link> (range 60 feet, 2d6 damage). If the chosen giant form has immunity or resistance to any energy type, the wearer gains resistance 20 to that energy type when in giant form. If the giant form has vulnerability to an energy type, the wearer gains that vulnerability when in giant form. In giant form, the wearer gains a +6 size bonus to Strength, a -2 penalty to Dexterity, a +4 size bonus to Constitution, and a +4 natural armor bonus.</p>
<h3 id="magic-wondrous-mask_of_giants_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/giant_form_i">giant form I</Link>; <strong>Cost</strong> 15,000 gp (lesser), 45,000 gp (greater)</p>
</>};
const _mask_of_stolen_mien = {title: "Mask of Stolen Mien", jsx: <><h2 id="magic-wondrous-mask_of_stolen_mien-mask-of-stolen-mien">Mask of Stolen Mien</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 248</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 17,200 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This grotesque leather mask is sewn together from pieces of faces taken from many humanoids. When the user places the mask against the face of a willing, pinned, or helpless humanoid as a full-round action, the mask's appearance changes to match the face of that creature. This effect functions even if the creature is dead, provided that the creature has been dead for less than 24 hours or has been treated with <Link to="/spell/gentle_repose">gentle repose</Link>. Thereafter, for 24 hours, the mask grants the following abilities to any humanoid creature wearing it.</p>
<p>First, the mask changes the wearer's shape to match that of the creature whose face is stored in the mask, as per <em>alter self</em> except she is able to transform into a specific creature and does not gain the listed size bonus to an ability score or the other racial abilities (such as darkvision and <Link to="/umr/scent">scent</Link>). The mask duplicates the imitated creature's appearance so accurately that the wearer takes no penalties on <Link to="/skill/disguise">Disguise</Link> checks for being disguised as different gender, race, age category, or size category, and she gains the usual +10 bonus on Disguise checks from using <em>alter self.</em> Second, the wearer can speak any languages the imitated creature knows. Lastly, the wearer's alignment and other auras match the imitated creature, as per <em>misdirection,</em> but with no save. When the duration ends, the mask reverts to its ugly, leathery form and can be used again to steal a creature's face. The duration can't be ended early, nor can the mask be used to imitate a new creature while it's still holding a character's visage; however, the wearer can still remove and replace the mask during that time.</p>
<h3 id="magic-wondrous-mask_of_stolen_mien-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/misdirection">misdirection</Link>, <Link to="/spell/tongues">tongues</Link>; <strong>Cost</strong> 8,600 gp</p>
</>};
const _mask_of_stony_demeanor = {title: "Mask of Stony Demeanor", jsx: <><h2 id="magic-wondrous-mask_of_stony_demeanor-mask-of-stony-demeanor">Mask of Stony Demeanor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 246</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 149</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> head; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>When worn, this mask transforms the wearer's face into a stone statue and its voice into an emotionless monotone. Though it allows the wearer to speak, its facial expressions and voice betray little emotion, granting a +10 competence bonus on <Link to="/skill/bluff">Bluff</Link> checks made to lie and a +5 competence bonus on Bluff checks made to feint, but also imposing a -5 penalty on Bluff checks made to pass a hidden message.</p>
<h3 id="magic-wondrous-mask_of_stony_demeanor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/innocence">innocence</Link>, <Link to="/spell/stone_shape">stone shape</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _mask_of_the_cursed_eye = {title: "Mask of the Cursed Eye", jsx: <><h2 id="magic-wondrous-mask_of_the_cursed_eye-mask-of-the-cursed-eye">Mask of the Cursed Eye</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 54</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> face; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This mask is decorated with a staring, bloodshot eye. Anyone other than an ally who observes the wearer using a scrying spell or pierces any of his magical disguise (including invisibility and polymorph effects) with a divination spell is <Link to="/misc/blinded">blinded</Link> for 1d4 minutes (Fortitude DC 16 negates) and the wearer receives a brief mental glimpse of the perpetrator. This is enough to enable scrying or teleportation to investigate the perpetrator, but the wearer is considered to have no familiarity with the subject. The mask can trigger only once per day, after which it falls dormant until the next midnight.</p>
<h3 id="magic-wondrous-mask_of_the_cursed_eye-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blindness_deafness">blindness/deafness</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _mask_of_the_far_traveler = {title: "Mask of the Far Traveler", jsx: <><h2 id="magic-wondrous-mask_of_the_far_traveler-mask-of-the-far-traveler">Mask of the Far Traveler</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 54</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 38,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This leather half-mask covers the wearer's nose and mouth, obscuring her lip movements but not her voice. Creatures that are on their native plane and have a language understand all words spoken by the wearer, as though her words were spoken in the listening creature's native tongue. In addition, because the mask replicates local idioms efficiently and skillfully, the wearer gains a +5 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> checks and on <Link to="/skill/bluff">Bluff</Link> checks to tell a lie. A mask of the far traveler does not function on the Material Plane.</p>
<h3 id="magic-wondrous-mask_of_the_far_traveler-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/tongues">tongues</Link>; <strong>Cost</strong> 19,000 gp</p>
</>};
const _mask_of_the_krenshar = {title: "Mask of the Krenshar", jsx: <><h2 id="magic-wondrous-mask_of_the_krenshar-mask-of-the-krenshar">Mask of the Krenshar</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 246</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple leather mask depicts an earless cat-like creature. When worn, it melds into its wearer's face and vanishes, leaving the wearer's face just as it looked before. Three times per day the wearer can command the mask to appear to retract the wearer's skin, revealing an illusion of the wearer's glistening skull and musculature. Creatures within 100 feet who see this display must succeed at a DC 13 Will save or become <Link to="/misc/frightened">frightened</Link> (if the target has 6 or fewer Hit Dice) or <Link to="/misc/shaken">shaken</Link> (if the target has more than 6 HD) for 1d4 rounds. This is a mind-affecting fear effect and a glamer. Anyone who can see through illusions (such as by <Link to="/spell/true_seeing">true seeing</Link>) is unaffected.</p>
<h3 id="magic-wondrous-mask_of_the_krenshar-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/scare">scare</Link>; <strong>Cost</strong> 3,600 gp</p>
</>};
const _mask_of_the_mantis = {title: "Mask of the Mantis", jsx: <><h2 id="magic-wondrous-mask_of_the_mantis-mask-of-the-mantis">Mask of the Mantis</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 159</Link>, <Link to="/source/pathfinder_9_escape_from_old_korvosa">Pathfinder #9: Escape from Old Korvosa pg. 69</Link>, <Link to="/source/pathfinder_10_a_history_of_ashes">Pathfinder #10: A History of Ashes pg. 18</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 197</Link>, <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 298</Link>, <Link to="/source/curse_of_the_crimson_throne">Curse of the Crimson Throne pg. 434</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>A mask of the mantis is the traditional headgear of the <Link to="/rule/red_mantis">Red Mantis</Link> assassin - a magical helm that evokes the eerie visage of a praying mantis. Designed both to mask the wearer's identity while on a job and to enhance the wearer's ferocious appearance, a mask of the mantis has 3 daily charges that can be used to gain additional bonuses. The wearer can spend a charge to gain darkvision to a range of 60 feet, the effects of <em>see invisibility,</em> the effects of <em>deathwatch,</em> or a +5 competence bonus on <Link to="/skill/perception">Perception</Link> checks. Once a charge is spent, the effect granted persists for 30 minutes before fading. Multiple effects can be active simultaneously. Charges expended from the mask replenish automatically in 24 hours.</p>
<h3 id="magic-wondrous-mask_of_the_mantis-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/deathwatch">deathwatch</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _mask_of_the_mesmerist = {title: "Mask of the Mesmerist", jsx: <><h2 id="magic-wondrous-mask_of_the_mesmerist-mask-of-the-mesmerist">Mask of the Mesmerist</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 261</Link><br/><strong>Aura</strong> faint divination and illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>Made from elaborately carved wood in the shape of a mythical creature, this mask covers the face of its wearer, leaving only two holes for eyes. A <Link to="/class/mesmerist">mesmerist</Link> wearing this mask increases the range of his hypnotic stare ability by 10 feet as the mask allows him to better focus on his targets. Creatures under the effects of the wearer's hypnotic stare take a -2 penalty on all attack rolls against the wearer.</p>
<p>Once per day, if the wearer possesses the mesmerist trick class feature, he can implant a trick without expending a use of his mesmerist trick ability. This trick also does not count against his limit of total tricks active at the same time.</p>
<h3 id="magic-wondrous-mask_of_the_mesmerist-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/aversion">aversion</Link>, <Link to="/spell/focused_scrutiny">focused scrutiny</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _mask_of_the_rabbit_prince = {title: "Mask of the Rabbit Prince", jsx: <><h2 id="magic-wondrous-mask_of_the_rabbit_prince-mask-of-the-rabbit-prince">Mask of the Rabbit Prince</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 54</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This colorful mask evokes the image of the Rabbit Prince from the Harrowed Realm. It covers the top half of the wearer's face and depicts the countenance of a resolute rabbit complete with large, floppy felt ears. Despite its apparently fragile construction, the mask is as tough as iron (hardness 10). The mask of the rabbit prince imparts reckless bravado, granting the wearer a +2 morale bonus on initiative checks and on saving throws against fear effects. In addition, the wearer always counts as having a running start when attempting <Link to="/skill/acrobatics">Acrobatics</Link> checks to jump.</p>
<h3 id="magic-wondrous-mask_of_the_rabbit_prince-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/jump">jump</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _mask_of_the_skull = {title: "Mask of the Skull", jsx: <><h2 id="magic-wondrous-mask_of_the_skull-mask-of-the-skull">Mask of the Skull</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 246</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 523</Link><br/><strong>Aura</strong> strong necromancy and transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> head; <strong>Price</strong> 22,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This fearsome-looking mask of ivory, beaten copper, or pale wood is typically fashioned into the likeness of a human skull with a missing lower jaw, allowing the bottom half of the wearer's face to remain visible when the mask is worn.</p>
<p>Once per day, after it has been worn for at least 1 hour, the mask can be loosed to fly from the wearer's face. It travels up to 50 feet away from the wearer and attacks a target assigned to it. The grinning skull mask makes a touch attack against the target based on the wearer's base attack bonus. If the attack succeeds, the target must make a successful DC 20 Fortitude save or take 130 points of damage, as if affected by a <em>finger of death</em> spell. If the target succeeds at its saving throw, it nevertheless takes 3d6+13 points of damage. After attacking (whether successful or not), the mask flies back to its user. The mask has AC 16, 10 hit points, and hardness 6.</p>
<h3 id="magic-wondrous-mask_of_the_skull-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/finger_of_death">finger of death</Link>, <Link to="/spell/fly">fly</Link>; <strong>Cost</strong> 11,000 gp</p>
</>};
const _mask_of_ugliness = {title: "Mask of Ugliness", jsx: <><h2 id="magic-wondrous-mask_of_ugliness-mask-of-ugliness">Mask of Ugliness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 347</Link></p>
<p><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> head; <strong>Weight</strong> 1 lb.</p>
<p>This strange, featureless mask seems to have the powers of a <em>headband of alluring charisma +4,</em> but instead of granting a bonus to Charisma, the mask melds to the wearer's face, making him seem uglier and his words come off as crude and insulting. The wearer takes a -4 penalty to <Link to="/skill/bluff">Bluff</Link> and <Link to="/skill/diplomacy">Diplomacy</Link> checks but gains a +2 bonus to <Link to="/skill/intimidate">Intimidate</Link> checks.</p>
<h3 id="magic-wondrous-mask_of_ugliness-construction">Construction</h3>
<p><strong>Requirements</strong> any magical mask or a <Link to="/magic-wondrous/headband_of_alluring_charisma">headband of alluring charisma</Link>; <strong>Cost</strong> -</p>
</>};
const _maw_of_the_wyrm = {title: "Maw of the Wyrm", jsx: <><h2 id="magic-wondrous-maw_of_the_wyrm-maw-of-the-wyrm">Maw of the Wyrm</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 246</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This fearsome helm, wrought into the shape of a roaring dragon's maw, has dozens of glittering dragon scales across its surface. The helm's wearer gains a +4 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks and a +4 insight bonus on saves to resist a dragon's <Link to="/umr/frightful_presence">frightful presence</Link> aura.</p>
<p>Each helm is modeled after a particular type of chromatic or metallic dragon. Once per day on command, the wearer can breathe out a blast of energy, as the <em>dragon's breath</em> spell to mimic the breath weapon of the dragon the helm is modeled after (7d6 points of damage, Reflex DC 16 half).</p>
<h3 id="magic-wondrous-maw_of_the_wyrm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dragons_breath">dragon's breath</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _medusa_mask = {title: "Medusa Mask", jsx: <><h2 id="magic-wondrous-medusa_mask-medusa-mask">Medusa Mask</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 246</Link>, <Link to="/source/pathfinder_2_the_skinsaw_murders">Pathfinder #2: The Skinsaw Murders pg. 54</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 422</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> head; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This intricate mask is made of gold-plated iron. Writhing snake tails radiate from a gemstone upon the brow, almost as if they were medusa-like hair. The mask grants a +4 bonus on all saving throws against visual effects, including <Link to="/umr/gaze">gaze</Link> attacks and sight-based illusions. Once per day as a standard action, the wearer can cause the central gemstone to glow with pale green light, at which point she may target any one creature within 30 feet. The targeted creature must succeed at a DC 15 Fortitude save or be <Link to="/rule/petrified">petrified</Link> for 1 minute, as if by <em>flesh to stone.</em></p>
<h3 id="magic-wondrous-medusa_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/flesh_to_stone">flesh to stone</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _miasmatic_mask = {title: "Miasmatic Mask", jsx: <><h2 id="magic-wondrous-miasmatic_mask-miasmatic-mask">Miasmatic Mask</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 23,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This dark purple mask is contorted and twisted, and it covers the top half of the wearer's face in swirls of thick brocade and lace. Dappled across the mask's swaths are dozens of twinkling amethysts. This mask grants the wearer the ability to transform into a poisonous gaseous form once per day, as per the spell <em>miasmatic form.</em> This transformation lasts for 5 minutes, at which point the wearer immediately turns back into her original form. If the wearer reverts to her original form in a space that would not normally accommodate her body, she is shunted to the nearest such open space. Activating this mask is a standard action that provokes attacks of opportunity.</p>
<h3 id="magic-wondrous-miasmatic_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/miasmatic_form">miasmatic form</Link>; <strong>Cost</strong> 11,500 gp</p>
</>};
const _misers_mask = {title: "Miser's Mask", jsx: <><h2 id="magic-wondrous-misers_mask-misers-mask">Miser's Mask</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 246</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This wooden mask depicts the sunken face of a miser with an upturned nose. The mask grants the wearer the <Link to="/umr/scent">scent</Link> ability, but she can use it only to sense coins and gems. Each type and quality of gem has its own unique aura to the wearer, granting her a +5 competence bonus on <Link to="/skill/appraise">Appraise</Link> checks made to ascertain the value of gems.</p>
<h3 id="magic-wondrous-misers_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bloodhound">bloodhound</Link>, the creator must have 4 ranks in Appraise; <strong>Cost</strong> 1,500 gp</p>
</>};
const _mitre_of_the_hierophant = {title: "Mitre of the Hierophant", jsx: <><h2 id="magic-wondrous-mitre_of_the_hierophant-mitre-of-the-hierophant">Mitre of the Hierophant</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 247</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This ostentatious hat functions only for a wearer who can cast divine spells. The wearer gains a +5 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> and <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> checks. Once per day on command, the wearer can ask a single question of her patron deity, as if by using <em>commune.</em> Once per week on command, the wearer can touch a creature, atoning it for past misdeeds as if using an <em>atonement</em> spell.</p>
<h3 id="magic-wondrous-mitre_of_the_hierophant-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/atonement">atonement</Link>, <Link to="/spell/commune">commune</Link>, <Link to="/spell/guidance">guidance</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _mortuary_mask = {title: "Mortuary Mask", jsx: <><h2 id="magic-wondrous-mortuary_mask-mortuary-mask">Mortuary Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_comics_12">Pathfinder Comics #12 pg. 26</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 6th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A mortuary mask covers the top half of the face, leaving the mouth and chin exposed. The design of this eerie mask evokes that of a human skull, although some mortuary masks have more canine or even demonic features. Regardless of the mask's appearance, once it is donned, a mortuary mask works to enhance the wearer's presence, making him or her appear more horrific and frightening and granting a resonant tone to the wearer's voice. These enhancements grant a +3 circumstance bonus on all <Link to="/skill/intimidate">Intimidate</Link> checks made while the mask is worn. In addition to this unnerving effect, a mortuary mask also grants constant deathwatch while it is worn, allowing the wearer to see the auras of living and dead creatures within 30 feet. The wearer loses the ability if he is <Link to="/misc/blinded">blinded</Link> or cannot see (such as might occur while in darkness). Furthermore, the mask guides the wearer's hand against foes who are heavily wounded. When the wearer of a mortuary mask attacks a creature that has 3 or fewer hit points remaining, the wearer gains a +2 insight bonus on the attack roll.</p>
<h3 id="magic-wondrous-mortuary_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cause_fear">cause fear</Link>, <Link to="/spell/deathwatch">deathwatch</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _mouthpiece_of_the_dominion = {title: "Mouthpiece of the Dominion", jsx: <><h2 id="magic-wondrous-mouthpiece_of_the_dominion-mouthpiece-of-the-dominion">Mouthpiece of the Dominion</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_88_valley_of_the_brain_collectors">Pathfinder #88: Valley of the Brain Collectors pg. 74</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The snake-like mouthpiece of the Dominion has a fanged mouth for a "head" and a trachea for a "tail." Though not mobile, the mouthpiece periodically thrashes and bites. As a full-round action that provokes attacks of opportunity, a mouthpiece of the Dominion can be forced into or pulled out of the throat of a Small or Medium creature that is willing or helpless. Installing or removing a mouthpiece deals 2 points of <Link to="/rule/constitution_damage">Constitution damage</Link> to the wearer.</p>
<p>The mouthpiece of the Dominion merges with the wearer's own mouth and throat. The wearer gains a bite attack that deals 1d6 points of damage (1d4 if the wearer is Small). If the wearer already has a natural bite attack, its damage is increased by one step. In addition, the wearer gains a +1 bonus to the DC of his audible <Link to="/ability/bardic_performance">bardic performances</Link> and any sonic or language-dependent spells and spell-like abilities he uses.</p>
<p>Any <Link to="/monster/neh_thalggu">neh-thalggu</Link> within telepathic range of the wearer can speak audibly through the mouthpiece of the Dominion. If multiple creatures wish to speak at the same time (either the wearer or one or more neh-thalggus), they must make opposed Charisma checks to determine who controls the mouthpiece each round. When speaking through the mouthpiece, a neh-thalggu can have any audible bardic performance or any sonic or language-dependent spell or spell-like ability it uses originate from the wearer instead of itself. These effects have their DC increased by the mouthpiece.</p>
<h3 id="magic-wondrous-mouthpiece_of_the_dominion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/magic_mouth">magic mouth</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _muzzle_of_suppression = {title: "Muzzle of Suppression", jsx: <><h2 id="magic-wondrous-muzzle_of_suppression-muzzle-of-suppression">Muzzle of Suppression</h2>
<p><strong>Sources</strong> <Link to="/source/wardens_of_the_reborn_forge">Wardens of the Reborn Forge pg. 26</Link><br/><strong>Aura</strong> faint abjuration and illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A muzzle of suppression hardly resembles the long-snouted devices often equipped to dogs or other dangerous creatures. More mask than anything, this leather garment sports an orange metallic ball that's inserted in the creature's mouth, after which the mask's straps and chains are secured around the back of the creature's head and neck. The muzzle can be strapped around a humanoid-shaped head (such as that of a <Link to="/monster/capramace">capramace</Link>) to negate the creature's ability to speak, mumble, or make any noise at all, identical to the effect of a <em>silence</em> spell. Not even muffled cries for help can pierce the barrier created by a muzzle of suppression. The garment's keystone strap can only be opened by the creature that placed the muzzle on its subject; other creatures attempting to disassemble the strap must succeed at a DC 30 <Link to="/skill/disable_device">Disable Device</Link> check to do so. A <Link to="/spell/dispel_magic">dispel magic</Link> or <Link to="/spell/knock">knock</Link> spell can also unlock a muzzle of suppression.</p>
<h3 id="magic-wondrous-muzzle_of_suppression-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_lock">arcane lock</Link>, <Link to="/spell/silence">silence</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _nightgaunt_mask = {title: "Nightgaunt Mask", jsx: <><h2 id="magic-wondrous-nightgaunt_mask-nightgaunt-mask">Nightgaunt Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_65_into_the_nightmare_rift">Pathfinder #65: Into the Nightmare Rift pg. 62</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> head; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lbs.</p>
<p>A black, horned nightgaunt mask has two eyeholes but no other facial features. When the mask is worn, even the eyeholes vanish, leaving the wearer with no visible face at all. The wearer gains the advantages shared by the faceless <Link to="/monster/nightgaunt">nightgaunts</Link> on which the mask is based. The entire face of the mask functions as a sort of "eye," allowing the wearer to see normally. The wearer also gains a +4 bonus on all saving throws against <Link to="/umr/gaze">gaze</Link> attacks, and does not breathe (and is thus immune to inhaled toxins and scent-based effects). However, the wearer can't speak, and therefore can't cast spells or use items that require verbal components or command words.</p>
<p>Once per day, but only after wearing the mask for at least 1 hour, the wearer can summon 1d4+1 nightgaunts to do her bidding, as if by casting <em>summon monster VI.</em> These nightgaunts remain for 11 rounds. Alternatively, the wearer can summon a single nightgaunt that remains for 24 hours. She can communicate with and thus give orders to these nightgaunts via telepathy to a range of 100 feet. If the wearer removes the nightgaunt mask, any summoned nightgaunts immediately turn on her and attempt to carry her off and drop her from a great height before vanishing.</p>
<h3 id="magic-wondrous-nightgaunt_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/blindness_deafness">blindness/deafness</Link>, <Link to="/spell/summon_monster_vi">summon monster VI</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _nose_ring_of_unearthly_scent = {title: "Nose Ring of Unearthly Scent", jsx: <><h2 id="magic-wondrous-nose_ring_of_unearthly_scent-nose-ring-of-unearthly-scent">Nose Ring of Unearthly Scent</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 13</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 11,475 gp; <strong>Weight</strong> -</p>
<p>This item allows its wearer to smell curses as an unearthly odor with traces of brimstone and iron. As a standard action, the wearer can bring its nose near an object or creature and sniff the target to glean information as if using <em>detect magic,</em> except this effect only detects curses and cursed items. The wearer must concentrate as normal to learn all possible information about the object or creature in question.</p>
<p>Once per day as a standard action, the wearer can sniff the air for signs of danger while considering a specific course of action to gain an effect similar to <em>augury.</em> The perceived smell of a favorite food indicates "weal" and the smell of death indicates "woe."</p>
<h3 id="magic-wondrous-nose_ring_of_unearthly_scent-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/augury">augury</Link>, <Link to="/spell/detect_magic">detect magic</Link>; <strong>Cost</strong> 6,675 gp</p>
</>};
const _ossuary_mask = {title: "Ossuary Mask", jsx: <><h2 id="magic-wondrous-ossuary_mask-ossuary-mask">Ossuary Mask</h2>
<p><strong>Sources</strong> <Link to="/source/tombs_of_golarion">Tombs of Golarion pg. 43</Link><br/><strong>Aura</strong> faint abjuration and divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,100 gp; <strong>Weight</strong> 1 lb.</p>
<p>This golden funerary mask depicts the serene expression found only at the moment of a peaceful death. When worn, it grants the wearer a +2 competence bonus on <Link to="/skill/appraise">Appraise</Link>, <Link to="/skill/perception">Perception</Link>, and <Link to="/skill/sense_motive">Sense Motive</Link> checks, and a +2 resistance bonus on Will saving throws.</p>
<h3 id="magic-wondrous-ossuary_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 1,550 gp</p>
</>};
const _plague_mask = {title: "Plague Mask", jsx: <><h2 id="magic-wondrous-plague_mask-plague-mask">Plague Mask</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 247</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 7,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This stylized bird mask consists of a pair of goggles attached to a ceramic beak that covers the nose and mouth. The goggles are not magic and can be replaced with other goggles or eye slot items. It grants the wearer a +4 resistance bonus on saving throws against disease. Once per day on command, the user can <em>remove disease</em> (as the spell) on a single creature touched.</p>
<h3 id="magic-wondrous-plague_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/remove_disease">remove disease</Link>; <strong>Cost</strong> 3,750 gp</p>
</>};
const _plaguebringers_mask = {title: "Plaguebringer's Mask", jsx: <><h2 id="magic-wondrous-plaguebringers_mask-plaguebringers-mask">Plaguebringer's Mask</h2>
<p><strong>Sources</strong> <Link to="/source/curse_of_the_crimson_throne">Curse of the Crimson Throne pg. 435</Link>, <Link to="/source/pathfinder_8_seven_days_to_the_grave">Pathfinder #8: Seven Days to the Grave pg. 18</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Resembling the more common nonmagical doctor's mask, a plaguebringer's mask grants a +2 resistance bonus on saving throws against nauseating scents and immunity to one specific <Link to="/rule/diseases">disease</Link> (the disease must be chosen at the time of the mask's creation - the ones in this adventure grant immunity to <Link to="/disease/blood_veil">blood veil</Link>). The mask also veils the wearer's alignment, making her aura register as neutral to alignment-detecting effects.</p>
<h3 id="magic-wondrous-plaguebringers_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/misdirection">misdirection</Link>, <Link to="/spell/remove_disease">remove disease</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _plume_of_panache = {title: "Plume of Panache", jsx: <><h2 id="magic-wondrous-plume_of_panache-plume-of-panache">Plume of Panache</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 233</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This plume is oversized, chic, and extravagant. To gain its effects, the user must affix it to a nonmagical hat worth at least 10 gp. Once per day when the wearer performs a <Link to="/ability/swashbuckler_deeds">deed</Link>, the plume provides her with 1 panache point that can be used for that deed. Once used, the plume appears wilted and bedraggled until its magic is replenished.</p>
<h3 id="magic-wondrous-plume_of_panache-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _quick_change_mask = {title: "Quick-Change Mask", jsx: <><h2 id="magic-wondrous-quick_change_mask-quick-change-mask">Quick-Change Mask</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 250</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 650 gp; <strong>Weight</strong> -</p>
<p>A wearer can remove this mask as a move action to change his appearance as if using <em>disguise self.</em> The effect persists for 10 minutes. A <Link to="/class/vigilante">vigilante</Link> can instead remove a quick-change mask to switch his identity as a move action. If the mask is used in this way, the effect functions just like changing identities normally (except faster), and doesn't have a limited duration. Regardless of which way he is using a quick-change mask, the user can attempt a <Link to="/skill/bluff">Bluff</Link> check to create a diversion so he can use <Link to="/skill/stealth">Stealth</Link> as part of the same move action he uses to activate the mask. The mask dissolves when used.</p>
<h3 id="magic-wondrous-quick_change_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>; <strong>Cost</strong> 325 gp</p>
</>};
const _reapers_mask = {title: "Reaper's Mask", jsx: <><h2 id="magic-wondrous-reapers_mask-reapers-mask">Reaper's Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_102_breaking_the_bones_of_hell">Pathfinder #102: Breaking the Bones of Hell pg. 13</Link>, <Link to="/source/pathfinder_2_the_skinsaw_murders">Pathfinder #2: The Skinsaw Murders pg. 47</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 422</Link><br/><strong>Aura</strong> moderate enchantment [evil]; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of a reaper's mask gains a +2 competence bonus on <Link to="/skill/perception">Perception</Link> checks made against creatures that aren't immune to fear and a +1 profane bonus on damage with slashing weapons made against living creatures. The wearer can cast confusion twice per day (DC 16). When a reaper's mask is donned, the wearer takes 1 point of <Link to="/rule/charisma_damage">Charisma damage</Link> - most Skinsaw cultists don their masks well in advance of a mission so they have time to recover.</p>
<h3 id="magic-wondrous-reapers_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/confusion">confusion</Link>, <Link to="/spell/deathwatch">deathwatch</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _roseskin_comb = {title: "Roseskin Comb", jsx: <><h2 id="magic-wondrous-roseskin_comb-roseskin-comb">Roseskin Comb</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 8</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 37,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>A green copper comb holds this pink-hued alabaster headpiece in its wearer's hair, subtly infusing her skin with strength. In addition to providing an air of loveliness to its wearer, a roseskin comb grants a +2 enhancement bonus to its wearer's natural armor. In addition, three times per day as a standard action, the wearer of a roseskin comb can command barbs to protrude from her skin, as per <em>thorn body,</em> for 7 rounds.</p>
<h3 id="magic-wondrous-roseskin_comb-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/barkskin">barkskin</Link>, <Link to="/spell/thorn_body">thorn body</Link>; <strong>Cost</strong> 18,500 gp</p>
</>};
const _seashell_diving_mask = {title: "Seashell Diving Mask", jsx: <><h2 id="magic-wondrous-seashell_diving_mask-seashell-diving-mask">Seashell Diving Mask</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 23</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This striped pink conch shell has thin leathery straps to keep it attached to the wearer's face, with a clear mask attached to the top that the wearer can see through. Prized by shoreborn pirates for searching for underwater treasure, these diving masks are popular among many different sailors. The interior of the shell holds enough air to allow the wearer to breathe underwater for 10 minutes, but the mask must then be exposed to air for 20 minutes before it can be used again to breathe underwater. The wearer gains a +4 competence bonus on <Link to="/skill/perception">Perception</Link> checks while underwater, and she can detect and attempt to identify magical auras underwater as though she had cast <em>detect magic.</em></p>
<h3 id="magic-wondrous-seashell_diving_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/air_bubble">air bubble</Link>, <Link to="/spell/detect_magic">detect magic</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _sensory_deprivation_hood = {title: "Sensory Deprivation Hood", jsx: <><h2 id="magic-wondrous-sensory_deprivation_hood-sensory-deprivation-hood">Sensory Deprivation Hood</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 261</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 27,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This especially heavy leather <Link to="/eq-misc/hoodwink_cowl">hoodwink cowl</Link> is designed to quiet the wearer's mundane senses, allowing him to focus on his supernatural senses. Donning or removing the hood requires 1 minute, or 5 rounds with assistance.</p>
<p>As with a normal hoodwink cowl, the wearer of a sensory deprivation hood is <Link to="/misc/blinded">blinded</Link>, <Link to="/misc/deafened">deafened</Link>, and takes a -10 penalty on all other <Link to="/skill/perception">Perception</Link> checks. If the wearer has <Link to="/umr/blindsense">blindsense</Link>, <Link to="/umr/blindsight">blindsight</Link>, <Link to="/umr/tremorsense">tremorsense</Link>, or a similar ability, he can take a full-round action to suppress those senses for as long as he wears the hood or until he resumes using them (which requires another full-round action). If the wearer is currently benefitting from one of these senses, he gains no benefits from the hood.</p>
<p>As long as the wearer's senses are suppressed, he gains the ability to perform <Link to="/skill/automatic_writing">automatic writing</Link>, <Link to="/skill/dowsing">dowsing</Link>, and <Link to="/skill/psychometry">psychometry</Link> even if he doesn't have psychic spellcasting or the <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> feat. If he does have psychic spellcasting or the Psychic Sensitivity feat, he gains a +5 bonus on skill checks for those skill unlocks.</p>
<p>Additionally, once per day while wearing the sensory deprivation hood, the wearer can open up his mind to passing spiritual phenomena in the hope of gaining greater insight into a specific issue. This functions as <em>contact other plane,</em> allowing the wearer to ask up to 5 questions per use, but rather than contacting an entity on another plane of existence, the wearer contacts a nearby spirit or other psychic entity. Rather than using the information for one of the planes listed in the spell, this effect uses the following information:</p>
<blockquote>
<p><strong>Avoid Int/Cha Decrease DC</strong> 10/24 hours; <strong>True Answer</strong> 01-34; <strong>Don't Know</strong> 35-62; <strong>Lie</strong> 63-83; <strong>Random Answer</strong> 84-100.</p>
</blockquote>
<p>Unlike with <em>contact other plane,</em> the wearer can attempt either an Intelligence check or a Charisma check to avoid the Intelligence and Charisma decrease.</p>
<h3 id="magic-wondrous-sensory_deprivation_hood-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/contact_other_plane">contact other plane</Link>; <strong>Cost</strong> 13,750 gp</p>
</>};
const _shadow_fletching = {title: "Shadow Fletching", jsx: <><h2 id="magic-wondrous-shadow_fletching-shadow-fletching">Shadow Fletching</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>These small black feathers appear to have been stripped off an arrow and crafted into a token. By braiding a shadow fletching into her hair, a character can imbue herself with the magic of the Shadow Plane. Three times per day by touching the fletching as a swift action in an area of <Link to="/rule/dim_light">dim light</Link> or darkness, the wearer can enshroud her next ranged attack in shadowy extraplanar energy. As long as the wearer makes this attack before the end of her turn, the target of the attack is denied its Dexterity bonus to AC as if the attacker were <Link to="/rule/invisible">invisible</Link>. This doesn't affect creatures with low-light vision, darkvision, or any ability that allows them to see invisible creatures.</p>
<h3 id="magic-wondrous-shadow_fletching-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gloomblind_bolts">gloomblind bolts</Link>, creator must be a <Link to="/race/fetchling">fetchling</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _shawl_of_shadowy_disguise = {title: "Shawl of Shadowy Disguise", jsx: <><h2 id="magic-wondrous-shawl_of_shadowy_disguise-shawl-of-shadowy-disguise">Shawl of Shadowy Disguise</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 27</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 1,350 gp; <strong>Weight</strong> 1 lb.</p>
<p>This violet shawl twists and melds with the darkness, becoming as black as coal in even the faintest shadow. While worn, the wearer can hide her appearance as if with a <em>penumbral disguise</em> spell. Onlookers never discern that the wearer was wearing a shawl of shadowy disguise.</p>
<h3 id="magic-wondrous-shawl_of_shadowy_disguise-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/penumbral_disguise">penumbral disguise</Link>; <strong>Cost</strong> 675 gp</p>
</>};
const _shawl_of_the_lingering_phantom = {title: "Shawl of the Lingering Phantom", jsx: <><h2 id="magic-wondrous-shawl_of_the_lingering_phantom-shawl-of-the-lingering-phantom">Shawl of the Lingering Phantom</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 31</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,200 gp; <strong>Weight</strong> -</p>
<p>This ghost-white shawl is partially transparent and flutters elegantly with every motion its wearer makes. If the wearer has the shared consciousness class feature, she gains the <Link to="/feat/skill_focus">Skill Focus</Link> feat in both skills determined by her phantom's <Link to="/ability/emotional_focus">emotional focus</Link> while the <Link to="/sidekick/phantom">phantom</Link> is manifested in ectoplasmic or incorporeal form. While her phantom is confined in her consciousness, she instead gains a +4 competence bonus on skill checks with those skills.</p>
<h3 id="magic-wondrous-shawl_of_the_lingering_phantom-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/borrow_skill">borrow skill</Link>, creator must be a spiritualist with the shared consciousness class feature.; <strong>Cost</strong> 1,600 gp</p>
</>};
const _shepsi_aks_funerary_mask = {title: "Shepsi-ak's Funerary Mask", jsx: <><h2 id="magic-wondrous-shepsi_aks_funerary_mask-shepsi-aks-funerary-mask">Shepsi-ak's Funerary Mask</h2>
<p><strong>Sources</strong> <Link to="/source/undead_unleashed">Undead Unleashed pg. 43</Link><br/><strong>Aura</strong> moderate varied; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>An undead wearing this golden mask is treated as both an undead and a creature of the type it was before becoming undead (including any associated subtypes) for the purposes of determining its eligibility as a target of illusion and transmutation spells (such as <Link to="/spell/alter_self">alter self</Link> or <Link to="/spell/disguise_self">disguise self</Link>). A corpse wearing the mask gains the effects of <Link to="/spell/gentle_repose">gentle repose</Link> and <em>sanctify corpse.</em> A living creature wearing the mask gains no effects.</p>
<h3 id="magic-wondrous-shepsi_aks_funerary_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link>, <Link to="/spell/sanctify_corpse">sanctify corpse</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _skinsaw_mask = {title: "Skinsaw Mask", jsx: <><h2 id="magic-wondrous-skinsaw_mask-skinsaw-mask">Skinsaw Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_100_a_song_of_silver">Pathfinder #100: A Song of Silver pg. 21</Link>, <Link to="/source/pathfinder_2_the_skinsaw_murders">Pathfinder #2: The Skinsaw Murders pg. 45</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 426</Link><br/><strong>Aura</strong> faint necromancy [evil]; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of a skinsaw mask gains a +2 competence bonus on <Link to="/skill/perception">Perception</Link> checks against creatures that aren't immune to fear and a +1 profane bonus on damage rolls with slashing weapons made against living creatures. When a mask is donned, the wearer takes 1 point of <Link to="/rule/charisma_damage">Charisma damage</Link> - most Skinsaw cultists don their masks well in advance of a mission.</p>
<h3 id="magic-wondrous-skinsaw_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/deathwatch">deathwatch</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _snipers_helmet = {title: "Sniper's Helmet", jsx: <><h2 id="magic-wondrous-snipers_helmet-snipers-helmet">Sniper's Helmet</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_71_rasputin_must_die">Pathfinder #71: Rasputin Must Die! pg. 61</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>A sniper's helmet looks like the simple steel soldier's helmet common to the European trenches of the First World War, with the addition of a steel eye shield. Once per day, the wearer of a sniper's helmet can, as a standard action, denote one creature within her line of sight as her target. The wearer can perceive the target when it is invisible or ethereal as though using the <Link to="/spell/see_invisibility">see invisibility</Link> spell, and gains a +20 competence bonus on <Link to="/skill/perception">Perception</Link> checks to locate the target. The wearer ignores <Link to="/rule/concealment">concealment</Link> provided by fog or mist, blur, displacement, invisibility, and similar effects affecting the target, but not concealment provided by darkness. These bonuses last for 5 minutes or until the target creature is dead. The sniper's helmet provides no benefits to the wearer's allies, and the wearer gains no benefits against creatures other than her chosen target.</p>
<p>In addition, once per day, the wearer of a sniper's helmet can create a magical sensor up to 600 feet above her that gives her a full 360-degree viewpoint as if she were actually there. The wearer perceives with her normal visual senses, and though the sensor cannot penetrate solid surfaces, it is unaffected by foliage and the like.</p>
<h3 id="magic-wondrous-snipers_helmet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagle_eye">eagle eye</Link>, <Link to="/spell/hunters_eye">hunter's eye</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _stags_helm = {title: "Stag's Helm", jsx: <><h2 id="magic-wondrous-stags_helm-stags-helm">Stag's Helm</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_31_stolen_land">Pathfinder #31: Stolen Land pg. 52</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This striking helmet is crafted to resemble the skull of a mighty stag. Although made from bone, the antlers and helm are as strong as metal. When worn, the helm greatly enhances eyesight and hearing, granting a +2 competence bonus on <Link to="/skill/perception">Perception</Link> checks. In addition, once per day the helm may be called upon to enhance any ranged attack made by the wearer to make an insightful shot. Activating this ability is a free action, and once activated, your next ranged attack against a target within 30 feet is made as if that target were <Link to="/rule/flat_footed">flat-footed</Link> against you - this allows a rogue to gain the benefit of <Link to="/ability/sneak_attack">sneak attack</Link> with this shot. If you don't make a ranged attack within 1 round of activating this power, the insight fades and is wasted for that day.</p>
<p>A worshiper of <Link to="/faith/erastil">Erastil</Link> who wears this helm may utilize the insightful shot ability up to 3 times per day.</p>
<h3 id="magic-wondrous-stags_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have at least 5 ranks in Perception, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _stalkers_mask = {title: "Stalker's Mask", jsx: <><h2 id="magic-wondrous-stalkers_mask-stalkers-mask">Stalker's Mask</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 247</Link>, <Link to="/source/pathfinder_2_the_skinsaw_murders">Pathfinder #2: The Skinsaw Murders pg. 40</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 427</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>Preserved sections harvested from several different human faces cover this mask. When worn, the mask desaturates the wearer's color, making him appear shadowy and granting a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. Once per day as a full-round action, the wearer can cause the mask's features to take on the appearance of any creature of the wearer's basic size and shape within 60 feet that he observes, allowing the wearer to adopt that creature's appearance for 1 hour. This grants him a +10 bonus on <Link to="/skill/disguise">Disguise</Link> checks made to appear as the creature. The mask also grants the wearer a +1 bonus on attack rolls and weapon damage rolls made against the creature he is disguised as, as the mask builds upon the wearer's rage and jealousy of the target's appearance.</p>
<h3 id="magic-wondrous-stalkers_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/rage">rage</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _steel_mind_cap = {title: "Steel-mind Cap", jsx: <><h2 id="magic-wondrous-steel_mind_cap-steel-mind-cap">Steel-mind Cap</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 247</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 33,600 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Ruined scraps of various constructs were repurposed and combined to form this ornate iron helmet. Though the helmet is not intelligent, it has a brute mechanical cunning that allows it to assert control whenever the wearer's mind is overwhelmed. The helmet takes control of the wearer's body anytime he is <Link to="/misc/dazed">dazed</Link> or <Link to="/misc/stunned">stunned</Link>. Whenever the wearer would be dazed, he is instead <Link to="/misc/confused">confused</Link>. Whenever the wearer would be stunned, he is instead confused and <Link to="/misc/staggered">staggered</Link>.</p>
<p>Time spent under the cap's influence counts against the duration of the daze or stun effect. The cap functions for up to 5 rounds per day. These rounds do not need to be consecutive. The cap stops asserting control over its wearer when the duration of the daze or stun effect ends, or when the cap's 5 rounds of duration are expended.</p>
<h3 id="magic-wondrous-steel_mind_cap-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/surmount_affliction">surmount affliction</Link>; <strong>Cost</strong> 16,800 gp</p>
</>};
const _stormlords_helm = {title: "Stormlord's Helm", jsx: <><h2 id="magic-wondrous-stormlords_helm-stormlords-helm">Stormlord's Helm</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 247</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> head; <strong>Price</strong> 35,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Two large horns jut from the sides of this iron helm, each of them carved with runes representing storms, thunder, and lightning. The runes give the wearer the ability to control the elements and bring forth a great storm. Once per day, the wearer can call upon the magic of the helm to call a thunderstorm, as if casting the <em>control weather</em> spell. Like that spell, it takes 10 minutes to call the weather and an additional 10 minutes for the thunderstorm to manifest. Once it does, the wearer can <em>call lighting</em> (as the spell) for 10 minutes or until the wearer dismisses the thunderstorm with a standard action.</p>
<h3 id="magic-wondrous-stormlords_helm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/call_lightning">call lightning</Link>, <Link to="/spell/control_weather">control weather</Link>; <strong>Cost</strong> 17,500 gp</p>
</>};
const _thremyrs_beard_lesser = {title: "Thremyr's Beard (Lesser)", jsx: <><h2 id="magic-wondrous-thremyrs_beard_lesser-thremyrs-beard">Thremyr's Beard</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_94_ice_tomb_of_the_giant_queen">Pathfinder #94: Ice Tomb of the Giant Queen pg. 33</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 13th<br/><strong>Slot</strong> head; <strong>Price</strong> 32,250 gp (Lesser), 42,250 gp (Greater); <strong>Weight</strong> 2 lbs.</p>
<p>This <Link to="/eq-material/mithral">mithral</Link> helm has a faceplate resembling a <Link to="/monster/frost_giant">frost giant's</Link> face, complete with a beard formed from layered, thin metal rods. While wearing a Thremyr's beard, a creature gains a +5 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks and a +2 circumstance bonus on <Link to="/skill/disguise">Disguise</Link> checks to impersonate a frost giant or <Link to="/monster/svathurim">svathurim</Link> (though the helm does nothing to increase the wearer's size).</p>
<p>Once per day as an immediate action after being successfully hit by a melee weapon, the wearer of a lesser Thremyr's beard can order the helm to animate, whereupon the thin metal rods of the helm's beard reach out to grasp the weapon. This functions as a <Link to="/rule/disarm">disarm</Link> combat maneuver that does not provoke an attack of opportunity.</p>
<p>A lesser Thremyr's beard has a CMB of +23; the wearer can use the helm's CMB or her own CMB, whichever is higher.</p>
<p>A greater Thremyr's beard functions identically to the lesser version, but offers more protection for the wearer's vulnerable neck. Once per day as an immediate action after a critical hit is confirmed against the wearer with a melee weapon, the wearer can force the attacker to reroll the confirmation roll and take the worse result.</p>
<h3 id="magic-wondrous-thremyrs_beard_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/grasping_hand">grasping hand</Link> (lesser and greater), <Link to="/spell/ill_omen">ill omen</Link> (greater); <strong>Cost</strong> 17,625 gp (Lesser), 21,125 gp (Greater)</p>
</>};
const _tin_cap = {title: "Tin Cap", jsx: <><h2 id="magic-wondrous-tin_cap-tin-cap">Tin Cap</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 265</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This simple tin headpiece is a lesser replica of the powerful <Link to="/magic-artifact/stannum_crown">stannum crown</Link>. A tin cap feeds on its wearer's paranoia, granting her a +4 insight bonus on saving throws against mind-affecting effects and divinations that gather information about her. Donning a tin cap saps the mind of the wearer, imposing a -2 penalty to her Intelligence, Wisdom, and Charisma. The increased paranoia causes the wearer to always attempt saving throws, even against harmless effects. Removing the tin cap removes both the benefits and drawbacks until it is donned again.</p>
<h3 id="magic-wondrous-tin_cap-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mind_blank">mind blank</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _tlil_mask = {title: "Tlil Mask", jsx: <><h2 id="magic-wondrous-tlil_mask-tlil-mask">Tlil Mask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_143_borne_by_the_suns_grace">Pathfinder #143: Borne by the Sun's Grace pg. 25</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 3,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This colorful, beaded mask bears floral patterns and attunes the wearer's senses to flora of all varieties. The wearer gains a +3 competence bonus on <Link to="/skill/knowledge_nature">Knowledge (nature)</Link> checks relating to plants, seasons, or weather. The wearer can use a command word to gain the effects of <em>greensight,</em> except that the wearer can freely focus her vision to see through plant matter for any distance up to 60 feet (for example, to examine the inner core of a reed) during the effect's duration. The <em>greensight</em> ability can be used a total of 10 times; when these uses are expended, the mask loses its magic and becomes a normal beaded mask. Most Tlil masks are discovered with 1d10 uses of <em>greensight</em> remaining; reduce the price by 300 gp for each expended use.</p>
<h3 id="magic-wondrous-tlil_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greensight">greensight</Link>; <strong>Cost</strong> 1,850 gp</p>
</>};
const _token_of_the_eldest = {title: "Token of the Eldest", jsx: <><h2 id="magic-wondrous-token_of_the_eldest-token-of-the-eldest">Token of the Eldest</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 18</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 27,680 gp; <strong>Weight</strong> -</p>
<p>A gift from an enigmatic master of the First World, each token of the <Link to="/rule/eldest">Eldest</Link> exemplifies the unique and specific relationship between its creator and its first recipient. <Link to="/faith/the_green_mother">The Green Mother</Link> might bestow a crown of interwoven willow branches, or <Link to="/faith/the_lantern_king">the Lantern King</Link> a tiara spun from moonlight. These tokens have an ethereal and fragile beauty, but prove surprisingly resistant to harm.</p>
<p>Once per day, the wearer of a token of the Eldest can use <em>commune with nature.</em> In addition to that spell's usual effects, if the area has a powerful natural protector likely to be helpful to the wearer, this protector automatically learns of the wearer and her location as well as a vague impression of her needs.</p>
<p>Once per day, the wearer can expend one use of mythic power to cast <em>charm monster</em> on a creature (DC 16 negates); fey creatures targeted by this effect take a -4 penalty on the saving throw.</p>
<p>Finally, as an immediate action the wearer can expend one use of mythic power to reroll any saving throw against a spell, spell-like ability, or supernatural ability of a fey, receiving a +2 bonus on the new saving throw. This ability must be used after the save but before the results are revealed. The wearer must take the result of the second roll, even if it's worse.</p>
<h3 id="magic-wondrous-token_of_the_eldest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/charm_monster">charm monster</Link>, <Link to="/spell/commune_with_nature">commune with nature</Link>; <strong>Cost</strong> 13,840 gp</p>
</>};
const _translators_cap_human = {title: "Translator's Cap (Human)", jsx: <><h2 id="magic-wondrous-translators_cap_human-translators-cap-human">Translator's Cap (Human)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 235</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This cap is adorned with seven brightly colored feathers of various types. Each feather imbues the cap's wearer with knowledge of one language; these languages are fixed for each translator's cap.</p>
<p>If the wearer is <Link to="/race/human">human</Link>, she can give a feather to an ally to allow that ally to use <em>tongues</em> for as long as he carries the feather on his person. Removing the feather removes the language of the wearer's choice from the cap's repertoire. A removed feather works for 1 day before turning to dust, and the cap loses its power when the last feather is gone. The price for the cap includes all seven feathers, and drops by 2,000 gp per missing feather.</p>
<h3 id="magic-wondrous-translators_cap_human-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/tongues">tongues</Link> or the ability to speak all seven languages, creator must be a human; <strong>Cost</strong> 7,000 gp</p>
</>};
const _traveling_masters_turban = {title: "Traveling Master's Turban", jsx: <><h2 id="magic-wondrous-traveling_masters_turban-traveling-masters-turban">Traveling Master's Turban</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 107</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This turban consists of 30 feet of cloth held in place by a brooch. The owner can command the turban to tie or untie itself as a move action. When the turban is tied on the wearer's head, the wearer gains the benefits of <em>endure elements.</em> Once per day when the turban is untied, the owner can use the fabric to perform a rope trick (as per the spell <em>rope trick</em>). In addition, the owner can spend 1 ki point as a swift action to cast <em>animate rope.</em></p>
<h3 id="magic-wondrous-traveling_masters_turban-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_rope">animate rope</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/rope_trick">rope trick</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _ushanka_of_the_northlands = {title: "Ushanka of the Northlands", jsx: <><h2 id="magic-wondrous-ushanka_of_the_northlands-ushanka-of-the-northlands">Ushanka of the Northlands</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_68_the_shackled_hut">Pathfinder #68: The Shackled Hut pg. 61</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> -</p>
<p>This large, furry hat is sewn from the thick pelt of an animal native to the frozen north, and has earflaps that can be pulled down or folded up over the crown of the hat. When worn, an ushanka of the northlands grants its wearer a +2 resistance bonus on saving throws against <Link to="/rule/cold_dangers">cold effects</Link> and a +5 competence bonus on <Link to="/skill/survival">Survival</Link> checks. When the earflaps are pulled down, the wearer gains a +2 bonus on saving throws against sonic effects, but also takes a -2 penalty on <Link to="/skill/perception">Perception</Link> checks made to hear. Pulling the earflaps down is a move action.</p>
<h3 id="magic-wondrous-ushanka_of_the_northlands-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/resistance">resistance</Link>, creator must have 5 ranks in Survival; <strong>Cost</strong> 2,250 gp</p>
</>};
const _vagrants_hood = {title: "Vagrant's Hood", jsx: <><h2 id="magic-wondrous-vagrants_hood-vagrants-hood">Vagrant's Hood</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 129</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 4,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>This linen hood is simply decorated with the colors of the forest and designed to cast a dramatic shadow upon the wearer's face, obscuring identifiable features. A vagrant's hood grants the wearer a +4 competence bonus on <Link to="/skill/disguise">Disguise</Link> checks and makes the wearer's voice sound deep and throaty, as per <em>vocal alteration.</em></p>
<h3 id="magic-wondrous-vagrants_hood-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/vocal_alteration">vocal alteration</Link>; <strong>Cost</strong> 2,200 gp</p>
</>};
const _veil_of_attentiveness = {title: "Veil of Attentiveness", jsx: <><h2 id="magic-wondrous-veil_of_attentiveness-veil-of-attentiveness">Veil of Attentiveness</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 12</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> head; <strong>Price</strong> 750 gp; <strong>Weight</strong> -</p>
<p>This gauzy veil sharpens the wearer's hearing, enhances her ability to interpret others' words, and improves her ability to perceive multiple conversations simultaneously. Veils of attentiveness have historically been popular among Iadaran diplomats or savvy elven political players in densely populated places. They are still especially prized in crowded areas where nobles gather, such as royal courts or upscale dining and lounging establishments in Iadara and beyond.</p>
<p>The wearer of a veil of attentiveness gains a +2 competence bonus on hearing-based <Link to="/skill/perception">Perception</Link> checks and on <Link to="/skill/sense_motive">Sense Motive</Link> checks to interpret others' meaning or to detect possible deception. In addition, when listening to multiple speakers' voices, the wearer of a veil of attentiveness can understand each speaker as though she were listening only to that voice.</p>
<h3 id="magic-wondrous-veil_of_attentiveness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/keen_senses">keen senses</Link>; <strong>Cost</strong> 375 gp</p>
</>};
const _veil_of_fleeting_glances = {title: "Veil of Fleeting Glances", jsx: <><h2 id="magic-wondrous-veil_of_fleeting_glances-veil-of-fleeting-glances">Veil of Fleeting Glances</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 247</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>In addition to hiding the face, this fine lace veil protects the wearer against <Link to="/umr/gaze">gaze</Link> attacks. The wearer has a 50% chance to avoid making a saving throw against a gaze attack even when not averting her eyes. If the wearer averts her eyes, she rolls twice (once for the veil, once for averting her eyes) and uses the more favorable result.</p>
<p>Against patterns, visual figments, and other vision-based effects and attacks that cannot affect blind creatures, the veil grants the wearer a +4 circumstance bonus on saving throws. The veil does not otherwise impede the wearer's vision in any way.</p>
<h3 id="magic-wondrous-veil_of_fleeting_glances-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blindness_deafness">blindness/deafness</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _veil_of_veils = {title: "Veil of Veils", jsx: <><h2 id="magic-wondrous-veil_of_veils-veil-of-veils">Veil of Veils</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 271</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 60</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> head; <strong>Price</strong> 3,300 gp; <strong>Weight</strong> -</p>
<p>This fine silken veil can change color or alter its appearance to a highwayman's mask or similar cloth face covering. Once per day, the wearer can use <em>disguise self,</em> though the veil remains visible as some kind of garment on the wearer's head or face.</p>
<p>If <Link to="/faith/sivanah">Sivanah</Link> is the wearer's patron, once per day the wearer can use <em>blur.</em> In addition, the wearer gains a +2 competence bonus on <Link to="/skill/bluff">Bluff</Link> checks.</p>
<h3 id="magic-wondrous-veil_of_veils-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blur">blur</Link>, <Link to="/spell/disguise_self">disguise self</Link>, creator must have 5 ranks in Bluff; <strong>Cost</strong> 1,650 gp</p>
</>};
const _vermin_mask = {title: "Vermin Mask", jsx: <><h2 id="magic-wondrous-vermin_mask-vermin-mask">Vermin Mask</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 31</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> head; <strong>Price</strong> 10,080 gp; <strong>Weight</strong> 1 lb.</p>
<p>These stylized wooden masks are carved to resemble a common type of wasteland vermin, such as a giant ant, scorpion, or spider. While using wild shape or a <em>vermin shape</em> spell to assume the form of a vermin that corresponds with the mask's design, the wearer gains the following benefits. First, the wearer can speak normally despite the limitations of the form's anatomy. Furthermore, the effect of the wearer's wild shape ability (if any) lasts for 3 additional hours, and when the wearer is under the effects of a <em>vermin shape</em> spell, the spell lasts for 7 additional minutes.</p>
<h3 id="magic-wondrous-vermin_mask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, wild shape class feature, <Link to="/spell/vermin_shape_i">vermin shape I</Link>; <strong>Cost</strong> 5,040 gp</p>
</>};
const _visage_of_the_bound = {title: "Visage of the Bound", jsx: <><h2 id="magic-wondrous-visage_of_the_bound-visage-of-the-bound">Visage of the Bound</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 21</Link><br/><strong>Aura</strong> moderate conjuration and evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 22,900 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Crafted from gold and lacquer, these elaborate masks resemble various outsiders. Once per day when the wearer casts a <em>summon monster</em> spell, he may choose to house the summoned outsider within the visage of the bound rather than conjuring it onto the Material Plane. For the spell's duration, the wearer can use of any of the bound outsider's spell-like abilities as if they were his own. A visage of the bound has no effect on outsiders already summoned or on summoning spells cast by other creatures. Removing the mask immediately releases a bound outsider.</p>
<p>The wearer cannot use the bound outsider's spell-like abilities to summon other creatures, and a <Link to="/class/summoner">summoner</Link> cannot activate a visage of the bound while his eidolon is summoned. Effects that extend the duration of a <em>summon monster</em> spell (such a the <Link to="/feat/extend_spell">Extend Spell</Link> metamagic feat or the <Link to="/arcaneschool/conjurer">conjurer's</Link> summoner's charm class ability) have no effect on the duration of a spell contained by a visage of the bound. Outsiders who are opposed to one or more axes of the wearer's alignment cannot be housed within a visage of the bound.</p>
<h3 id="magic-wondrous-visage_of_the_bound-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>, <Link to="/spell/summon_monster_v">summon monster V</Link>; <strong>Cost</strong> 11,450 gp</p>
</>};
const _visage_of_the_broodlord = {title: "Visage of the Broodlord", jsx: <><h2 id="magic-wondrous-visage_of_the_broodlord-visage-of-the-broodlord">Visage of the Broodlord</h2>
<p><strong>Sources</strong> <Link to="/source/lost_kingdoms">Lost Kingdoms pg. 51</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> head; <strong>Price</strong> 9,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>Made of interwoven wicker strands and insect-excreted resin, these horrific masks have the appearance of demonic insects. The mask's wearer is rendered immune to swarms' distraction special attack. Additionally, once per day the wearer can transform into an insect as per the spell <em>vermin shape I.</em></p>
<h3 id="magic-wondrous-visage_of_the_broodlord-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/vermin_shape_i">vermin shape I</Link>; <strong>Cost</strong> 4,800 gp</p>
</>};
const _vudran_ashak_helmet = {title: "Vudran Ashak Helmet", jsx: <><h2 id="magic-wondrous-vudran_ashak_helmet-vudran-ashak-helmet">Vudran Ashak Helmet</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_27_what_lies_in_dust">Pathfinder #27: What Lies in Dust pg. 59</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> head; <strong>Price</strong> 22,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Crafted of overlaid bronze, steel, and chain, each Vudran Ashak helmet is a work of art. These exotic helmets possess three stylized faces, each serene visage staring in a different direction (with the wearer's face concealed behind the central sculpted plate). The helm allows the wearer to see in every direction, granting him immunity to being <Link to="/rule/flanked">flanked</Link>, as well as granting a +4 enhancement bonus on all vision-based <Link to="/skill/perception">Perception</Link> checks.</p>
<p>One in every 10 Vudran Ashak helmets is an <Link to="/rule/intelligent_items">intelligent magical item</Link>, having spontaneously manifested such properties after the deaths of heroically devoted former wearers. Such helms are lawful good, speak Vudran, and have an ego score of 10. These lingering personalities prove noble, knowledgable of Vudra's diverse deities, and actively encourage wearers to defend the holy places of such gods and their devout worshipers. Some might even possess goals from their lives that they wish their new wearer to fulfill. Despite any of the helmet's desires, though, it possesses no way to compel a wearer other than deactivating or reactivating its magical properties at will.</p>
<h3 id="magic-wondrous-vudran_ashak_helmet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clairvoyance">clairvoyance</Link>; <strong>Cost</strong> 11,000 gp</p>
</>};
const _war_mask_of_terror = {title: "War Mask of Terror", jsx: <><h2 id="magic-wondrous-war_mask_of_terror-war-mask-of-terror">War Mask of Terror</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_38_racing_to_ruin">Pathfinder #38: Racing to Ruin pg. 39</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> head; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Shamans and warriors of many of the indigenous tribes of western Garund add to their fierceness and mystique by wearing wooden masks that bear terrifying visages of demonic spirits. A war mask is considered sacred and personal, and is often handed down to the next generation when a wearer dies. Individual masks are often notorious, and many tribesfolk can readily identify masks of other tribes with a DC 15 Knowledge (local) check.</p>
<p>A war mask of terror provides its wearer with a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks and a +1 deflection bonus to Armor Class. In addition, the wearer may cast <em>scare</em> once per day.</p>
<p>Other war masks exist with different abilities; some have higher deflection bonuses, while others can cast <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/fear">fear</Link>, or <Link to="/spell/flesh_to_stone">flesh to stone</Link> instead of <em>scare.</em></p>
<h3 id="magic-wondrous-war_mask_of_terror-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/scare">scare</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _yithian_thought_ring = {title: "Yithian Thought Ring", jsx: <><h2 id="magic-wondrous-yithian_thought_ring-yithian-thought-ring">Yithian Thought Ring</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_113_what_grows_within">Pathfinder #113: What Grows Within pg. 50</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 15th<br/><strong>Slot</strong> head; <strong>Price</strong> 35,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Each yithian thought ring is attuned to a particular type or category of creature, and this decision is made at the item's creation. This can go beyond simple creature types - a yithian thought ring can be made to function for very specific conditions. For example, the one in this adventure is keyed into minds that have been exposed to <Link to="/faith/xhamen_dor">Xhamen-Dor</Link>, which is how Kaklatath was able to reach out across great distances to the PCs. A <Link to="/monster/yithian">yithian</Link> wearing one of these devices can also use its mind swap and amnesia abilities at the same range.</p>
<p>Once a yithian thought ring has been created with a particular parameter, it can be attuned again, but this process requires partially dismantling the original device and rebuilding it. This process takes 1d4 days and costs an additional 5,000 gp in materials.</p>
<p>A yithian thought ring can be used only by yithians.</p>
<h3 id="magic-wondrous-yithian_thought_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/telepathic_bond">telepathic bond</Link>, creator must be a yithian; <strong>Cost</strong> 17,500 gp</p>
</>};
const _band_of_the_stalwart_warrior = {title: "Band of the Stalwart Warrior", jsx: <><h2 id="magic-wondrous-band_of_the_stalwart_warrior-band-of-the-stalwart-warrior">Band of the Stalwart Warrior</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 248</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 16th<br/><strong>Slot</strong> headband; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This plain iron band protects its wearer from fear effects. Whenever the wearer suffers a fear effect, she is merely <Link to="/misc/shaken">shaken</Link> (even if the effect would normally make the target frightened or panicked). Furthermore, the subject gains a +2 competence bonus on all Will saves against fear. If the wearer has the bravery class feature, she is considered four levels higher when determining that class feature's effect.</p>
<h3 id="magic-wondrous-band_of_the_stalwart_warrior-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _centering_jewel = {title: "Centering Jewel", jsx: <><h2 id="magic-wondrous-centering_jewel-centering-jewel">Centering Jewel</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 8</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> headband; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This simple teardrop jewel is worn on the center of the forehead and gives its wearer the ability to quickly focus her mind. The wearer can center herself (see <Link to="/rule/components_oa">Thought Components</Link>) as a swift action.</p>
<h3 id="magic-wondrous-centering_jewel-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/burst_of_insight">burst of insight</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _circlet_of_speaking = {title: "Circlet of Speaking", jsx: <><h2 id="magic-wondrous-circlet_of_speaking-circlet-of-speaking">Circlet of Speaking</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 26</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 4th<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>This thin, silver circlet allows an animal wearing it to speak, even if it is not normally capable of doing so because of its low Intelligence score or lack of known languages. The creator of the item decides what language the circlet's wearer can speak when she crafts the item (typically Common); once crafting is complete, this cannot be changed. A circlet of speaking does not grant an animal a bonus to Intelligence, and the wearer's general behavior remains largely the same while it wears a circlet of speaking, though it can communicate its desires and rudimentary knowledge as though being spoken to via <em>speak with animals.</em></p>
<h3 id="magic-wondrous-circlet_of_speaking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>; <strong>Cost</strong> 2,400 gp</p>
</>};
const _crown_of_blindness = {title: "Crown of Blindness", jsx: <><h2 id="magic-wondrous-crown_of_blindness-crown-of-blindness">Crown of Blindness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 345</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> moderate illusion; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Weight</strong> 1 lb.</p>
<p>This fine silver circlet is often set with a milky moonstone. When a wearer places it on his head, the stone quickly goes dark like the waning moon, and the wearer must make a DC 14 Fortitude saving throw or immediately go <Link to="/misc/blind">blind</Link>. The saving throw must be made each round that the crown is worn until the wearer succumbs to the blindness. Removing the circlet requires breaking the curse. In addition to a <Link to="/spell/remove_curse">remove curse</Link> spell or similar effect, <Link to="/spell/remove_blindness_deafness">remove blindness/deafness</Link> can be used to end the circlet's curse long enough to remove the item.</p>
<h3 id="magic-wondrous-crown_of_blindness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/headband_of_alluring_charisma">headband of alluring charisma</Link>, <Link to="/magic-wondrous/headband_of_inspired_wisdom">headband of inspired wisdom</Link>, <Link to="/magic-wondrous/headband_of_mental_prowess">headband of mental prowess</Link>, <Link to="/magic-wondrous/headband_of_mental_superiority">headband of mental superiority</Link>, <Link to="/magic-wondrous/headband_of_vast_intelligence">headband of vast intelligence</Link>, <Link to="/magic-wondrous/moon_circlet">moon circlet</Link>; <strong>Cost</strong> -</p>
</>};
const _dead_mans_headband = {title: "Dead Man's Headband", jsx: <><h2 id="magic-wondrous-dead_mans_headband-dead-mans-headband">Dead Man's Headband</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 248</Link><br/><strong>Aura</strong> faint enchantment and abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> headband; <strong>Price</strong> 3,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This taut black band, clipped with a black metal skull, can be attached on the outside of a hat or other head slot item or can be worn as a normal headband. The wearer gains a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks and increases the DC of any fear effect he creates by +1. In addition, if this headband is attached to the outside of a hat, the wearer's hat or headgear cannot be blown off or removed by wind, water, or environmental effects, and the wearer gains a +5 circumstance bonus to his CMD against <Link to="/rule/steal">steal</Link> and <Link to="/rule/sunder">sunder</Link> attempts targeting his headgear.</p>
<h3 id="magic-wondrous-dead_mans_headband-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/doom">doom</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Cost</strong> 1,800 gp</p>
</>};
const _diadem_of_control = {title: "Diadem of Control", jsx: <><h2 id="magic-wondrous-diadem_of_control-diadem-of-control">Diadem of Control</h2>
<p><strong>Sources</strong> <Link to="/source/construct_handbook">Construct Handbook pg. 16</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 15th<br/><strong>Slot</strong> headband; <strong>Price</strong> 189,000 gp; <strong>Weight</strong> -</p>
<p>This elegant headband has an intricately carved crystal located in its center. The crystal shimmers with arcane energy. The wearer can remove or replace this crystal as a swift action. As a standard action, the wearer can attempt to force the gem onto a construct's body with a touch attack that provokes an attack of opportunity. Once the crystal is attached to a construct, the construct must succeed at a DC 23 Will save or become dominated by the crystal and follow the orders of whomever is wearing the headband. The wearer of the headband can assume direct control of the construct as a full-round action, controlling all of the construct's actions as <em>possession.</em> The wearer can end this control at any time as a free action. The wearer can remove the crystal from a construct as a standard action, allowing the wearer to use the crystal on a different construct and returning control of the construct to its original master. If the construct is destroyed while the crystal is attached, there is a 10% chance that the crystal is destroyed along with the construct.</p>
<h3 id="magic-wondrous-diadem_of_control-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dominate_monster">dominate monster</Link>, <Link to="/spell/possession">possession</Link>; <strong>Cost</strong> 94,500 gp</p>
</>};
const _efreeti_horns = {title: "Efreeti Horns", jsx: <><h2 id="magic-wondrous-efreeti_horns-efreeti-horns">Efreeti Horns</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 107</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 24,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of efreeti horns gains a +4 enhancement bonus to Wisdom. In addition, the wearer can spend 1 ki point as a full-round action to gain the effects of <em>enlarge person</em> (self only) or <em>reduce person</em> (self only) for 1 minute. These effects apply to the wearer regardless of her actual creature type.</p>
<h3 id="magic-wondrous-efreeti_horns-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/enlarge_person">enlarge person</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>, <Link to="/spell/reduce_person">reduce person</Link>; <strong>Cost</strong> 12,000 gp</p>
</>};
const _esoteric_diadem_lesser = {title: "Esoteric Diadem (Lesser)", jsx: <><h2 id="magic-wondrous-esoteric_diadem_lesser-esoteric-diadem">Esoteric Diadem</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 9</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 18,000 gp (Lesser), 50,000 gp (Normal), 98,000 gp (Greater); <strong>Weight</strong> -</p>
<p>The diamond-shaped gems in these metal headbands are typically one of two colors, each corresponding to a different esoteric element: onyx (void) and pink (wood). The diadem's gem grants the wearer greater control over its associated element.</p>
<p>While worn by a <Link to="/class/kineticist">kineticist</Link>, this item increases the damage dealt by the kineticist's simple and composite blasts that match the element of the inlaid gem by 1d6 points (for a lesser esoteric diadem), 2d6 points (for an esoteric diadem), or 3d6 points (for a greater esoteric diadem). If the blast is a physical blast, the extra damage dice from the esoteric diadem increase to d8s instead of d6s. These extra damage dice don't multiply on a critical hit, and they don't apply to blasts with form infusions that don't apply the extra damage from elemental overflow.</p>
<p>Other esoteric diadem variants exist for other little-known kineticist elements.</p>
<h3 id="magic-wondrous-esoteric_diadem_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be a 10th-level kineticist with access to the appropriate element; <strong>Cost</strong> 9,000 gp (Lesser), 25,000 gp (Normal), 49,000 gp (Greater)</p>
</>};
const _guerrilla_bandanna = {title: "Guerrilla Bandanna", jsx: <><h2 id="magic-wondrous-guerrilla_bandanna-guerrilla-bandanna">Guerrilla Bandanna</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 59</Link><br/><strong>Aura</strong> moderate enchantment and illusion; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Used by warband leaders in Nirmathas, a guerrilla bandanna is a plain brown and green bandanna that can be tied around the forehead. The wearer gains a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks while traveling in forested terrain, and can extend this bonus to up to 10 allies while they remain within 100 feet of the wearer.</p>
<p>If the wearer is a <Link to="/class/ranger">ranger</Link>, the guerrilla bandanna increases his <Link to="/ability/favored_enemy">favored enemy</Link> bonus on attack rolls by 1 for each of his favored enemies. If the ranger has the hunter's bond (companions) class feature, this increase also applies to the attack roll bonus his allies gain from that ability.</p>
<h3 id="magic-wondrous-guerrilla_bandanna-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/instant_enemy">instant enemy</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _headband_of_aerial_agility = {title: "Headband of Aerial Agility", jsx: <><h2 id="magic-wondrous-headband_of_aerial_agility-headband-of-aerial-agility">Headband of Aerial Agility</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 248</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,500 gp (+2), 42,000 gp (+4), 81,000 gp (+6); <strong>Weight</strong> -</p>
<p>This headband is decorated with feathers from a number of colorful birds. It grants boons to flying magic, and more powerful versions grant the power of flight. The wearer of a headband of aerial agility +2 treats his caster level as if it were one level higher when casting spells or creating extracts that grant flight. A headband of aerial agility +4 gains the same benefits and, on command, grants the wearer the ability to fly (as the <em>fly</em> spell) three times per day. A headband of aerial agility +6 functions like a +4 version, but the headband grants the ability to use <em>fly</em> at will.</p>
<p>All versions also grant the wearer an enhancement bonus to one mental ability score (Intelligence, Wisdom, or Charisma) of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn. This bonus is chosen when the headband is created and cannot be changed. If the headband grants a bonus to Intelligence, it also grants skill ranks as a <Link to="/magic-wondrous/headband_of_vast_intelligence">headband of vast intelligence</Link>, usually granting ranks in <Link to="/skill/fly">Fly</Link>, <Link to="/skill/acrobatics">Acrobatics</Link>, or <Link to="/skill/knowledge_planes">Knowledge (planes)</Link>.</p>
<h3 id="magic-wondrous-headband_of_aerial_agility-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, <Link to="/spell/fly">fly</Link>; <strong>Cost</strong> 2,250 gp (+2), 21,000 gp (+4), 40,500 gp (+6)</p>
</>};
const _headband_of_alluring_charisma = {title: "Headband of Alluring Charisma", jsx: <><h2 id="magic-wondrous-headband_of_alluring_charisma-headband-of-alluring-charisma">Headband of Alluring Charisma</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 248</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 516</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,000 gp (+2), 16,000 gp (+4), 36,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This attractive silver headband is decorated with a number of small red and orange gemstones. The headband grants the wearer an enhancement bonus to Charisma of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn.</p>
<h3 id="magic-wondrous-headband_of_alluring_charisma-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>; <strong>Cost</strong> 2,000 gp (+2), 8,000 gp (+4), 18,000 gp (+6)</p>
</>};
const _headband_of_arcane_energy = {title: "Headband of Arcane Energy", jsx: <><h2 id="magic-wondrous-headband_of_arcane_energy-headband-of-arcane-energy">Headband of Arcane Energy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 248</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 13th<br/><strong>Slot</strong> headband; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This headband has three swirling patterns of red, green, and blue crystals arching across its length. Three times per day, its wearer can sacrifice an arcane spell to create an offensive blast or defensive shield. The blast is a ranged touch attack with a range of 30 feet, which deals 1d6 points of energy damage (cold, electricity, or fire) per spell level sacrificed. The shield creates a swirling band of energy that lasts 1 round and gives the wearer a deflection bonus to AC equal to 2 + the level of the spell sacrificed.</p>
<h3 id="magic-wondrous-headband_of_arcane_energy-construction">Construction</h3>
<p><strong>Requirements</strong> Arcane Blast, Arcane Shield, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/prismatic_spray">prismatic spray</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _headband_of_controlling_illusions_elf = {title: "Headband of Controlling Illusions (Elf)", jsx: <><h2 id="magic-wondrous-headband_of_controlling_illusions_elf-headband-of-controlling-illusions-elf">Headband of Controlling Illusions (Elf)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 231</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 13th<br/><strong>Slot</strong> headband; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> -</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This elaborately woven leather beaded cord shifts in coloration from light gray at the front to pitch black at the back. Once per day on command, the headband allows the wearer to make any choices for an ongoing non-permanent illusion as if she were casting the illusion, although its duration is not reset and she cannot change its target or area. The spell's effect changes to match those choices, and its remaining duration plays out as if the wearer were its original caster. To affect the illusion, the wearer must succeed at a caster level check (with a +13 bonus for the headband's caster level) with a DC equal to 11 + the illusion's creator's caster level.</p>
<p>If the wearer is an <Link to="/race/elf">elf</Link>, she can use a second command word to cause the headband to produce illusory duplicates of up to six allies similar to how <em>mirror image</em> functions once per day. The wearer can control any number of the duplicates with a move action provided they all receive the same commands, but otherwise they mimic the actions of the originals and remain in the original's square. When in the original creature's square, the image functions exactly as <em>mirror image,</em> but when the headband's wearer directs them separately, the images have an AC equal to the original's AC - 5 and are destroyed by any successful attack roll against that AC.</p>
<h3 id="magic-wondrous-headband_of_controlling_illusions_elf-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/mirror_image">mirror image</Link>, <Link to="/spell/project_image">project image</Link>, creator must be an elf; <strong>Cost</strong> 20,000 gp</p>
</>};
const _headband_of_counterspelling = {title: "Headband of Counterspelling", jsx: <><h2 id="magic-wondrous-headband_of_counterspelling-headband-of-counterspelling">Headband of Counterspelling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 248</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> headband; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This metal headband grants a +5 insight bonus on <Link to="/skill/spellcraft">Spellcraft</Link> checks made to identify a spell as it is being cast. Furthermore, once per day the wearer can attempt to <Link to="/rule/counterspells">counter</Link> a spell by casting the appropriate spell as an immediate action instead of doing so with a readied action. The wearer must first identify the spell being cast before countering a spell with this headband.</p>
<h3 id="magic-wondrous-headband_of_counterspelling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spell_turning">spell turning</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _headband_of_deathless_devotion = {title: "Headband of Deathless Devotion", jsx: <><h2 id="magic-wondrous-headband_of_deathless_devotion-headband-of-deathless-devotion">Headband of Deathless Devotion</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 249</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 1st<br/><strong>Slot</strong> headband; <strong>Price</strong> 6,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>This white headband, often painted or embroidered with calligraphy or a stylized pictogram such as a sunburst, helps focus the wearer's resolve and absolute determination to survive and succeed. The wearer gains a +2 morale bonus on <Link to="/misc/dying">stabilization</Link> checks and on saving throws against ongoing effects with recurring saves, such as diseases, poisons, or compulsions such as <Link to="/spell/dominate_person">dominate person</Link> or <Link to="/spell/hold_person">hold person</Link>.</p>
<p>If the wearer is a <Link to="/class/samurai">samurai</Link>, he treats his resolve ability as if he were two class levels higher.</p>
<h3 id="magic-wondrous-headband_of_deathless_devotion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/stabilize">stabilize</Link>; <strong>Cost</strong> 3,200 gp</p>
</>};
const _headband_of_fortunes_favor = {title: "Headband of Fortune's Favor", jsx: <><h2 id="magic-wondrous-headband_of_fortunes_favor-headband-of-fortunes-favor">Headband of Fortune's Favor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 249</Link><br/><strong>Aura</strong> faint enchantment and evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 7,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This multicolored headband with beaded tassels tips luck in the wearer's favor. The wearer gains a +1 luck bonus on saving throws.</p>
<p>Any effect that gives the wearer a luck bonus (such as a divine favor or <em>prayer</em> spell) or explicitly increases the wearer's good luck (such as a witch's <Link to="/hex/fortune">fortune</Link> hex, the <Link to="/domain/luck">Luck</Link> domain's bit of luck domain power, and so on) lasts for 1 round longer than normal on the wearer. Abilities without a time-based duration (such as carrying a <Link to="/magic-wondrous/stone_of_good_luck">stone of good luck</Link>) are unaffected by the headband.</p>
<h3 id="magic-wondrous-headband_of_fortunes_favor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ill_omen">ill omen</Link> or <Link to="/spell/prayer">prayer</Link>; <strong>Cost</strong> 3,850 gp</p>
</>};
const _headband_of_havoc = {title: "Headband of Havoc", jsx: <><h2 id="magic-wondrous-headband_of_havoc-headband-of-havoc">Headband of Havoc</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 249</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This band of raggedly stitched animal skins and teeth focuses a <Link to="/class/barbarian">barbarian</Link> wearer's bloodlust. When the wearer enters a rage, she selects one of her <Link to="/ability/rage_powers">rage powers</Link>. For the duration of the rage, that power functions as if the wearer's barbarian level were four levels higher.</p>
<p>Once per day when the wearer is attacked or has to make a saving throw against a hostile effect, she may spend 2 rounds of rage to begin a rage as an immediate action. This rage becomes active prior to resolving the attack that triggered it and lasts until the start of her next turn (at which time she may continue to rage as if she had begun the rage in the normal manner).</p>
<h3 id="magic-wondrous-headband_of_havoc-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/rage">rage</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _headband_of_inspired_wisdom = {title: "Headband of Inspired Wisdom", jsx: <><h2 id="magic-wondrous-headband_of_inspired_wisdom-headband-of-inspired-wisdom">Headband of Inspired Wisdom</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 250</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 516</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,000 gp (+2), 16,000 gp (+4), 36,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This simple bronze headband is decorated with an intricate pattern of fine green etchings. The headband grants the wearer an enhancement bonus to Wisdom of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn.</p>
<h3 id="magic-wondrous-headband_of_inspired_wisdom-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>; <strong>Cost</strong> 2,000 gp (+2), 8,000 gp (+4), 18,000 gp (+6)</p>
</>};
const _headband_of_intuition = {title: "Headband of Intuition", jsx: <><h2 id="magic-wondrous-headband_of_intuition-headband-of-intuition">Headband of Intuition</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 250</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> headband; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This headband gives its wearer the gift of foresight, effectively allowing her to determine whether or not a particular course of action will grant weal and/or woe. Three times per day the wearer of this headband can, as a standard action, gain information about a specified course of action as if using the <em>augury</em> spell, except that the wearer always gets a meaningful reply.</p>
<h3 id="magic-wondrous-headband_of_intuition-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/augury">augury</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _headband_of_ki_focus = {title: "Headband of Ki Focus", jsx: <><h2 id="magic-wondrous-headband_of_ki_focus-headband-of-ki-focus">Headband of Ki Focus</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 250</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> headband; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>This tied headband helps the wearer focus his ki more effectively. Whenever the wearer spends ki points to make an additional attack, that attack roll gains a +1 insight bonus (+2 if the wearer is using a ki focus weapon with that attack). Furthermore, the wearer of a headband of ki focus is immune to the ninja's <Link to="/ninjatrick/ki_block">ki block</Link> trick or similar effects that block the wearer from using ki points.</p>
<h3 id="magic-wondrous-headband_of_ki_focus-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have a ki pool; <strong>Cost</strong> 2,700 gp</p>
</>};
const _headband_of_knucklebones = {title: "Headband of Knucklebones", jsx: <><h2 id="magic-wondrous-headband_of_knucklebones-headband-of-knucklebones">Headband of Knucklebones</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 250</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> headband; <strong>Price</strong> 27,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This headband is made of interlocked finger bones woven together by leathery tendons and gristle. The wearer may use <em>command undead</em> up to three times per day, but only affecting <Link to="/template/zombie">zombies</Link>. Once per day, the wearer may use the headband to animate one Medium zombie as if using <em>animate dead.</em></p>
<h3 id="magic-wondrous-headband_of_knucklebones-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_dead">animate dead</Link>, <Link to="/spell/command_undead">command undead</Link>; <strong>Cost</strong> 13,750 gp</p>
</>};
const _headband_of_mental_prowess = {title: "Headband of Mental Prowess", jsx: <><h2 id="magic-wondrous-headband_of_mental_prowess-headband-of-mental-prowess">Headband of Mental Prowess</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 250</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 517</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> headband; <strong>Price</strong> 10,000 gp (+2), 40,000 gp (+4), 90,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This simple copper headband has a small yellow gem set so that when it rests upon the forehead of the wearer, the yellow gem sits perched on the wearer's brow as if it were a third eye in the middle of her forehead. Often, the headband contains additional designs to further accentuate the appearance of a third, crystal eye.</p>
<p>The headband grants the wearer an enhancement bonus to two mental ability scores (Intelligence, Wisdom, or Charisma) of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn.</p>
<p>These bonuses are chosen when the headband is created and cannot be changed. If the headband grants a bonus to Intelligence, it also grants skill ranks as a <Link to="/magic-wondrous/headband_of_vast_intelligence">headband of vast intelligence</Link>.</p>
<h3 id="magic-wondrous-headband_of_mental_prowess-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link> (any two); <strong>Cost</strong> 5,000 gp (+2), 20,000 gp (+4), 45,000 gp (+6)</p>
</>};
const _headband_of_mental_resilience = {title: "Headband of Mental Resilience", jsx: <><h2 id="magic-wondrous-headband_of_mental_resilience-headband-of-mental-resilience">Headband of Mental Resilience</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 250</Link><br/><strong>Aura</strong> strong abjuration and transmutation; <strong>CL</strong> 16th<br/><strong>Slot</strong> headband; <strong>Price</strong> 64,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Five faceted sapphires decorate this ornate headband. The headband protects the wearer from effects that would damage his mental capacity. After wearing the headband for 24 hours, the wearer gains five temporary ability points. These points do not add to the wearer's ability scores and do not grant a bonus to any roll. Any <Link to="/rule/ability_damage_drain">damage or drain</Link> to a mental ability score (Intelligence, Wisdom, or Charisma) taken by the wearer is subtracted from these points first. Damage or drain in excess of the wearer's temporary ability points is applied to his current ability scores as normal. The wearer immediately loses all temporary ability points upon removing the headband.</p>
<p>In addition, the headband grants the wearer a +2 enhancement bonus to Intelligence, Wisdom, and Charisma. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn. It also grants skill ranks as a <Link to="/magic-wondrous/headband_of_vast_intelligence_2">headband of vast intelligence +2</Link>.</p>
<p>Temporary ability points that are lost to ability damage return after 24 hours. Ability points lost to ability drain are lost permanently.</p>
<h3 id="magic-wondrous-headband_of_mental_resilience-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>; <strong>Cost</strong> 32,000 gp</p>
</>};
const _headband_of_mental_superiority = {title: "Headband of Mental Superiority", jsx: <><h2 id="magic-wondrous-headband_of_mental_superiority-headband-of-mental-superiority">Headband of Mental Superiority</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 251</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 517</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 16th<br/><strong>Slot</strong> headband; <strong>Price</strong> 16,000 gp (+2), 64,000 gp (+4), 144,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This ornate headband is decorated with numerous clusters of small gemstones. The headband grants the wearer an enhancement bonus to all mental ability scores (Intelligence, Wisdom, and Charisma) of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn. The headband also grants skill ranks as a <Link to="/magic-wondrous/headband_of_vast_intelligence">headband of vast intelligence</Link>.</p>
<h3 id="magic-wondrous-headband_of_mental_superiority-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>; <strong>Cost</strong> 8,000 gp (+2), 32,000 gp (+4), 77,000 gp (+6)</p>
</>};
const _headband_of_ninjitsu = {title: "Headband of Ninjitsu", jsx: <><h2 id="magic-wondrous-headband_of_ninjitsu-headband-of-ninjitsu">Headband of Ninjitsu</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 251</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> headband; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple black cloth band focuses the wearer's ki, helping her use subtle misdirection against opponents in combat. The wearer gains a +2 competence bonus on <Link to="/skill/bluff">Bluff</Link> checks made to feint and combat maneuver checks made to <Link to="/rule/reposition">reposition</Link>, and once per day she can attempt a feint or reposition maneuver as a swift action. The wearer also gains a +2 insight bonus on attack rolls on sneak attacks and can <Link to="/ability/sneak_attack">sneak attack</Link> creatures with <Link to="/rule/concealment">concealment</Link> or total concealment, though miss chances apply normally.</p>
<h3 id="magic-wondrous-headband_of_ninjitsu-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _headband_of_ponderous_recollection = {title: "Headband of Ponderous Recollection", jsx: <><h2 id="magic-wondrous-headband_of_ponderous_recollection-headband-of-ponderous-recollection">Headband of Ponderous Recollection</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 251</Link><br/><strong>Aura</strong> moderate divination and transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 5,100 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black leather headband has two small amber gemstones set so they rest on the wearer's forehead. The headband grants the wearer a +2 enhancement bonus to Intelligence. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn. It also grants skill ranks as a <Link to="/magic-wondrous/headband_of_vast_intelligence">headband of vast intelligence</Link>, but always grants ranks in a <Link to="/skill/knowledge">Knowledge</Link> skill.</p>
<p>As a swift action three times per day, the wearer can call upon the headband to reveal the abilities and weaknesses of a creature within line of sight. The headband fills the wearer's mind with information as though the wearer had made a Knowledge check with a natural roll of a 5, adding her bonuses to the check as normal. At the start of her next turn, the wearer receives additional information as though she had made the check with a natural roll of 10. At the start of her turn after that, the wearer receives a final piece of information, treating her natural roll as 15.</p>
<h3 id="magic-wondrous-headband_of_ponderous_recollection-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/know_the_enemy">know the enemy</Link>; <strong>Cost</strong> 2,550 gp</p>
</>};
const _headband_of_sealed_thoughts = {title: "Headband of Sealed Thoughts", jsx: <><h2 id="magic-wondrous-headband_of_sealed_thoughts-headband-of-sealed-thoughts">Headband of Sealed Thoughts</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 152</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> headband; <strong>Price</strong> 150,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Uncomfortably sharp protrusions bristle on the inner edge of this heavy, bronze headband. It grants its wearer a +4 enhancement bonus to Intelligence. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn. It also grants skill ranks as a <Link to="/magic-wondrous/headband_of_vast_intelligence_4">headband of vast intelligence +4</Link>. The wearer is protected from all effects that gather information about her via divination, and gains a bonus equal to her mythic tier on saving throws against mind-affecting effects. This protection otherwise functions as <em>mind blank,</em> except the headband provides no protection against <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/miracle">miracle</Link>, and <Link to="/spell/wish">wish</Link>, and it doesn't grant a resistance bonus on saving throws.</p>
<p>When the wearer succeeds at a saving throw against a mind-affecting effect, she can rebound the effect onto the caster as an immediate action by expending one use of mythic power. Treat this as the original spell or effect, except the wearer is treated as the caster and the original caster as the target. The rebounded spell affects only the original caster, and rebounding doesn't prevent the original spell from affecting targets other than the wearer of the headband of sealed thoughts.</p>
<h3 id="magic-wondrous-headband_of_sealed_thoughts-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/mind_blank">mind blank</Link>, <Link to="/spell/spell_turning">spell turning</Link>; <strong>Cost</strong> 75,000 gp</p>
</>};
const _headband_of_seduction = {title: "Headband of Seduction", jsx: <><h2 id="magic-wondrous-headband_of_seduction-headband-of-seduction">Headband of Seduction</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 251</Link><br/><strong>Aura</strong> faint enchantment and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This plain white band makes the wearer seem more attractive. The wearer gains a +2 competence bonus on Charisma-based checks with other members of his creature type. If the wearer is of the humanoid type, he gains a +5 competence bonus on creatures of his subtype instead. Once per day, the wearer can attempt to affect a creature as the spell <em>unnatural lust</em> but with a duration of 10 minutes.</p>
<h3 id="magic-wondrous-headband_of_seduction-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/unnatural_lust">unnatural lust</Link>; <strong>Cost</strong> 20,000 gp</p>
</>};
const _headband_of_social_competence = {title: "Headband of Social Competence", jsx: <><h2 id="magic-wondrous-headband_of_social_competence-headband-of-social-competence">Headband of Social Competence</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 28</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> headband; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This simple yet elegant silver headband mentally warns the wearer before she commits a social misstep, which includes any action that would increase the DCs of Diplomacy checks to alter the attitudes of those around her or worsen the attitude of a person that the wearer considers very important. This effect functions similarly to that of a <Link to="/magic-wondrous/phylactery_of_faithfulness">phylactery of faithfulness</Link>, except no contemplation is required; the headband simply alerts the wearer of the consequences before she can perform the action.</p>
<h3 id="magic-wondrous-headband_of_social_competence-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cultural_adaptation">cultural adaptation</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _headband_of_stupidity = {title: "Headband of Stupidity", jsx: <><h2 id="magic-wondrous-headband_of_stupidity-headband-of-stupidity">Headband of Stupidity</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 346</Link></p>
<p><strong>Aura</strong> strong transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Weight</strong> 1 lb.</p>
<p>This headband appears to be a <em>headband of vast intelligence +4,</em> but instead of granting a +4 bonus to Intelligence and bonuses to associated skills, the wearer take a -4 penalty to Intelligence and a further -2 penalty on all <Link to="/skill/knowledge">Knowledge</Link> checks. The wearer is not aware of the debilitating effects of the headband; even the stupidest statement or misguided insight seems intelligent to him while he is wearing it.</p>
<h3 id="magic-wondrous-headband_of_stupidity-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/headband_of_vast_intelligence_4">headband of vast intelligence +4</Link>; <strong>Cost</strong> -</p>
</>};
const _headband_of_the_sage = {title: "Headband of the Sage", jsx: <><h2 id="magic-wondrous-headband_of_the_sage-headband-of-the-sage">Headband of the Sage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 357</Link></p>
<p><strong>Aura</strong> moderate divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 71,300 gp; <strong>Weight</strong> 1 lb.</p>
<p>This headband of vast intelligence +6 also holds a consciousness that shares its knowledge and education with a suitable wearer. This intelligence can be of any alignment and its only <Link to="/rule/purpose">purpose</Link> is to share its vast knowledge with its wearer. The headband also functions as a <Link to="/magic-wondrous/helm_of_comprehend_languages_and_read_magic">helm of comprehend languages and read magic</Link>. Furthermore, instead of granting the normal skill ranks of a <Link to="/magic-wondrous/headband_of_vast_intelligence_6">headband of vast intelligence +6</Link>, this headband grants 4 ranks in six skills, but all of those skills must be <Link to="/skill/knowledge">Knowledge</Link> skills. It grants such intelligence by a stream of constant whispers and arguments that the headband communicates telepathically in Common or in one of 10 other languages it knows. Once per week on command, the wearer can also convince the headband to use <em>legend lore</em> as the spell, though the casting time is only a standard action.</p>
<h3 id="magic-wondrous-headband_of_the_sage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/legend_lore">legend lore</Link>, <Link to="/spell/read_magic">read magic</Link>; <strong>Price</strong> 35,650 gp</p>
<h3 id="magic-wondrous-headband_of_the_sage-statistics">Statistics</h3>
<p><strong>Alignment</strong> varies; <strong>Ego</strong> 20<br/><strong>Senses</strong> 30 ft.<br/><strong>Int</strong> 20, <strong>Wis</strong> 16, <strong>Cha</strong> 12<br/><strong>Communication</strong> telepathy (Common and 10 other languages)</p>
</>};
const _headband_of_the_tainted_ouroboros = {title: "Headband of the Tainted Ouroboros", jsx: <><h2 id="magic-wondrous-headband_of_the_tainted_ouroboros-headband-of-the-tainted-ouroboros">Headband of the Tainted Ouroboros</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 31</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> -</p>
<p>This thin green headband is made entirely out of small metal scales that shimmer in the sunlight, sparkling in turn with flashes of emerald, forest green, and sea-foam depending on the angle from which the wearer is viewed. While the wearer is taking damage or otherwise being negatively affected by a poison, she can touch another creature and duplicate the poison's effects in that creature. This requires a melee touch attack that provokes attacks of opportunity. When the wearer makes a successful touch attack in this way, the target creature must attempt a Fortitude saving throw against the duplicated poison's DC as if it were the target of the initial poisoning. Failing this Fortitude saving throw subjects the target to the full duration of the duplicated poison's effects. The initial poison can be duplicated to only one additional target at a time.</p>
<h3 id="magic-wondrous-headband_of_the_tainted_ouroboros-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/touch_injection">touch injection</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _headband_of_the_wolf = {title: "Headband of the Wolf", jsx: <><h2 id="magic-wondrous-headband_of_the_wolf-headband-of-the-wolf">Headband of the Wolf</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 230</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This silver band is cast to resemble a pack of hunting wolves. On command, the wearer can gain the <Link to="/umr/scent">scent</Link> ability with a range of 10 feet (20 feet upwind, 5 feet downwind) as the <Link to="/aspect/wolf">wolf</Link> aspect of the hunter's animal focus class feature. If the wearer is a <Link to="/class/hunter">hunter</Link> with that aspect, this headband instead increases the wearer's effective hunter level for the wolf aspect by 8 levels.</p>
<h3 id="magic-wondrous-headband_of_the_wolf-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bloodhound">bloodhound</Link>, creator must have the animal focus class feature; <strong>Cost</strong> 2,500 gp</p>
</>};
const _headband_of_twisted_intellect = {title: "Headband of Twisted Intellect", jsx: <><h2 id="magic-wondrous-headband_of_twisted_intellect-headband-of-twisted-intellect">Headband of Twisted Intellect</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_123_the_flooded_cathedral">Pathfinder #123: The Flooded Cathedral pg. 54</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This strange metal <Link to="/magic-wondrous/headband_of_vast_intelligence_2">headband of vast intelligence +2</Link> is crafted in the shape of intertwined tentacles and adorned with runes in the Aboleth language. When a creature dons the headpiece, the tentacles seem almost alive, changing their size and shape to fit the contours of the wearer's head.</p>
<p>The headband has two special indentations for <Link to="/magic-wondrous/ioun_stone">ioun stones</Link> similar to those found in a <Link to="/magic-wondrous/wayfinder">wayfinder</Link>. When an ioun stone is inserted into one of the slots, the tentacles animate for a moment, adjusting themselves around the slot to accommodate the shape of the ioun stone. The wearer benefits from the ioun stone's effect as though the stone were orbiting her head.</p>
<p>The headband uses a more refined version of the same technology that powers a wayfinder. First, it coaxes two ioun stones to manifest their resonant powers simultaneously. Furthermore, the slotted ioun stones do not suppress the headband's own magical abilities. However, if the wearer is also carrying, wearing, or wielding a wayfinder or any similar item into which ioun stones can be inserted, the two items suppress one another's abilities, but both return to normal when one is set aside.</p>
<h3 id="magic-wondrous-headband_of_twisted_intellect-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, creator must be an <Link to="/monster/aboleth">aboleth</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _headband_of_unshakeable_resolve = {title: "Headband of Unshakeable Resolve", jsx: <><h2 id="magic-wondrous-headband_of_unshakeable_resolve-headband-of-unshakeable-resolve">Headband of Unshakeable Resolve</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 251</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 5,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple white cotton headband is decorated with a stylized imperial dragon coiled above the wearer's forehead. The headband grants the wearer a +2 enhancement bonus to her Wisdom score. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn.</p>
<p>Whenever the wearer suffers a fear effect, she may spend an immediate action to reduce the severity of the fear effect by one step. If the wearer would become <Link to="/misc/panicked">panicked</Link>, she is instead <Link to="/misc/frightened">frightened</Link>. If she would become frightened, she is instead <Link to="/misc/shaken">shaken</Link>. If the wearer would become shaken, the effect is negated entirely. The wearer can use this ability up to three times per day.</p>
<h3 id="magic-wondrous-headband_of_unshakeable_resolve-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 2,800 gp</p>
</>};
const _headband_of_vast_intelligence = {title: "Headband of Vast Intelligence", jsx: <><h2 id="magic-wondrous-headband_of_vast_intelligence-headband-of-vast-intelligence">Headband of Vast Intelligence</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 251</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 517</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,000 gp (+2), 16,000 gp (+4), 36,000 gp (+6); <strong>Weight</strong> 1 lb.</p>
<p>This intricate gold headband is decorated with several small blue and deep purple gemstones. The headband grants the wearer an enhancement bonus to Intelligence of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn. A headband of vast intelligence has one skill associated with it per +2 bonus it grants. After being worn for 24 hours, the headband grants a number of skill ranks in those skills equal to the wearer's total Hit Dice. These ranks do not stack with the ranks a creature already possesses. These skills are chosen when the headband is created. If no skill is listed, the headband is assumed to grant skill ranks in randomly determined <Link to="/skill/knowledge">Knowledge</Link> skills.</p>
<h3 id="magic-wondrous-headband_of_vast_intelligence-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>; <strong>Cost</strong> 2,000 gp (+2), 8,000 gp (+4), 18,000 gp (+6)</p>
</>};
const _headband_of_vermin_control = {title: "Headband of Vermin Control", jsx: <><h2 id="magic-wondrous-headband_of_vermin_control-headband-of-vermin-control">Headband of Vermin Control</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 45</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of this black leather headband can spend 10 minutes attuning the headband to one touched vermin of Medium or larger size. Once the headband is attuned, any creature wearing it can attempt <Link to="/skill/handle_animal">Handle Animal</Link> and <Link to="/skill/ride">Ride</Link> checks to influence or control that vermin as if it were an animal and had animal-level intelligence. The attunement lasts until the vermin dies, the headband is destroyed, or the headband is attuned to a different vermin.</p>
<p><Link to="/race/duergar">Duergar</Link>-created items of this type are usually protected by a <Link to="/spell/dust_ward">dust ward</Link> spell.</p>
<h3 id="magic-wondrous-headband_of_vermin_control-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/control_vermin">control vermin</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _hollywreath_band = {title: "Hollywreath Band", jsx: <><h2 id="magic-wondrous-hollywreath_band-hollywreath-band">Hollywreath Band</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 252</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> headband; <strong>Price</strong> 5,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This headband is woven of magically preserved holly, its deep green leaves and bright red berries perpetually lustrous. The wearer may create <em>goodberries</em> once per day as the spell, and any effect she creates that affects plants, including the domain powers of the <Link to="/domain/plant">Plant</Link> domain, take effect at +1 caster level and gain a +1 bonus to the save DC.</p>
<h3 id="magic-wondrous-hollywreath_band-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/goodberry">goodberry</Link>, <Link to="/spell/plant_growth">plant growth</Link>; <strong>Cost</strong> 2,580 gp</p>
</>};
const _hunters_band = {title: "Hunter's Band", jsx: <><h2 id="magic-wondrous-hunters_band-hunters-band">Hunter's Band</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 252</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> headband; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This simple headband of braided hide grants a +5 competence bonus on <Link to="/skill/survival">Survival</Link> checks and inures the wearer to the strain of long travel, as the <em>tireless pursuit</em> spell. If the wearer is a <Link to="/class/ranger">ranger</Link>, the hunter's band increases his <Link to="/ability/favored_enemy">favored enemy</Link> bonus on attack rolls by +1 for all his favored enemies. If the ranger has the hunter's bond (companions) class feature, this increase also applies to the attack roll bonus his allies gain from that ability.</p>
<h3 id="magic-wondrous-hunters_band-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/instant_enemy">instant enemy</Link>, <Link to="/spell/tireless_pursuit">tireless pursuit</Link>, creator must have 5 ranks in Survival; <strong>Cost</strong> 5,500 gp</p>
</>};
const _imperious_headband = {title: "Imperious Headband", jsx: <><h2 id="magic-wondrous-imperious_headband-imperious-headband">Imperious Headband</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 29</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>Adorned with stylized bronze feathers, these headbands are prized by treacherous nobles who fear an assassin's dagger in the back. While worn, an imperious headband grants its wearer a +4 deflection bonus to his AC against any attack made by a hireling, a slave, a servant, or any other sentient creature in his employ. In addition, such creatures must succeed at a DC 13 Will save or treat their master as if he were affected by a <em>sanctuary</em> spell. If such creatures are subject to magical compulsion to attack the wearer, they must roll all attack rolls and checks to overcome spell resistance against the wearer twice and take the lower result.</p>
<h3 id="magic-wondrous-imperious_headband-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/sanctuary">sanctuary</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _iron_band_of_iron_mind = {title: "Iron Band of Iron Mind", jsx: <><h2 id="magic-wondrous-iron_band_of_iron_mind-iron-band-of-iron-mind">Iron Band of Iron Mind</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_91_battle_of_bloodmarch_hills">Pathfinder #91: Battle of Bloodmarch Hills pg. 73</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> headband; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This headband grants a +4 bonus on saving throws against all enchantment spells. When worn by a creature with the giant subtype, it makes the wearer immune to enchantments that target only humanoid creatures (such as <Link to="/spell/charm_person">charm person</Link> or <Link to="/spell/hold_person">hold person</Link>).</p>
<h3 id="magic-wondrous-iron_band_of_iron_mind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/break_enchantment">break enchantment</Link>, creator must have the giant subtype; <strong>Cost</strong> 7,500 gp</p>
</>};
const _kineticists_diadem_lesser = {title: "Kineticist's Diadem (Lesser)", jsx: <><h2 id="magic-wondrous-kineticists_diadem_lesser-kineticists-diadem">Kineticist's Diadem</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 259</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 18,000 gp (Lesser), 50,000 gp (Normal), 98,000 gp (Greater); <strong>Weight</strong> -</p>
<p>This metal headband holds a glistening, diamond-shaped gem. A kineticist's diadem includes one of five colors of gem, each corresponding to a different element: blue (water), clear (aether), green (earth), red (fire), and white (air). The diadem's gem grants the wearer greater control over its associated element.</p>
<p>While worn by a <Link to="/class/kineticist">kineticist</Link>, this item increases the damage dealt by the kineticist's simple and composite blasts that match the element of the inlaid gem by 1d6 points (for a lesser kineticist's diadem), 2d6 points (for a kineticist's diadem), or 3d6 points (for a greater kineticist's diadem). If the blast is a physical blast, the extra damage dice from the kineticist's diadem increase to d8s instead of d6s. These extra damage dice do not multiply on a critical hit, and the extra damage dice do not apply to blasts with form infusions that do not apply the extra damage from elemental overflow, like <Link to="/kinetic/kinetic_blade">kinetic blade</Link> and <Link to="/kinetic/kinetic_whip">kinetic whip</Link>.</p>
<h3 id="magic-wondrous-kineticists_diadem_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be a 10th-level kineticist with access to the appropriate element; <strong>Cost</strong> 9,000 gp (Lesser), 25,000 gp (Normal), 49,000 gp (Greater)</p>
</>};
const _moon_circlet = {title: "Moon Circlet", jsx: <><h2 id="magic-wondrous-moon_circlet-moon-circlet">Moon Circlet</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 308</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 15th<br/><strong>Slot</strong> headband; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>This fine silver circlet typically has a carved moonstone inset on the front or a crescent moon design. The wearer of a moon circlet gains darkvision out to 60 feet (if she does not already possess it). Its other effects only benefit a wearer capable of casting arcane spells.</p>
<p>During the waxing moon, the wearer's caster level is considered one higher for purposes of caster level checks and spell effects; during the three nights of the full moon, this benefit increases to two levels higher than normal. However, this additional power comes with a price. During the waning moon, the wearer's caster level is considered one lower for purposes of caster level checks and spell effects, and during the three nights of the new moon, this penalty increases to two levels lower.</p>
<p>Removing a moon circlet imposes 2 <Link to="/rule/negative_levels">negative levels</Link> on the wearer until the next full moon (or until the circlet is worn again, whichever comes first). These negative levels cannot be restored by any means short of a <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/wish">wish</Link>, or <Link to="/spell/miracle">miracle</Link>.</p>
<h3 id="magic-wondrous-moon_circlet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/light">light</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _phylactery_of_faithfulness = {title: "Phylactery of Faithfulness", jsx: <><h2 id="magic-wondrous-phylactery_of_faithfulness-phylactery-of-faithfulness">Phylactery of Faithfulness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 252</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 525</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> headband; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This item is a tiny box containing religious scripture. The box is affixed to a leather cord and tied around the forehead, worn so that the box sits upon the wearer's brow. There is no mundane way to determine what function this religious item performs until it is worn. The wearer of a phylactery of faithfulness is aware of any action or item that could adversely affect her alignment and her standing with her deity, including magical effects. She acquires this information prior to performing such an action or becoming associated with such an item if she takes a moment to contemplate the act.</p>
<h3 id="magic-wondrous-phylactery_of_faithfulness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_chaos">detect chaos</Link>, <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/detect_good">detect good</Link>, <Link to="/spell/detect_law">detect law</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _phylactery_of_jadis_vel = {title: "Phylactery of Jadis-Vel", jsx: <><h2 id="magic-wondrous-phylactery_of_jadis_vel-phylactery-of-jadis-vel">Phylactery of Jadis-Vel</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 47</Link><br/><strong>Aura</strong> moderate necromancy [evil]; <strong>CL</strong> 11th<br/><strong>Slot</strong> headband; <strong>Price</strong> 135,000 gp</p>
<p>This item is a receptacle for a lich's soul. It was broken into five pieces. Individually, each piece can do no more than whisper "Jadis-Vel," the name of the <Link to="/template/lich">lich</Link> whose fragmented soul is trapped within. When the pieces of the phylactery are all gathered within 30 feet of each other, they collectively become an intelligent item with the memories and will of the lich whose soul it contains. The spirit retains only fractured memories of its former existence, but it gains an understanding of how to escape and reclaim those memories.</p>
<p>The combined pieces teach their owner how to find the path to lichdom, a process that is unique to each soul. They have a +13 bonus on <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> checks for this purpose. A prospective lich can choose the Phylactery of Jadis-Vel as her own phylactery, negating the gold cost of crafting a phylactery (though this does not bypass the other construction requirements for creating a phylactery). Once the prospective lich performs the necessary ritual to become a lich, the trickery of the phylactery comes to fruition: the new lich's spirit becomes trapped within the shards of this phylactery, and the soul of Jadis-Vel is released into the new lich's body. The freed lich is without a phylactery and must craft a new one, but is otherwise returned to the world intact, albeit in a different body.</p>
<h3 id="magic-wondrous-phylactery_of_jadis_vel-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have at least 10 ranks in Knowledge (religion) and a caster level of 11th or higher; <strong>Price</strong> 127,500 gp</p>
<h3 id="magic-wondrous-phylactery_of_jadis_vel-statistics">Statistics</h3>
<p><strong>Alignment</strong> neutral; <strong>Ego</strong> 19<br/><strong>Senses</strong> 60 ft.<br/><strong>Int</strong> 16, <strong>Wis</strong> 14, <strong>Cha</strong> 14<br/><strong>Communication</strong> speech (Common, Necril, Osiriani)</p>
</>};
const _phylactery_of_negative_channeling = {title: "Phylactery of Negative Channeling", jsx: <><h2 id="magic-wondrous-phylactery_of_negative_channeling-phylactery-of-negative-channeling">Phylactery of Negative Channeling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 252</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 525</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> -</p>
<p>This item is a boon to any character able to <Link to="/ability/channel_negative_energy">channel negative energy</Link>, increasing the amount of damage dealt to living creatures by +2d6. This also increases the amount of damage healed by undead creatures.</p>
<h3 id="magic-wondrous-phylactery_of_negative_channeling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be a 10th-level cleric; <strong>Cost</strong> 5,500 gp</p>
</>};
const _phylactery_of_positive_channeling = {title: "Phylactery of Positive Channeling", jsx: <><h2 id="magic-wondrous-phylactery_of_positive_channeling-phylactery-of-positive-channeling">Phylactery of Positive Channeling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 252</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 526</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> -</p>
<p>This item allows <Link to="/ability/channel_positive_energy">channelers of positive energy</Link> to increase the amount of damage dealt to undead creatures by +2d6. This also increases the amount of damage healed by living creatures.</p>
<h3 id="magic-wondrous-phylactery_of_positive_channeling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be a 10th-level cleric; <strong>Cost</strong> 5,500 gp</p>
</>};
const _phylactery_of_the_shepherd = {title: "Phylactery of the Shepherd", jsx: <><h2 id="magic-wondrous-phylactery_of_the_shepherd-phylactery-of-the-shepherd">Phylactery of the Shepherd</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 252</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> headband; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Three times per day on command, the phylactery's wearer can determine the current health and overall well-being of any one ally within 30 feet. This effect acts as the <em>status</em> spell. If the wearer has the ability to <Link to="/ability/channel_energy">channel energy</Link> or <Link to="/ability/lay_on_hands">lay on hands</Link>, he can as a swift action choose to apply the effects of that class feature to an ally he is currently evaluating so long as that ally is within 30 feet of him, but doing so ends the effect of the phylactery's <em>status.</em></p>
<h3 id="magic-wondrous-phylactery_of_the_shepherd-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/status">status</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _pull_ring_of_scent = {title: "Pull-Ring of Scent", jsx: <><h2 id="magic-wondrous-pull_ring_of_scent-pull-ring-of-scent">Pull-Ring of Scent</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 26</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This dull brass ring is typically placed in the nose or muzzle, or elsewhere on the head of an animal, and is used to attach a lead rope or bridle. The wearer (and its rider, if any) gives off no scent and cannot be tracked or located by scent. In addition, it gains the <Link to="/umr/scent">scent</Link> ability within 30 feet; if the wearer already possesses scent, the range for this sense increases by 30 feet (to a maximum of 60 feet).</p>
<h3 id="magic-wondrous-pull_ring_of_scent-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _serpents_band = {title: "Serpent's Band", jsx: <><h2 id="magic-wondrous-serpents_band-serpents-band">Serpent's Band</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 252</Link><br/><strong>Aura</strong> moderate conjuration and enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> headband; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of this circlet gains a +2 insight bonus on saving throws against effects with the emotion descriptor, including fear effects. The wearer gains fluency in Draconic and may converse with non-sentient (Intelligence 1 or 2) reptilian animals and magical beasts as if using the <em>speak with animals</em> spell, and gains a +4 competence bonus on <Link to="/skill/handle_animal">Handle Animal</Link> and <Link to="/ability/wild_empathy">wild empathy</Link> checks made when interacting with such creatures.</p>
<h3 id="magic-wondrous-serpents_band-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animal_trance">animal trance</Link>, <Link to="/spell/hypnotism">hypnotism</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, <Link to="/spell/summon_natures_ally_v">summon nature's ally V</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _shifters_headband = {title: "Shifter's Headband", jsx: <><h2 id="magic-wondrous-shifters_headband-shifters-headband">Shifter's Headband</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 253</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> headband; <strong>Price</strong> 4,500 gp (+2), 17,500 gp (+4), 39,000 gp (+6); <strong>Weight</strong> -</p>
<p>This band of reddish fox fur is marked on the front with a distinctive symbol that constantly shifts into a different character. The headband grants the wearer an enhancement bonus to one mental ability score (Intelligence, Wisdom, or Charisma) of +2, +4, or +6. Treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the headband is worn. This bonus is chosen when the headband is created and cannot be changed. If the headband grants a bonus to Intelligence, it also grants skill ranks as a <Link to="/magic-wondrous/headband_of_vast_intelligence">headband of vast intelligence</Link>.</p>
<p>If the wearer is a creature who uses magic to change form, she gains the following additional benefits.</p>
<blockquote>
<p><strong className="hl">Shifter's headband +2:</strong> The wearer treats her caster level as if it were one level higher when casting spells or creating extracts of the polymorph subschool.</p>
<p><strong className="hl">Shifter's headband +4:</strong> Once per day while under the effect of a polymorph spell or extract, the wearer can assume another form allowed by that effect. This is a standard action.</p>
<p><strong className="hl">Shifter's headband +6:</strong> Whenever the wearer changes her shape with a polymorph effect, she gains DR 5/silver for 1 minute (this ends if she returns to her natural form).</p>
</blockquote>
<p>These additional shapeshifter abilities are cumulative. For example, a creature wearing a shifter's headband +4 gains the extra transformation ability and treats her caster level as 1 higher than normal for polymorph spells and extracts.</p>
<h3 id="magic-wondrous-shifters_headband-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link>; <strong>Cost</strong> 2,250 gp (+2), 8,750 gp (+4), 19,500 gp (+6)</p>
</>};
const _soulbound_eye = {title: "Soulbound Eye", jsx: <><h2 id="magic-wondrous-soulbound_eye-soulbound-eye">Soulbound Eye</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 253</Link>, <Link to="/source/rival_guide">Rival Guide pg. 41</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 16th<br/><strong>Slot</strong> headband; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> -</p>
<p>Appearing at first like an expensive, masochistic adornment, this almond-sized star ruby is set in a gold clasp, one side of which is festooned with several long spikes. A soulbound eye is not an item that most creatures would voluntarily wear; they are instead crafted by powerful creatures who wish to use another creature as a sort of remote-viewing slave. A soulbound eye must be attached to a willing or <Link to="/misc/helpless">helpless</Link> creature by pressing the spike-covered surface to the creature's brow - the gem swiftly and painfully embeds itself in the victim's forehead, immediately activating to forge a shared link between the wearer and the creature who placed the item on its head (the "master").</p>
<p>Once implanted, the soulbound eye allows the master to observe the world around the wearer through the wearer's senses. It also allows for telepathic communication between the wearer and the master. Neither of these features function across planar boundaries.</p>
<p>The soulbound eye's wearer is not compelled to obey its master's telepathic commands, but the master can use the soulbound eye as a conduit for <Link to="/spell/hold_monster">hold monster</Link>, <Link to="/spell/modify_memory">modify memory</Link>, <Link to="/spell/pain_strike">pain strike</Link>, and <Link to="/spell/suggestion">suggestion</Link> spells, treating the wearer as the target of the spell no matter the distance between master and wearer. The victim is allowed any normal saving throws or spell resistance against spells cast through the soulbound eye.</p>
<p>An implanted soulbound eye functions like a cursed item once it is in place - it can only be removed if the curse is first lifted via an effect like <Link to="/spell/remove_curse">remove curse</Link> or <Link to="/spell/break_enchantment">break enchantment</Link>. Once removed, a soulbound eye crumbles to fragments.</p>
<h3 id="magic-wondrous-soulbound_eye-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/scrying">scrying</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _veiled_eye = {title: "Veiled Eye", jsx: <><h2 id="magic-wondrous-veiled_eye-veiled-eye">Veiled Eye</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 253</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> headband; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>This banded agate attaches itself to its wearer's forehead and then, blinking and focusing, begins to act as an additional eye. When worn, the veiled eye has the same vision as the wearer (such as low-light vision, darkvision 60 ft., or the oracle's <Link to="/oraclecurse/clouded_vision">clouded vision</Link> curse). It grants the wearer no particular advantages so long as his original eyes continue to function normally. However, should his original eyes stop working, whether because of the wearer becoming <Link to="/misc/blinded">blinded</Link> or even his own decision to close them, he can see through the veiled eye instead. When the wearer is using the veiled eye as his only vision source, he takes a -2 penalty on ranged attack rolls but gains a +2 insight bonus on saves against <Link to="/umr/gaze">gaze</Link> attacks.</p>
<h3 id="magic-wondrous-veiled_eye-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/remove_blindness_deafness">remove blindness/deafness</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _winter_wolf_headband = {title: "Winter Wolf Headband", jsx: <><h2 id="magic-wondrous-winter_wolf_headband-winter-wolf-headband">Winter Wolf Headband</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 253</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> headband; <strong>Price</strong> 32,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Crafted of pale bone or silver, this headband features a snarling wolf's head centered on the wearer's forehead. The wearer gains cold resistance 10. Once per day, the wearer may transform into a Large white-furred <Link to="/monster/wolf">wolf</Link> for 11 minutes. In addition, once per day the wearer may breathe a 30-foot cone of cold that deals 7d6 points of cold damage (Reflex DC 16 for half). The wearer may use this breath weapon even when transformed.</p>
<h3 id="magic-wondrous-winter_wolf_headband-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>, <Link to="/spell/dragons_breath">dragon's breath</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 16,000 gp</p>
</>};
